        {
            get { return GetChatCostSettings().storageType; }
            set { ConfigureChatStorageCosts(value, ChatStorageCostFactor); }
        }

        public double ChatStorageCostFactor
        {
            get { return GetChatCostSettings().storageCostFactor; }
            set { ConfigureChatStorageCosts(ChatStorageType, value); }
        }

        public double ChatCpuTdpWatts
        {
            get { return GetChatCostSettings().cpuTdpWatts; }
        }

        public void ConfigureChatStorageCosts(string storageType, double costFactor)
        {
            ChatCostSettings settings = GetChatCostSettings();
            settings.storageType = NormalizeStorageType(storageType);
            settings.storageCostFactor = ClampStorageCostFactor(costFactor);
            SaveChatCostSettings(settings);
        }

        public GpuTdpDetectionSnapshot DetectAndApplyNvidiaGpuTdpWatts()
        {
            GpuTdpDetectionSnapshot snapshot = DetectNvidiaGpuTdp();
            lock (_chatCostLock)
            {
                _detectedGpuTdpWatts = snapshot.TdpWatts > 0 ? snapshot.TdpWatts : 0;
            }

            if (snapshot.TdpWatts > 0)
            {
                lock (_chatSessionLock)
                {
                    var table = GetChatCostsTable();
                    UpsertChatCostSetting(table, "gpuTdpWatts", snapshot.TdpWatts);
                    _chatSessionData.Save();
                }
            }

            return snapshot;
        }

        public bool AllowOpenRegistration
        {
            get { return GetChatCostSettings().allowOpenRegistration; }
            set
            {
                ChatCostSettings settings = GetChatCostSettings();
                settings.allowOpenRegistration = value;
                SaveChatCostSettings(settings);
            }
        }

