        public IReadOnlyList<ChatSessionDiagnosticsSnapshot> GetChatSessionDiagnostics()
        {
            var sessions = new List<ChatSessionDiagnosticsSnapshot>();
            lock (_chatSessionLock)
            {
                var table = GetChatSessionsTable();
                foreach (object[] sourceRow in table.Rows)
                {
                    object[] row = NormalizeChatSessionRow(sourceRow);
                    sessions.Add(new ChatSessionDiagnosticsSnapshot
                    {
                        Id = GetRowValue(row, 0),
                        Title = GetRowValue(row, 1),
                        CreatedUtc = GetRowValue(row, 2),
                        UpdatedUtc = GetRowValue(row, 3),
                        Model = GetRowValue(row, 4),
                        OwnerKey = GetRowValue(row, 7),
                        MessageCount = CountJsonArrayItems(GetRowValue(row, 5)),
                        FileCount = CountJsonArrayItems(GetRowValue(row, 6))
                    });
                }
            }

            sessions.Sort((a, b) => string.CompareOrdinal(b.UpdatedUtc, a.UpdatedUtc));
            return sessions;
        }

        public IReadOnlyList<ActivePromptSessionDiagnosticsSnapshot> GetActivePromptSessionDiagnostics()
        {
            var sessions = new List<ActivePromptSessionDiagnosticsSnapshot>();
            lock (_activePromptSessionLock)
            {
                PruneInactivePromptSessionsLocked();
                foreach (ActivePromptSessionState state in _activePromptSessions.Values)
                {
                    sessions.Add(new ActivePromptSessionDiagnosticsSnapshot
                    {
                        Id = state.Id,
                        Source = state.Source,
                        Title = state.Title,
                        OwnerKey = state.OwnerKey,
                        Model = state.Model,
                        Status = state.Status,
                        Phase = state.Phase,
                        StartedUtc = state.StartedUtc.ToString("O"),
                        UpdatedUtc = state.UpdatedUtc.ToString("O"),
                        CompletedUtc = state.CompletedUtc.HasValue ? state.CompletedUtc.Value.ToString("O") : "",
                        ElapsedSeconds = Math.Max(0, (int)Math.Round(((state.CompletedUtc ?? DateTimeOffset.UtcNow) - state.StartedUtc).TotalSeconds))
                    });
                }
            }

            sessions.Sort((a, b) => string.CompareOrdinal(b.UpdatedUtc, a.UpdatedUtc));
            return sessions;
        }

        public string GetDefaultLocalChatOwnerKey()
        {
            return "ip:127.0.0.1";
        }

        public IReadOnlyList<ChatFilesystemAccessSnapshot> GetChatFilesystemAccessDiagnostics(string ownerKey)
        {
            var snapshots = new List<ChatFilesystemAccessSnapshot>();
            foreach (ChatFilesystemAccessEntry entry in GetChatFilesystemAccess(NormalizeChatFilesystemOwnerKey(ownerKey)))
            {
                snapshots.Add(new ChatFilesystemAccessSnapshot
                {
                    Path = entry?.path ?? "",
                    Exists = entry != null && entry.exists,
                    CreatedUtc = entry?.createdUtc ?? ""
                });
            }
            return snapshots;
        }

        public IReadOnlyList<ChatFilesystemAccessSnapshot> AddChatFilesystemAccessDirectory(string ownerKey, string directoryPath)
        {
            ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
            if (!TryNormalizeAccessibleDirectory(directoryPath, requireExists: true, out string normalizedPath, out string error))
                throw new InvalidOperationException(error);

            SaveChatFilesystemAccess(ownerKey, normalizedPath);
            return GetChatFilesystemAccessDiagnostics(ownerKey);
        }

        public IReadOnlyList<ChatFilesystemAccessSnapshot> RemoveChatFilesystemAccessDirectory(string ownerKey, string directoryPath)
        {
            ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
            if (!TryNormalizeAccessibleDirectory(directoryPath, requireExists: false, out string normalizedPath, out string error))
                throw new InvalidOperationException(error);

            RemoveChatFilesystemAccess(ownerKey, normalizedPath);
            StopChatFtpServerIfRootRemoved(ownerKey, normalizedPath);
            return GetChatFilesystemAccessDiagnostics(ownerKey);
        }

        public FilesystemPermissionRequestSnapshot ApproveFilesystemPermissionRequest(string requestId, bool alwaysAllow)
        {
            FilesystemPermissionRequestSnapshot request = FindPendingFilesystemPermissionRequest(requestId);
            if (request == null)
                throw new InvalidOperationException("Filesystem permission request was not found or is no longer pending.");

            if (alwaysAllow)
            {
                SaveChatFilesystemAccess(request.OwnerKey, request.DirectoryPath);
            }
            else
            {
                AddTemporaryFilesystemAccess(request.OwnerKey, request.DirectoryPath);
            }

            RemovePendingFilesystemPermissionRequest(request.Id);
            LogMessage("[Filesystem Permission] " + (alwaysAllow ? "Always allowed " : "Allowed once ") + request.DirectoryPath + " for " + request.OwnerKey + ".");
            return request;
        }

        public FilesystemPermissionRequestSnapshot DenyFilesystemPermissionRequest(string requestId, bool alwaysDeny)
        {
            FilesystemPermissionRequestSnapshot request = FindPendingFilesystemPermissionRequest(requestId);
            if (request == null)
                throw new InvalidOperationException("Filesystem permission request was not found or is no longer pending.");

            if (alwaysDeny)
                SaveChatFilesystemDeniedDirectory(request.OwnerKey, request.DirectoryPath);

            RemovePendingFilesystemPermissionRequest(request.Id);
            LogMessage("[Filesystem Permission] " + (alwaysDeny ? "Always denied " : "Denied ") + request.DirectoryPath + " for " + request.OwnerKey + ".");
            return request;
        }

        public TerminalPermissionRequestSnapshot ApproveTerminalPermissionRequest(string requestId, bool alwaysApprove, bool foreverApprove)
        {
            PendingTerminalPermissionRequest pending = FindPendingTerminalPermissionRequest(requestId);
            if (pending == null)
                throw new InvalidOperationException("Terminal permission request was not found or is no longer pending.");

            TerminalPermissionRequestSnapshot request = pending.Request;
            if (foreverApprove)
            {
                ChatPermissionState permissions = GetChatPermissions(request.OwnerKey);
                permissions.terminalCommands = true;
                permissions.terminalForeverApproved = true;
                SaveChatPermissions(request.OwnerKey, permissions);
                ApplyRuntimeChatPermissions(GetChatPermissions());
            }
            else if (alwaysApprove)
            {
                SaveTerminalPermissionRule(request.OwnerKey, request.Command, "allow");
            }

            RemovePendingTerminalPermissionRequest(request.Id);
            pending.Completion.TrySetResult(new TerminalPermissionDecision(true, alwaysApprove, foreverApprove));
            LogMessage("[Terminal Permission] " + (foreverApprove ? "Forever approved " : alwaysApprove ? "Always approved " : "Approved ") + request.Command + " for " + request.OwnerKey + ".");
            return request;
        }

        public TerminalPermissionRequestSnapshot DenyTerminalPermissionRequest(string requestId, bool alwaysDeny)
        {
            PendingTerminalPermissionRequest pending = FindPendingTerminalPermissionRequest(requestId);
            if (pending == null)
                throw new InvalidOperationException("Terminal permission request was not found or is no longer pending.");

            TerminalPermissionRequestSnapshot request = pending.Request;
            if (alwaysDeny)
                SaveTerminalPermissionRule(request.OwnerKey, request.Command, "deny");

            RemovePendingTerminalPermissionRequest(request.Id);
            pending.Completion.TrySetResult(new TerminalPermissionDecision(false, false, false));
            LogMessage("[Terminal Permission] " + (alwaysDeny ? "Always denied " : "Denied ") + request.Command + " for " + request.OwnerKey + ".");
            return request;
        }

        public IReadOnlyList<WebAuthRegistrationRequestSnapshot> GetPendingWebAuthRegistrationRequests()
        {
            var requests = new List<WebAuthRegistrationRequestSnapshot>();
            lock (_chatSessionLock)
            {
                var table = GetWebAuthRegistrationRequestsTable();
                foreach (object[] sourceRow in table.Rows)
                {
                    WebAuthRegistrationRequestRecord record = WebAuthRegistrationRequestRecordFromRow(sourceRow);
                    if (record.status.Equals("pending", StringComparison.OrdinalIgnoreCase))
                        requests.Add(WebAuthRegistrationRequestSnapshotFromRecord(record));
                }
            }

            requests.Sort((a, b) => string.CompareOrdinal(b.RequestedUtc, a.RequestedUtc));
            return requests;
        }

        public WebAuthRegistrationRequestSnapshot ApproveWebAuthRegistrationRequest(string requestId)
        {
            WebAuthRegistrationRequestRecord record = DecideWebAuthRegistrationRequest(requestId, approved: true, decidedBy: "admin", note: "");
            LogMessage("[WebAuth] Approved registration request for " + record.userName + " from " + record.clientIp + ".");
            return WebAuthRegistrationRequestSnapshotFromRecord(record);
        }

        public WebAuthRegistrationRequestSnapshot DenyWebAuthRegistrationRequest(string requestId, string note = "")
        {
            WebAuthRegistrationRequestRecord record = DecideWebAuthRegistrationRequest(requestId, approved: false, decidedBy: "admin", note: note ?? "");
            LogMessage("[WebAuth] Denied registration request for " + record.userName + " from " + record.clientIp + ".");
            return WebAuthRegistrationRequestSnapshotFromRecord(record);
        }

        public IReadOnlyList<TerminalPermissionRuleSnapshot> GetTerminalPermissionRulesDiagnostics(string ownerKey)
        {
            return GetTerminalPermissionRules(ownerKey);
        }

        public void RemoveTerminalPermissionRule(string ownerKey, string commandHash)
        {
            ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
            commandHash = (commandHash ?? "").Trim();
            if (string.IsNullOrWhiteSpace(commandHash))
                return;

            var ownerKeys = GetEquivalentFilesystemOwnerKeys(ownerKey);
            lock (_chatSessionLock)
            {
                var table = GetTerminalPermissionRulesTable();
                for (int i = table.Rows.Count - 1; i >= 0; i--)
                {
                    object[] row = NormalizeTerminalPermissionRuleRow(table.Rows[i]);
                    if (OwnerKeyListContains(ownerKeys, GetRowValue(row, 0)) &&
                        string.Equals(GetRowValue(row, 1), commandHash, StringComparison.OrdinalIgnoreCase))
                    {
                        table.Rows.RemoveAt(i);
                    }
                }

                _chatSessionData.Save();
            }
        }

        public ChatClientPermissionSnapshot GetChatClientPermissionsDiagnostics(string ownerKey)
        {
            ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
            return BuildChatClientPermissionSnapshot(ownerKey, GetChatPermissions(ownerKey));
        }

        public ChatClientPermissionSnapshot SaveChatClientPermissionsDiagnostics(ChatClientPermissionSnapshot snapshot)
        {
            if (snapshot == null)
                throw new ArgumentNullException(nameof(snapshot));
            string ownerKey = NormalizeChatFilesystemOwnerKey(snapshot.OwnerKey);
            ChatPermissionState permissions = ChatPermissionStateFromSnapshot(snapshot, GetChatPermissions(ownerKey));
            SaveChatPermissions(ownerKey, permissions);
            ApplyRuntimeChatPermissions(GetChatPermissions());
            return BuildChatClientPermissionSnapshot(ownerKey, GetChatPermissions(ownerKey));
        }

        public ChatClientPermissionSnapshot RestrictChatClient(string ownerKey, string restriction, TimeSpan? duration)
        {
            ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
            ChatPermissionState permissions = GetChatPermissions(ownerKey);
            DateTimeOffset now = DateTimeOffset.UtcNow;
            bool untilEnabled = !duration.HasValue || duration.Value <= TimeSpan.Zero;
            string until = untilEnabled ? "" : now.Add(duration.Value).ToString("O");
            if (string.Equals(restriction, "ban", StringComparison.OrdinalIgnoreCase))
            {
                permissions.bannedUntilUtc = until;
                permissions.banUntilEnabled = untilEnabled;
            }
            else
            {
                permissions.mutedUntilUtc = until;
                permissions.muteUntilEnabled = untilEnabled;
            }

            SaveChatPermissions(ownerKey, permissions);
            return BuildChatClientPermissionSnapshot(ownerKey, GetChatPermissions(ownerKey));
        }

        public ChatClientPermissionSnapshot EnableChatClient(string ownerKey)
        {
            ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
            ChatPermissionState permissions = GetChatPermissions(ownerKey);
            permissions.mutedUntilUtc = "";
            permissions.bannedUntilUtc = "";
            permissions.muteUntilEnabled = false;
            permissions.banUntilEnabled = false;
            SaveChatPermissions(ownerKey, permissions);
            return BuildChatClientPermissionSnapshot(ownerKey, GetChatPermissions(ownerKey));
        }

        private string NormalizeChatFilesystemOwnerKey(string ownerKey)
        {
            return string.IsNullOrWhiteSpace(ownerKey) ? GetDefaultLocalChatOwnerKey() : ownerKey.Trim();
        }

        private string BeginActivePromptSession(string source, string ownerKey, string requestBody)
        {
            string id = "prompt_" + Guid.NewGuid().ToString("N");
            DateTimeOffset now = DateTimeOffset.UtcNow;
            var state = new ActivePromptSessionState
            {
                Id = id,
                Source = string.IsNullOrWhiteSpace(source) ? "LLM Prompt" : source.Trim(),
                Title = InferPromptSessionTitle(requestBody),
                OwnerKey = NormalizeChatFilesystemOwnerKey(ownerKey),
                Model = ExtractJsonStringProperty(requestBody, "model") ?? ChatModel ?? "lm-studio",
                Status = "Running",
                Phase = "Processing prompt",
                StartedUtc = now,
                UpdatedUtc = now
            };

            lock (_activePromptSessionLock)
            {
                PruneInactivePromptSessionsLocked();
                _activePromptSessions[id] = state;
            }
            return id;
        }

        private void UpdateActivePromptSessionPhase(string id, string phase)
        {
            if (string.IsNullOrWhiteSpace(id))
                return;

            lock (_activePromptSessionLock)
            {
                if (_activePromptSessions.TryGetValue(id, out ActivePromptSessionState state))
                {
                    state.Phase = string.IsNullOrWhiteSpace(phase) ? state.Phase : phase.Trim();
                    state.UpdatedUtc = DateTimeOffset.UtcNow;
                }
            }
        }

        private void CompleteActivePromptSession(string id, string status)
        {
            if (string.IsNullOrWhiteSpace(id))
                return;

            lock (_activePromptSessionLock)
            {
                if (_activePromptSessions.TryGetValue(id, out ActivePromptSessionState state))
                {
                    DateTimeOffset now = DateTimeOffset.UtcNow;
                    state.Status = string.IsNullOrWhiteSpace(status) ? "Completed" : status.Trim();
                    state.Phase = state.Status;
                    state.UpdatedUtc = now;
                    state.CompletedUtc = now;
                }
            }
        }

        private void PruneInactivePromptSessionsLocked()
        {
            DateTimeOffset cutoff = DateTimeOffset.UtcNow - TimeSpan.FromMinutes(5);
            var remove = new List<string>();
            foreach (var pair in _activePromptSessions)
            {
                if (pair.Value.CompletedUtc.HasValue && pair.Value.CompletedUtc.Value < cutoff)
                    remove.Add(pair.Key);
            }

            foreach (string id in remove)
                _activePromptSessions.Remove(id);
        }

        private string InferPromptSessionTitle(string requestBody)
        {
            try
            {
                using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(requestBody) ? "{}" : requestBody))
                {
                    JsonElement root = document.RootElement;
                    if (root.ValueKind == JsonValueKind.Object &&
                        root.TryGetProperty("messages", out JsonElement messages) &&
                        messages.ValueKind == JsonValueKind.Array)
                    {
                        var messageList = new List<JsonElement>();
                        foreach (JsonElement message in messages.EnumerateArray())
                            messageList.Add(message);
                        for (int i = messageList.Count - 1; i >= 0; i--)
                        {
                            JsonElement message = messageList[i];
                            string role = ExtractStringProperty(message, "role") ?? "";
                            if (!role.Equals("user", StringComparison.OrdinalIgnoreCase))
                                continue;
                            string text = ExtractMessageTextForTitle(message);
                            if (!string.IsNullOrWhiteSpace(text))
                                return TruncateForLog(text.Replace("\r", " ").Replace("\n", " "), 72);
                        }
                    }

                    if (root.ValueKind == JsonValueKind.Object &&
                        root.TryGetProperty("input", out JsonElement input))
                    {
                        string text = input.ValueKind == JsonValueKind.String
                            ? input.GetString()
                            : ExtractResponsesContentText(input);
                        if (!string.IsNullOrWhiteSpace(text))
                            return TruncateForLog(text.Replace("\r", " ").Replace("\n", " "), 72);
                    }
                }
            }
            catch { }

            return "LLM prompt " + DateTime.Now.ToString("h:mm:ss tt");
        }

        private string GetHttpPromptOwnerKey(HttpListenerRequest request)
        {
            try
            {
                string ip = request?.RemoteEndPoint?.Address?.ToString();
                if (!string.IsNullOrWhiteSpace(ip))
                    return "ip:" + NormalizeClientIp(ip);
            }
            catch { }

            return GetDefaultLocalChatOwnerKey();
        }

