            server.OnError += RelaySocketJackError;
            ChatPermissionState chatPermissions = GetChatPermissions();
            server.RegisterProtocol(new SocketJack.Net.Database.TdsProtocolHandler(_chatSessionData));
            server.SqlAdminPanelEnabled = chatPermissions.sqlAdmin;
            server.IndexPageHtml = null;
            server.RouteFile("GET", "/", GetChatUiHtmlPath(), new[] {
                new[] { "CHAT_MODEL", WebUtility.HtmlEncode(string.IsNullOrWhiteSpace(ChatModel) ? "lm-studio" : ChatModel) },
                new[] { "LM_ENDPOINT", WebUtility.HtmlEncode($"http://{_lmStudioHost}:{_lmStudioPort}/v1/chat/completions") }
            }, 0);
            server.Robots = "User-agent: *\nDisallow: /\n";

            server.Map("GET", "/health", (connection, request, cancellationToken) =>
                JsonSerializer.Serialize(new
                {
                    ok = true,
                    proxyPort = _proxyPort,
                    lmStudioEndpoint = $"http://{_lmStudioHost}:{_lmStudioPort}/v1/chat/completions",
                    chatModel = ChatModel,
                    database = new
