        private string HandleChatUiModelsRequest(CancellationToken cancellationToken)
        {
            try
            {
                string url = $"http://{_lmStudioHost}:{_lmStudioPort}/v1/models";
                using (var timeoutCts = CancellationTokenSource.CreateLinkedTokenSource(cancellationToken))
                {
                    timeoutCts.CancelAfter(ChatModelListTimeout);
                    using (var response = _httpClient.GetAsync(url, timeoutCts.Token).GetAwaiter().GetResult())
                    {
                        string responseBody = response.Content == null ? "" : response.Content.ReadAsStringAsync().GetAwaiter().GetResult();
                        if (!response.IsSuccessStatusCode)
                        {
                            LogMessage($"[Chat UI] LM Studio models request returned {(int)response.StatusCode} {response.ReasonPhrase}: {TruncateForLog(responseBody, 1000)}");
                            return JsonSerializer.Serialize(new
                            {
                                ok = true,
                                selected = string.IsNullOrWhiteSpace(ChatModel) ? "lm-studio" : ChatModel,
                                modelListAvailable = false,
                                warning = "LM Studio is reachable, but /v1/models returned HTTP " + (int)response.StatusCode + " " + response.ReasonPhrase + ".",
                                models = BuildChatModelInfos(new List<string> { string.IsNullOrWhiteSpace(ChatModel) ? "lm-studio" : ChatModel })
                            });
                        }

                        var models = ExtractModelInfos(responseBody);
                        if (models.Count == 0)
                            models.Add(BuildChatModelInfo(string.IsNullOrWhiteSpace(ChatModel) ? "lm-studio" : ChatModel));

                        return JsonSerializer.Serialize(new
                        {
                            ok = true,
                            selected = string.IsNullOrWhiteSpace(ChatModel) ? "lm-studio" : ChatModel,
                            modelListAvailable = true,
                            models
                        });
                    }
                }
            }
            catch (OperationCanceledException)
            {
                LogMessage("[Chat UI] Models request timed out after " + ChatModelListTimeout.TotalSeconds.ToString("0", CultureInfo.InvariantCulture) + "s; using configured model.");
                return JsonSerializer.Serialize(new
                {
                    ok = true,
                    selected = string.IsNullOrWhiteSpace(ChatModel) ? "lm-studio" : ChatModel,
                    modelListAvailable = false,
                    warning = "LM Studio model list timed out; using the configured model.",
                    models = BuildChatModelInfos(new List<string> { string.IsNullOrWhiteSpace(ChatModel) ? "lm-studio" : ChatModel })
                });
            }
            catch (Exception ex)
            {
                LogMessage($"[Chat UI] Models request failed: {ex.Message}");
                return JsonSerializer.Serialize(new
                {
                    ok = false,
                    error = ex.Message,
                    models = BuildChatModelInfos(new List<string> { string.IsNullOrWhiteSpace(ChatModel) ? "lm-studio" : ChatModel })
                });
            }
        }

        private string HandleChatServicesRequest(NetworkConnection connection, HttpRequest request)
        {
            try
            {
                string ownerKey = GetChatSessionOwnerKey(connection, request);
                ChatPermissionState permissions = GetChatPermissions(ownerKey);
                return JsonSerializer.Serialize(new
                {
                    ok = true,
                    canEdit = IsDatabaseAdministrator(connection, request),
                    services = BuildChatServiceCatalog(permissions)
                });
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] Service catalog load failed: " + ex.Message);
                return JsonSerializer.Serialize(new { ok = false, error = ex.Message });
            }
        }

        private string HandleWebAuthCorsPreflight(HttpRequest request)
        {
            AddWebAuthCorsHeaders(request);
            SetHttpStatus(request, 204, "No Content");
            return "";
        }

        private string HandleWebAuthRegisterRequest(NetworkConnection connection, HttpRequest request)
        {
            AddWebAuthCorsHeaders(request);
            try
            {
                bool localAdmin = IsLocalAdmin(connection, request);
                bool openRegistration = AllowOpenRegistration;
                if (!localAdmin && !openRegistration)
                {
                    return BuildJsonError(request, 403, "Forbidden",
                        "Open registration is disabled. Send a registration request for administrator approval.");
                }

                string body = request?.Body ?? "{}";
                using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
                {
                    JsonElement root = document.RootElement;
                    string username = ExtractStringProperty(root, "username") ??
                                      ExtractStringProperty(root, "user") ??
                                      ExtractStringProperty(root, "login");
                    string password = ExtractStringProperty(root, "password") ??
                                      ExtractStringProperty(root, "pass");
                    bool overwrite = localAdmin &&
                                     root.TryGetProperty("overwrite", out JsonElement overwriteElement) &&
                                     ReadJsonBool(overwriteElement, false);

                    if (!TryNormalizeWebAuthUserName(username, out string normalizedUserName, out string userError))
                        return BuildJsonError(request, 400, "Bad Request", userError);
                    if (!IsValidWebAuthPassword(password, out string passwordError))
                        return BuildJsonError(request, 400, "Bad Request", passwordError);

                    WebAuthRecord record = CreateWebAuthRecord(normalizedUserName, password);
                    record.lastClientIp = ExtractClientIp(connection, request) ?? "";
                    if (localAdmin &&
                        ((root.TryGetProperty("isAdministrator", out JsonElement isAdministratorElement) &&
                          ReadJsonBool(isAdministratorElement, false)) ||
                         (root.TryGetProperty("administrator", out JsonElement administratorElement) &&
                          ReadJsonBool(administratorElement, false)) ||
                         !HasAnyWebAuthAdministrator()))
                    {
                        record.isAdministrator = true;
                    }
                    bool created = SaveWebAuthRecord(record, overwrite);
                    if (!created && !overwrite)
                        return BuildJsonError(request, 409, "Conflict", "A WebAuth user with that name already exists.");

                    string token = "";
                    DateTimeOffset expires = DateTimeOffset.UtcNow.Add(WebAuthTokenLifetime);
                    if (!localAdmin)
                    {
                        token = GenerateWebAuthToken();
                        record.tokenHash = HashWebAuthToken(token);
                        record.tokenExpiresUtc = expires.ToString("O");
                        UpsertWebAuthRecord(record);
                        SetWebAuthCookie(request, token, expires);
                        LinkWebAuthUserToIp(record.userName, record.lastClientIp);
                    }

                    return JsonSerializer.Serialize(new
                    {
                        ok = true,
                        authenticated = !localAdmin,
                        username = normalizedUserName,
                        isAdministrator = record.isAdministrator,
                        created = created,
                        overwritten = !created && overwrite,
                        canRegisterRemotely = openRegistration,
                        tokenType = string.IsNullOrWhiteSpace(token) ? "" : "Bearer",
                        accessToken = token,
                        expiresUtc = string.IsNullOrWhiteSpace(token) ? "" : record.tokenExpiresUtc,
                        usage = BuildChatUsageSnapshot("webauth:" + normalizedUserName.ToLowerInvariant(), record),
                        table = WebAuthDatabaseName + "." + WebAuthUsersTableName
                    });
                }
            }
            catch (Exception ex)
            {
                LogMessage("[WebAuth] Register failed: " + ex.Message);
                return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
            }
        }

        private string HandleWebAuthRegistrationRequest(NetworkConnection connection, HttpRequest request)
        {
            AddWebAuthCorsHeaders(request);
            try
            {
                string body = request?.Body ?? "{}";
                using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
                {
                    JsonElement root = document.RootElement;
                    string username = ExtractStringProperty(root, "username") ??
                                      ExtractStringProperty(root, "user") ??
                                      ExtractStringProperty(root, "login");
                    string password = ExtractStringProperty(root, "password") ??
                                      ExtractStringProperty(root, "pass");

                    if (!TryNormalizeWebAuthUserName(username, out string normalizedUserName, out string userError))
                        return BuildJsonError(request, 400, "Bad Request", userError);
                    if (!IsValidWebAuthPassword(password, out string passwordError))
                        return BuildJsonError(request, 400, "Bad Request", passwordError);
                    if (GetWebAuthRecord(normalizedUserName) != null)
                        return BuildJsonError(request, 409, "Conflict", "A WebAuth user with that name already exists.");

                    string clientIp = ExtractClientIp(connection, request) ?? "";
                    if (AllowOpenRegistration || IsLocalAdmin(connection, request))
                    {
                        WebAuthRecord record = CreateWebAuthRecord(normalizedUserName, password);
                        record.lastClientIp = clientIp;
                        if (IsLocalAdmin(connection, request) && !HasAnyWebAuthAdministrator())
                            record.isAdministrator = true;
                        if (!SaveWebAuthRecord(record, overwrite: false))
                            return BuildJsonError(request, 409, "Conflict", "A WebAuth user with that name already exists.");

                        string token = GenerateWebAuthToken();
                        DateTimeOffset expires = DateTimeOffset.UtcNow.Add(WebAuthTokenLifetime);
                        record.tokenHash = HashWebAuthToken(token);
                        record.tokenExpiresUtc = expires.ToString("O");
                        UpsertWebAuthRecord(record);
                        SetWebAuthCookie(request, token, expires);
                        LinkWebAuthUserToIp(record.userName, clientIp);

                        return JsonSerializer.Serialize(new
                        {
                            ok = true,
                            authenticated = true,
                            registered = true,
                            pending = false,
                            username = record.userName,
                            isAdministrator = record.isAdministrator,
                            tokenType = "Bearer",
                            accessToken = token,
                            expiresUtc = record.tokenExpiresUtc,
                            usage = BuildChatUsageSnapshot("webauth:" + record.userName.ToLowerInvariant(), record)
                        });
                    }

                    WebAuthRegistrationRequestRecord registration = SaveWebAuthRegistrationRequest(normalizedUserName, password, clientIp);
                    WebAuthRegistrationRequestSnapshot snapshot = WebAuthRegistrationRequestSnapshotFromRecord(registration);
                    LogMessage("[WebAuth] Registration request from " + snapshot.ClientIp + " for " + snapshot.UserName + ".");
                    WebAuthRegistrationRequested?.Invoke(this, new WebAuthRegistrationRequestEventArgs(snapshot));

                    return JsonSerializer.Serialize(new
                    {
                        ok = true,
                        authenticated = false,
                        registered = false,
                        pending = true,
                        requestId = snapshot.Id,
                        username = snapshot.UserName,
                        message = "Registration request sent. An administrator must approve it before you can sign in."
                    });
                }
            }
            catch (Exception ex)
            {
                LogMessage("[WebAuth] Registration request failed: " + ex.Message);
                return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
            }
        }

        private string HandleWebAuthLoginRequest(NetworkConnection connection, HttpRequest request)
        {
            AddWebAuthCorsHeaders(request);
            try
            {
                string body = request?.Body ?? "{}";
                using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
                {
                    JsonElement root = document.RootElement;
                    string username = ExtractStringProperty(root, "username") ??
                                      ExtractStringProperty(root, "user") ??
                                      ExtractStringProperty(root, "login");
                    string password = ExtractStringProperty(root, "password") ??
                                      ExtractStringProperty(root, "pass");

                    if (!TryValidateWebAuthCredentials(username, password, out WebAuthRecord record, out string error))
                        return BuildJsonError(request, 401, "Unauthorized", error);

                    string token = GenerateWebAuthToken();
                    DateTimeOffset expires = DateTimeOffset.UtcNow.Add(WebAuthTokenLifetime);
                    record.tokenHash = HashWebAuthToken(token);
                    record.tokenExpiresUtc = expires.ToString("O");
                    record.lastLoginUtc = DateTimeOffset.UtcNow.ToString("O");
                    record.lastClientIp = ExtractClientIp(connection, request) ?? "";
                    record.updatedUtc = DateTimeOffset.UtcNow.ToString("O");
                    UpsertWebAuthRecord(record);
                    SetWebAuthCookie(request, token, expires);
                    LinkWebAuthUserToIp(record.userName, record.lastClientIp);

                    return JsonSerializer.Serialize(new
                    {
                        ok = true,
                        username = record.userName,
                        isAdministrator = record.isAdministrator,
                        tokenType = "Bearer",
                        accessToken = token,
                        expiresUtc = record.tokenExpiresUtc,
                        usage = BuildChatUsageSnapshot("webauth:" + record.userName.ToLowerInvariant(), record)
                    });
                }
            }
            catch (Exception ex)
            {
                LogMessage("[WebAuth] Login failed: " + ex.Message);
                return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
            }
        }

        private string HandleWebAuthLogoutRequest(NetworkConnection connection, HttpRequest request)
        {
            AddWebAuthCorsHeaders(request);
            try
            {
                if (!TryAuthenticateWebAuthRequest(request, out WebAuthPrincipal principal, out string error))
                    return BuildJsonError(request, 401, "Unauthorized", error);

                ClearWebAuthToken(principal.UserName);
                ClearWebAuthCookie(request);
                return JsonSerializer.Serialize(new
                {
                    ok = true,
                    username = principal.UserName,
                    loggedOut = true
                });
            }
            catch (Exception ex)
            {
                LogMessage("[WebAuth] Logout failed: " + ex.Message);
                return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
            }
        }

        private string HandleWebAuthSessionRequest(NetworkConnection connection, HttpRequest request)
        {
            AddWebAuthCorsHeaders(request);
            try
            {
                if (TryAuthenticateWebAuthRequest(request, out WebAuthPrincipal principal, out _))
                {
                    string authOwnerKey = "webauth:" + principal.UserName.ToLowerInvariant();
                    WebAuthRecord record = GetWebAuthRecord(principal.UserName);
                    LinkWebAuthUserToIp(principal.UserName, ExtractClientIp(connection, request) ?? "");
                    return JsonSerializer.Serialize(new
                    {
                        ok = true,
                        authenticated = true,
                        username = principal.UserName,
                        authType = principal.AuthType,
                        expiresUtc = principal.ExpiresUtc,
                        ownerKey = authOwnerKey,
                        isAdministrator = record != null && record.enabled && record.isAdministrator,
                        canRegisterOpen = AllowOpenRegistration,
                        usage = BuildChatUsageSnapshot(authOwnerKey, record),
                        table = WebAuthDatabaseName + "." + WebAuthUsersTableName
                    });
                }

                if (IsLocalAdmin(connection, request))
                {
                    string ownerKey = GetChatSessionOwnerKey(connection, request);
                    return JsonSerializer.Serialize(new
                    {
                        ok = true,
                        authenticated = true,
                        username = "localhost",
                        authType = "Localhost",
                        expiresUtc = "",
                        ownerKey,
                        isAdministrator = false,
                        canRegisterOpen = AllowOpenRegistration,
                        usage = BuildAdminChatUsageSnapshot(ownerKey),
                        table = WebAuthDatabaseName + "." + WebAuthUsersTableName
                    });
                }

                return JsonSerializer.Serialize(new
                {
                    ok = true,
                    authenticated = false,
                    isAdministrator = false,
                    canRegisterOpen = AllowOpenRegistration,
                    usage = BuildAnonymousChatUsageSnapshot(),
                    table = WebAuthDatabaseName + "." + WebAuthUsersTableName
                });
            }
            catch (Exception ex)
            {
                LogMessage("[WebAuth] Session check failed: " + ex.Message);
                return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
            }
        }

        private string HandleWebAuthTokenLimitRequest(NetworkConnection connection, HttpRequest request)
        {
            AddWebAuthCorsHeaders(request);
            try
            {
                if (!IsLocalAdmin(connection, request))
                    return BuildJsonError(request, 403, "Forbidden", "Token limits can only be changed from localhost or 127.0.0.1.");

                string body = request?.Body ?? "{}";
                using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
                {
                    JsonElement root = document.RootElement;
                    string username = ExtractStringProperty(root, "username") ??
                                      ExtractStringProperty(root, "user") ??
                                      ExtractStringProperty(root, "login");
                    string action = (ExtractStringProperty(root, "action") ?? "add").Trim().ToLowerInvariant();
                    long tokens = root.TryGetProperty("tokens", out JsonElement tokensElement)
                        ? ReadJsonLong(tokensElement, 0)
                        : 0;

                    if (!TryNormalizeWebAuthUserName(username, out string normalizedUserName, out string userError))
                        return BuildJsonError(request, 400, "Bad Request", userError);

                    WebAuthRecord record = GetWebAuthRecord(normalizedUserName);
                    if (record == null)
                        return BuildJsonError(request, 404, "Not Found", "WebAuth user was not found.");

                    if (action.Equals("set", StringComparison.OrdinalIgnoreCase))
                    {
                        record.tokenLimit = Math.Max(0, tokens);
                    }
                    else if (action.Equals("reset", StringComparison.OrdinalIgnoreCase))
                    {
                        record.tokensUsed = 0;
                    }
                    else
                    {
                        record.tokenLimit = Math.Max(0, record.tokenLimit + Math.Max(0, tokens));
                    }

                    record.updatedUtc = DateTimeOffset.UtcNow.ToString("O");
                    UpsertWebAuthRecord(record);
                    string ownerKey = "webauth:" + record.userName.ToLowerInvariant();
                    return JsonSerializer.Serialize(new
                    {
                        ok = true,
                        username = record.userName,
                        usage = BuildChatUsageSnapshot(ownerKey, record)
                    });
                }
            }
            catch (Exception ex)
            {
                LogMessage("[WebAuth] Token limit update failed: " + ex.Message);
                return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
            }
        }

