        private string HandleChatCostsSaveRequest(NetworkConnection connection, HttpRequest request)
        {
            AddWebAuthCorsHeaders(request);
            try
            {
                if (!IsLocalAdmin(connection, request))
                    return BuildJsonError(request, 403, "Forbidden", "Cost settings can only be changed from localhost or 127.0.0.1.");

                ChatCostSettings settings = GetChatCostSettings();
                string body = request?.Body ?? "{}";
                using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
                {
                    JsonElement root = document.RootElement;
                    if (root.TryGetProperty("tokenUsdPerToken", out JsonElement tokenUsdPerToken))
                        settings.tokenUsdPerToken = Math.Max(0, ReadJsonDouble(tokenUsdPerToken, settings.tokenUsdPerToken));
                    if (root.TryGetProperty("tokenUsdPerThousand", out JsonElement tokenUsdPerThousand))
                        settings.tokenUsdPerToken = Math.Max(0, ReadJsonDouble(tokenUsdPerThousand, settings.tokenUsdPerToken * 1000.0) / 1000.0);
                    if (root.TryGetProperty("electricityCentsPerKwh", out JsonElement electricityCents))
                        settings.electricityCentsPerKwh = Math.Max(0, ReadJsonDouble(electricityCents, settings.electricityCentsPerKwh));
                    if (root.TryGetProperty("electricityMultiplier", out JsonElement electricityMultiplier))
                        settings.electricityMultiplier = Math.Max(0, ReadJsonDouble(electricityMultiplier, settings.electricityMultiplier));
                    if (root.TryGetProperty("gpuTdpWatts", out JsonElement gpuTdpWatts))
                        settings.gpuTdpWatts = Math.Max(0, ReadJsonDouble(gpuTdpWatts, settings.gpuTdpWatts));
                    if (root.TryGetProperty("cpuTdpWatts", out JsonElement cpuTdpWatts))
                        settings.cpuTdpWatts = Math.Max(0, ReadJsonDouble(cpuTdpWatts, settings.cpuTdpWatts));
                    if (root.TryGetProperty("ramWattsPerGb", out JsonElement ramWattsPerGb))
                        settings.ramWattsPerGb = Math.Max(0, ReadJsonDouble(ramWattsPerGb, settings.ramWattsPerGb));
                    if (root.TryGetProperty("systemWatts", out JsonElement systemWatts))
                        settings.systemWatts = Math.Max(0, ReadJsonDouble(systemWatts, settings.systemWatts));
                    if (root.TryGetProperty("ioWattsPerGbps", out JsonElement ioWattsPerGbps))
                        settings.ioWattsPerGbps = Math.Max(0, ReadJsonDouble(ioWattsPerGbps, settings.ioWattsPerGbps));
                    if (root.TryGetProperty("serviceTaxRate", out JsonElement serviceTaxRate))
                        settings.serviceTaxRate = Math.Max(0, ReadJsonDouble(serviceTaxRate, settings.serviceTaxRate));
                    if (root.TryGetProperty("serviceTaxPercent", out JsonElement serviceTaxPercent))
                        settings.serviceTaxRate = Math.Max(0, ReadJsonDouble(serviceTaxPercent, settings.serviceTaxRate * 100.0) / 100.0);
                    if (root.TryGetProperty("storageType", out JsonElement storageType))
                        settings.storageType = NormalizeStorageType(ExtractJsonString(storageType));
                    if (root.TryGetProperty("storageCostFactor", out JsonElement storageCostFactor))
                        settings.storageCostFactor = ClampStorageCostFactor(ReadJsonDouble(storageCostFactor, settings.storageCostFactor));
                    if (root.TryGetProperty("storageLimitBytes", out JsonElement storageLimitBytes))
                        settings.storageLimitBytes = Math.Max(0, ReadJsonLong(storageLimitBytes, settings.storageLimitBytes));
                    if (root.TryGetProperty("allowOpenRegistration", out JsonElement allowOpenRegistration))
                        settings.allowOpenRegistration = ReadJsonBool(allowOpenRegistration, settings.allowOpenRegistration);

                    SaveChatCostSettings(settings);
                }

                string ownerKey = GetChatSessionOwnerKey(connection, request);
                return JsonSerializer.Serialize(new
                {
                    ok = true,
                    settings = GetChatCostSettings(),
                    usage = GetChatUsageSnapshot(ownerKey)
                });
            }
            catch (Exception ex)
            {
                LogMessage("[Chat Costs] Save failed: " + ex.Message);
                return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
            }
        }

