        private LmVsProxyScreenCaptureOptions ReadScreenCaptureOptions(HttpRequest request)
        {
            var options = new LmVsProxyScreenCaptureOptions();

            if (request?.QueryParameters != null)
            {
                if (request.QueryParameters.TryGetValue("target", out string target))
                    options.Target = target;
                if (request.QueryParameters.TryGetValue("quality", out string quality))
                    options.Quality = ParseStoredInt(quality, options.Quality);
                if (request.QueryParameters.TryGetValue("maxWidth", out string maxWidth))
                    options.MaxWidth = ParseStoredInt(maxWidth, options.MaxWidth);
                if (request.QueryParameters.TryGetValue("maxHeight", out string maxHeight))
                    options.MaxHeight = ParseStoredInt(maxHeight, options.MaxHeight);
            }

            string body = request?.Body ?? "";
            if (!string.IsNullOrWhiteSpace(body))
            {
                using (JsonDocument document = JsonDocument.Parse(body))
                {
                    JsonElement root = document.RootElement;
                    if (root.ValueKind == JsonValueKind.Object)
                    {
                        if (root.TryGetProperty("target", out JsonElement target))
                            options.Target = ExtractJsonString(target) ?? options.Target;
                        if (root.TryGetProperty("quality", out JsonElement quality))
                            options.Quality = ReadJsonInt(quality, options.Quality);
                        if (root.TryGetProperty("maxWidth", out JsonElement maxWidth))
                            options.MaxWidth = ReadJsonInt(maxWidth, options.MaxWidth);
                        if (root.TryGetProperty("maxHeight", out JsonElement maxHeight))
                            options.MaxHeight = ReadJsonInt(maxHeight, options.MaxHeight);
                    }
                }
            }

            options.Quality = Math.Max(1, Math.Min(100, options.Quality));
            options.MaxWidth = Math.Max(0, options.MaxWidth);
            options.MaxHeight = Math.Max(0, options.MaxHeight);
            if (string.IsNullOrWhiteSpace(options.Target))
                options.Target = "admin";
            return options;
        }

        private LmVsProxyScreenCaptureResult CaptureScreenForRemoteControl(LmVsProxyScreenCaptureOptions options)
        {
            var captureProvider = LmVsProxyRemoteControl.CaptureScreen;
            if (captureProvider == null)
                throw new NotSupportedException("SocketJack.WPF remote screen capture is not registered. Use SocketJack.WPF and register a WPF element for capture.");

            LmVsProxyScreenCaptureResult capture = captureProvider(options ?? new LmVsProxyScreenCaptureOptions());
            if (capture == null || capture.Bytes == null || capture.Bytes.Length == 0)
                throw new InvalidOperationException("SocketJack.WPF did not return a screen capture.");
            if (string.IsNullOrWhiteSpace(capture.MimeType))
                capture.MimeType = "image/jpeg";
            return capture;
        }

        private LmVsProxyRemoteInputResult ExecuteRemoteInput(JsonElement root)
        {
            var inputProvider = LmVsProxyRemoteControl.ExecuteInput;
            if (inputProvider == null)
                throw new NotSupportedException("SocketJack.WPF remote input is not registered. Use SocketJack.WPF to enable mouse control.");

            LmVsProxyRemoteInputRequest input = ReadRemoteInputRequest(root);
            return inputProvider(input);
        }

        private LmVsProxyRemoteInputRequest ReadRemoteInputRequest(JsonElement root)
        {
            var request = new LmVsProxyRemoteInputRequest();
            if (root.ValueKind != JsonValueKind.Object)
                return request;

            if (root.TryGetProperty("action", out JsonElement action))
                request.Action = ExtractJsonString(action) ?? request.Action;
            if (root.TryGetProperty("button", out JsonElement button))
                request.Button = ExtractJsonString(button) ?? request.Button;
            if (root.TryGetProperty("text", out JsonElement text))
                request.Text = ExtractJsonString(text) ?? request.Text;
            if (root.TryGetProperty("key", out JsonElement key))
                request.Key = ExtractJsonString(key) ?? request.Key;
            if (root.TryGetProperty("normalized", out JsonElement normalized))
                request.Normalized = ReadJsonBool(normalized, request.Normalized);
            if (root.TryGetProperty("x", out JsonElement x))
            {
                request.X = ReadJsonDouble(x, request.X);
                request.HasPoint = true;
            }
            if (root.TryGetProperty("y", out JsonElement y))
            {
                request.Y = ReadJsonDouble(y, request.Y);
                request.HasPoint = true;
            }
            if (root.TryGetProperty("toX", out JsonElement toX))
            {
                request.ToX = ReadJsonDouble(toX, request.ToX);
                request.HasTargetPoint = true;
            }
            if (root.TryGetProperty("toY", out JsonElement toY))
            {
                request.ToY = ReadJsonDouble(toY, request.ToY);
                request.HasTargetPoint = true;
            }
            if (root.TryGetProperty("durationMs", out JsonElement durationMs))
                request.DurationMs = ReadJsonInt(durationMs, request.DurationMs);
            if (root.TryGetProperty("steps", out JsonElement steps))
                request.Steps = ReadJsonInt(steps, request.Steps);
            if (root.TryGetProperty("delta", out JsonElement delta))
                request.Delta = ReadJsonInt(delta, request.Delta);

            request.DurationMs = Math.Max(0, Math.Min(30000, request.DurationMs));
            request.Steps = Math.Max(1, Math.Min(240, request.Steps));
            if (string.IsNullOrWhiteSpace(request.Action))
                request.Action = "move";
            if (string.IsNullOrWhiteSpace(request.Button))
                request.Button = "left";
            return request;
        }

        private List<ChatUiModelInfo> BuildChatModelInfos(List<string> modelIds)
        {
            var result = new List<ChatUiModelInfo>();
            foreach (string id in modelIds ?? new List<string>())
            {
                if (string.IsNullOrWhiteSpace(id))
                    continue;

                result.Add(new ChatUiModelInfo
                {
                    id = id,
                    supportsImages = ModelLikelySupportsImages(id),
                    supportsTools = ModelLikelySupportsTools(id)
                });
            }
            return result;
        }

        private ChatUiModelInfo BuildChatModelInfo(string modelId)
        {
            return new ChatUiModelInfo
            {
                id = modelId,
                supportsImages = ModelLikelySupportsImages(modelId),
                supportsTools = ModelLikelySupportsTools(modelId)
            };
        }

        private List<ChatUiServiceInfo> BuildChatServiceCatalog(ChatPermissionState permissions)
        {
            bool internetSearchEnabled = permissions != null && permissions.internetSearch;
            bool agentEnabled = permissions == null || (permissions.agentAccess && permissions.vsCopilotTools);
            bool vsToolsEnabled = permissions == null || permissions.vsCopilotTools;

            return new List<ChatUiServiceInfo> {
                new ChatUiServiceInfo {
                    id = "agent",
                    name = "Agent",
                    kind = "Agent",
                    source = "LmVsProxy VS tools",
                    permission = "agentAccess",
                    enabled = agentEnabled,
                    description = "Agent mode with local VS-style read, write, replace, search, and list tools when permission is enabled."
                },
                new ChatUiServiceInfo {
                    id = "internet_search",
                    name = "Internet Search",
                    kind = "Service",
                    source = "Net/Services/SearchInternet.cs",
                    permission = "internetSearch",
                    enabled = internetSearchEnabled,
                    description = "Raw JSON internet search service used by /s and the proxy internet_search tool."
                },
                new ChatUiServiceInfo {
                    id = "search_service",
                    name = "Search Service",
                    kind = "Service",
                    source = "Net/Services/SearchService.cs",
                    permission = "internetSearch",
                    enabled = internetSearchEnabled,
                    description = "Underlying web, image, video, download, and package lookup provider."
                },
                new ChatUiServiceInfo {
                    id = "reflection_service",
                    name = "Reflection Service",
                    kind = "Service",
                    source = "Net/Services/ReflectionService.cs",
                    permission = "vsCopilotTools",
                    enabled = vsToolsEnabled,
                    description = "Loaded assembly and type inspection service for /reflect-style commands."
                },
                new ChatUiServiceInfo {
                    id = "prompt_intellisense",
                    name = "Prompt Intellisense",
                    kind = "Service",
                    source = "Net/Services/PromptIntellisense.cs",
                    permission = "",
                    enabled = true,
                    description = "Command, parameter, and path completion metadata for the browser chat prompt."
                }
            };
        }

        private string BuildAvailableChatServicesSystemHint(ChatPermissionState permissions)
        {
            permissions ??= GetChatPermissions();

            var services = new List<string>
            {
                "Prompt Intellisense is available in the Web UI composer for completions, slash-command discovery, file/path suggestions, and parameter hints.",
                "Slash commands are UI commands the user can type in the composer, such as /help, /commands, /s <query>, /i <query>, /yt <query>, and /fs read <file>. You can suggest them to the user, but do not claim you executed a slash command unless it appears in the conversation or a tool result.",
                "Saved sessions and the session files area are available; uploaded, downloaded, and generated files should stay tied to the current session."
            };

            if (permissions != null && permissions.imageUploads)
                services.Add("Image attachments are allowed for this session when the selected model supports images.");
            if (permissions != null && permissions.fileUploads)
                services.Add("File uploads are allowed; uploaded files are stored in the current session file store.");
            if (permissions != null && permissions.agentAccess && permissions.vsCopilotTools)
                services.Add("Agent mode is allowed; when Service is set to Agent, VS-style file read/write/replace/search/list tools can be used.");
            else if (permissions != null && !permissions.agentAccess)
                services.Add("Agent mode is disabled for this session; answer normally and do not claim local agent actions are available.");
            if (permissions != null && permissions.internetSearch)
                services.Add("Internet/search services are enabled; in Agent mode use internet_search, nuget_search, nuget_package_info, or github_code_search for current external lookup.");
            if (permissions != null && permissions.fileDownloads)
                services.Add("File download service is enabled; in Agent mode download_file can save HTTP/HTTPS files into the current session Downloads folder.");
            if (permissions != null && permissions.terminalCommands)
                services.Add(permissions.terminalForeverApproved
                    ? "Terminal commands are enabled and forever approved for this session; use run_command_in_terminal only when Agent or Terminal service is active and command execution is genuinely needed."
                    : "Terminal commands are enabled but may require approval in the LmVsProxy GUI; use run_command_in_terminal only when Agent or Terminal service is active and command execution is genuinely needed.");
            else
                services.Add("Terminal commands are disabled for this session.");
            if (permissions != null && permissions.ftpServer)
                services.Add(BuildFtpServiceAvailabilityText());
            if (permissions != null && permissions.sqlAdmin)
                services.Add("SQL Admin is enabled for the chat database at /sql.");

            services.Add("Port forwarding is managed by the WPF GUI, not by the model. When enabled there, the intended forwarded TCP ports are 11436 for the Web UI and 2121 for FTP.");
            services.Add("Respect disabled permissions: do not claim to have used a service that is unavailable or only present as a UI affordance.");

            return "[LmVsProxy session services] " + string.Join(" ", services);
        }

        private string BuildFtpServiceAvailabilityText()
        {
            lock (_chatFtpServerLock)
            {
                if (_chatFtpServer != null && _chatFtpServer.IsListening && _activeChatFtpConfig != null)
                {
                    int port = NormalizeFtpPort(_activeChatFtpConfig.port);
                    string rootPath = string.IsNullOrWhiteSpace(_activeChatFtpConfig.rootPath)
                        ? "the configured accessible directory"
                        : _activeChatFtpConfig.rootPath;
                    return "FTP server permission is enabled and FTP is currently running at ftp://localhost:" + port.ToString(CultureInfo.InvariantCulture) + "/ for " + rootPath + ".";
                }
            }

            return "FTP server permission is enabled; it can be configured from /FTP and defaults to port 2121 when started.";
        }

        private string BuildSelectedChatServiceSystemHint(string serviceId, ChatPermissionState permissions = null)
        {
            if (string.IsNullOrWhiteSpace(serviceId))
                return "";

            permissions ??= GetChatPermissions();
            ChatUiServiceInfo service = BuildChatServiceCatalog(permissions)
                .Find(item => item != null && string.Equals(item.id, serviceId, StringComparison.OrdinalIgnoreCase));
            if (service == null)
                return "";

            if (!string.IsNullOrWhiteSpace(service.permission) && !service.enabled)
                return "[LmVsProxy service selection] The Web UI Service dropdown selected " + service.name +
                       ", but its permission is disabled. Answer normally and do not claim that service ran.";

            if (string.Equals(service.id, "agent", StringComparison.OrdinalIgnoreCase))
            {
                return "[LmVsProxy service selection] The Web UI Service dropdown selected Agent. " +
                       "Operate like an agent: inspect files before editing, use exact replacements, and summarize changed files. " +
                       "Create generated files only inside the current session files folder. " +
                       "Use internet search only when its separate permission is enabled and the user asks for current web information.";
            }

            if (string.Equals(service.id, "terminal", StringComparison.OrdinalIgnoreCase))
            {
                return "[LmVsProxy service selection] The Web UI Service dropdown selected Terminal. " +
                       "Use run_command_in_terminal for PowerShell, console, terminal, or shell commands. " +
                       "Do not invent command-specific tool names such as netstat; pass the full command string to run_command_in_terminal. " +
                       "Every command may require approval in the LmVsProxy GUI before it runs.";
            }

            return "[LmVsProxy service selection] The Web UI Service dropdown selected " + service.name +
                   " (" + service.kind + "). Use this service context when it is relevant.";
        }

