        private ActiveChatStreamCancellation RegisterActiveChatStreamCancellation(string ownerKey, string streamId)
        {
            ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
            streamId = NormalizeChatUiStreamId(streamId);
            var active = new ActiveChatStreamCancellation
            {
                OwnerKey = ownerKey,
                StreamId = streamId,
                Cancellation = new CancellationTokenSource(),
                StartedUtc = DateTimeOffset.UtcNow
            };

            lock (_activeChatStreamCancellationLock)
            {
                PruneActiveChatStreamCancellationsLocked();
                string key = BuildActiveChatStreamCancellationKey(ownerKey, streamId);
                if (_activeChatStreamCancellations.TryGetValue(key, out ActiveChatStreamCancellation existing))
                    existing.Cancellation.Cancel();
                _activeChatStreamCancellations[key] = active;
                if (_pendingChatStreamStops.Remove(key))
                    active.Cancellation.Cancel();
            }

            return active;
        }

        private bool CancelActiveChatStream(string ownerKey, string streamId)
        {
            ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
            streamId = NormalizeChatUiStreamId(streamId);
            lock (_activeChatStreamCancellationLock)
            {
                string key = BuildActiveChatStreamCancellationKey(ownerKey, streamId);
                if (!_activeChatStreamCancellations.TryGetValue(key, out ActiveChatStreamCancellation active))
                {
                    _pendingChatStreamStops[key] = DateTimeOffset.UtcNow;
                    return true;
                }

                active.Cancellation.Cancel();
                return true;
            }
        }

        private void UnregisterActiveChatStreamCancellation(ActiveChatStreamCancellation active)
        {
            if (active == null)
                return;

            lock (_activeChatStreamCancellationLock)
            {
                string key = BuildActiveChatStreamCancellationKey(active.OwnerKey, active.StreamId);
                if (_activeChatStreamCancellations.TryGetValue(key, out ActiveChatStreamCancellation current) &&
                    ReferenceEquals(current, active))
                    _activeChatStreamCancellations.Remove(key);
            }

            active.Cancellation.Dispose();
        }

        private string BuildActiveChatStreamCancellationKey(string ownerKey, string streamId)
        {
            return NormalizeChatFilesystemOwnerKey(ownerKey) + "\u001F" + NormalizeChatUiStreamId(streamId);
        }

        private void PruneActiveChatStreamCancellationsLocked()
        {
            DateTimeOffset cutoff = DateTimeOffset.UtcNow - TimeSpan.FromHours(1);
            var remove = new List<string>();
            foreach (var pair in _activeChatStreamCancellations)
            {
                if (pair.Value == null || pair.Value.StartedUtc < cutoff)
                    remove.Add(pair.Key);
            }

            foreach (string key in remove)
            {
                if (_activeChatStreamCancellations.TryGetValue(key, out ActiveChatStreamCancellation active))
                    active.Cancellation.Cancel();
                _activeChatStreamCancellations.Remove(key);
            }

            DateTimeOffset pendingCutoff = DateTimeOffset.UtcNow - TimeSpan.FromSeconds(10);
            remove.Clear();
            foreach (var pair in _pendingChatStreamStops)
            {
                if (pair.Value < pendingCutoff)
                    remove.Add(pair.Key);
            }
            foreach (string key in remove)
                _pendingChatStreamStops.Remove(key);
        }

        private string HandleChatUiStreamStopRequest(NetworkConnection connection, HttpRequest request)
        {
            AddWebAuthCorsHeaders(request);
            try
            {
                string ownerKey = GetChatSessionOwnerKey(connection, request);
                string streamId = ExtractChatUiStreamId(request?.Body);
                if (string.IsNullOrWhiteSpace(streamId))
                    return BuildJsonError(request, 400, "Bad Request", "streamId is required.");

                bool cancelled = CancelActiveChatStream(ownerKey, streamId);
                if (cancelled)
                    LogMessage("[Chat UI] Stop requested for stream " + NormalizeChatUiStreamId(streamId) + " by " + ownerKey + ".");

                return JsonSerializer.Serialize(new
                {
                    ok = true,
                    cancelled
                });
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] Stop request failed: " + ex.Message);
                return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
            }
        }

        private string HandlePromptIntellisenseRequest(NetworkConnection connection, HttpRequest request)
        {
            try
            {
                string ownerKey = GetChatSessionOwnerKey(connection, request);
                string body = request?.Body ?? "{}";
                using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
                {
                    JsonElement root = document.RootElement;
                    string text = ExtractStringProperty(root, "text") ?? "";
                    int caretIndex = root.TryGetProperty("caretIndex", out JsonElement caretElement)
                        ? ReadJsonInt(caretElement, text.Length)
                        : text.Length;
                    int take = root.TryGetProperty("take", out JsonElement takeElement)
                        ? ReadJsonInt(takeElement, 12)
                        : 12;

                    caretIndex = Math.Max(0, Math.Min(text.Length, caretIndex));
                    take = Math.Max(1, Math.Min(30, take));

                    var completions = new List<object>();
                    foreach (var item in _promptIntellisense.GetCompletions(text, caretIndex))
                    {
                        if (!IsPromptIntellisenseCompletionAllowed(item, ownerKey))
                            continue;

                        var applied = _promptIntellisense.ApplyCompletion(text, caretIndex, item);
                        completions.Add(new
                        {
                            displayText = item.DisplayText ?? "",
                            insertText = item.InsertText ?? "",
                            description = item.Description ?? "",
                            category = item.Category ?? "",
                            writeup = item.Writeup ?? "",
                            isDirectory = item.IsDirectory,
                            isExecutable = item.IsExecutable,
                            hasBrowseButton = item.HasBrowseButton,
                            browseTarget = item.BrowseTarget.ToString(),
                            browseTitle = item.BrowseTitle ?? "",
                            browseFilter = item.BrowseFilter ?? "",
                            browseInsertPrefix = item.BrowseInsertPrefix ?? "",
                            browseInitialDirectory = item.BrowseInitialDirectory ?? "",
                            newText = applied.newText ?? text,
                            caretIndex = applied.caretIndex
                        });

                        if (completions.Count >= take)
                            break;
                    }

                    return JsonSerializer.Serialize(new
                    {
                        ok = true,
                        service = "prompt_intellisense",
                        mode = IsChatAgentServiceSelected(body) ? "agent" : "assistant",
                        completions
                    });
                }
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] Prompt intellisense failed: " + ex.Message);
                return JsonSerializer.Serialize(new { ok = false, error = ex.Message });
            }
        }

        private bool IsPromptIntellisenseCompletionAllowed(PromptIntellisense.CompletionItem item, string ownerKey)
        {
            if (item == null)
                return false;

            string insertText = item.InsertText ?? "";
            if (item.Category != null &&
                item.Category.Equals("File", StringComparison.OrdinalIgnoreCase) &&
                Path.IsPathRooted(insertText))
            {
                try
                {
                    string candidate = Path.GetFullPath(insertText.TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar));
                    return IsPathUnderAnyRoot(candidate, GetChatAgentAllowedRoots(ownerKey));
                }
                catch
                {
                    return false;
                }
            }

            return true;
        }

        private bool ModelLikelySupportsImages(string modelId)
        {
            if (string.IsNullOrWhiteSpace(modelId))
                return false;

            string id = modelId.ToLowerInvariant();
            return id.Contains("vision") ||
                   id.Contains("visual") ||
                   id.Contains("image") ||
                   id.Contains("multimodal") ||
                   id.Contains("vl") ||
                   id.Contains("v-l") ||
                   id.Contains("llava") ||
                   id.Contains("bakllava") ||
                   id.Contains("moondream") ||
                   id.Contains("pixtral") ||
                   id.Contains("minicpm-v") ||
                   id.Contains("qwen-vl") ||
                   id.Contains("qwen2-vl") ||
                   id.Contains("qwen2.5-vl") ||
                   id.Contains("qwen3") ||
                   id.Contains("gemma-3") ||
                   id.Contains("gemma3") ||
                   id.Contains("gpt-4o") ||
                   id.Contains("omni");
        }

        private bool ModelLikelySupportsTools(string modelId)
        {
            if (string.IsNullOrWhiteSpace(modelId))
                return false;

            string id = modelId.ToLowerInvariant();
            return id.Contains("tool") ||
                   id.Contains("function") ||
                   id.Contains("reasoning") ||
                   id.Contains("instruct") ||
                   id.Contains("chat") ||
                   id.Contains("qwen") ||
                   id.Contains("llama") ||
                   id.Contains("mistral") ||
                   id.Contains("gpt") ||
                   id.Contains("claude");
        }

        private List<ChatUiModelInfo> ExtractModelInfos(string responseBody)
        {
            var models = new List<ChatUiModelInfo>();
            if (string.IsNullOrWhiteSpace(responseBody))
                return models;

            try
            {
                using (JsonDocument document = JsonDocument.Parse(responseBody))
                {
                    AddModelInfosFromElement(document.RootElement, models);

                    if (document.RootElement.ValueKind == JsonValueKind.Object)
                    {
                        if (document.RootElement.TryGetProperty("data", out JsonElement data))
                            AddModelInfosFromElement(data, models);
                        if (document.RootElement.TryGetProperty("models", out JsonElement modelList))
                            AddModelInfosFromElement(modelList, models);
                    }
                }
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] Could not parse model capabilities response: " + ex.Message);
            }

            return models;
        }

        private void AddModelInfosFromElement(JsonElement element, List<ChatUiModelInfo> models)
        {
            if (models == null)
                return;

            if (element.ValueKind == JsonValueKind.Array)
            {
                foreach (JsonElement child in element.EnumerateArray())
                    AddModelInfosFromElement(child, models);
                return;
            }

            ChatUiModelInfo info = null;
            if (element.ValueKind == JsonValueKind.Object)
            {
                string id = ExtractStringProperty(element, "id") ??
                            ExtractStringProperty(element, "name") ??
                            ExtractStringProperty(element, "model");
                if (!string.IsNullOrWhiteSpace(id))
                {
                    info = BuildChatModelInfo(id);
                    info.supportsImages = info.supportsImages || ElementIndicatesCapability(element, "vision", "image", "images", "multimodal", "vlm");
                    info.supportsTools = info.supportsTools || ElementIndicatesCapability(element, "tool", "tools", "function", "function_calling", "tool_use");
                }
            }
            else if (element.ValueKind == JsonValueKind.String)
            {
                string id = element.GetString();
                if (!string.IsNullOrWhiteSpace(id))
                    info = BuildChatModelInfo(id);
            }

            if (info == null || string.IsNullOrWhiteSpace(info.id))
                return;

            ChatUiModelInfo existing = models.Find(model => string.Equals(model.id, info.id, StringComparison.OrdinalIgnoreCase));
            if (existing == null)
            {
                models.Add(info);
            }
            else
            {
                existing.supportsImages = existing.supportsImages || info.supportsImages;
                existing.supportsTools = existing.supportsTools || info.supportsTools;
            }
        }

        private bool ElementIndicatesCapability(JsonElement element, params string[] tokens)
        {
            if (tokens == null || tokens.Length == 0)
                return false;

            if (element.ValueKind == JsonValueKind.Object)
            {
                foreach (JsonProperty property in element.EnumerateObject())
                {
                    bool propertyMatches = ContainsAnyToken(property.Name, tokens);
                    JsonElement value = property.Value;

                    if (propertyMatches)
                    {
                        if (value.ValueKind == JsonValueKind.True)
                            return true;
                        if (value.ValueKind == JsonValueKind.Number && value.TryGetInt32(out int number) && number != 0)
                            return true;
                        if (value.ValueKind == JsonValueKind.String)
                        {
                            string text = value.GetString();
                            if (!string.IsNullOrWhiteSpace(text) &&
                                !text.Equals("false", StringComparison.OrdinalIgnoreCase) &&
                                !text.Equals("none", StringComparison.OrdinalIgnoreCase) &&
                                !text.Equals("0", StringComparison.OrdinalIgnoreCase))
                                return true;
                        }
                        if (value.ValueKind == JsonValueKind.Array || value.ValueKind == JsonValueKind.Object)
                            return ElementIndicatesCapability(value, tokens);
                    }

                    if (ElementIndicatesCapability(value, tokens))
                        return true;
                }
            }
            else if (element.ValueKind == JsonValueKind.Array)
            {
                foreach (JsonElement child in element.EnumerateArray())
                {
                    if (ElementIndicatesCapability(child, tokens))
                        return true;
                }
            }
            else if (element.ValueKind == JsonValueKind.String)
            {
                return ContainsAnyToken(element.GetString(), tokens);
            }

            return false;
        }

        private bool ContainsAnyToken(string text, string[] tokens)
        {
            if (string.IsNullOrWhiteSpace(text))
                return false;

            string lower = text.ToLowerInvariant();
            foreach (string token in tokens)
            {
                if (!string.IsNullOrWhiteSpace(token) && lower.Contains(token.ToLowerInvariant()))
                    return true;
            }
            return false;
        }

        private List<string> ExtractModelIds(string responseBody)
        {
            var models = new List<string>();
            if (string.IsNullOrWhiteSpace(responseBody))
                return models;

            try
            {
                using (JsonDocument document = JsonDocument.Parse(responseBody))
                {
                    AddModelIdsFromElement(document.RootElement, models);

                    if (document.RootElement.ValueKind == JsonValueKind.Object)
                    {
                        if (document.RootElement.TryGetProperty("data", out JsonElement data))
                            AddModelIdsFromElement(data, models);
                        if (document.RootElement.TryGetProperty("models", out JsonElement modelList))
                            AddModelIdsFromElement(modelList, models);
                    }
                }
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] Could not parse models response: " + ex.Message);
            }

            return models;
        }

        private void AddModelIdsFromElement(JsonElement element, List<string> models)
        {
            if (models == null)
                return;

            if (element.ValueKind == JsonValueKind.Array)
            {
                foreach (JsonElement child in element.EnumerateArray())
                    AddModelIdsFromElement(child, models);
                return;
            }

            string id = null;
            if (element.ValueKind == JsonValueKind.Object)
            {
                id = ExtractStringProperty(element, "id") ??
                     ExtractStringProperty(element, "name") ??
                     ExtractStringProperty(element, "model");
            }
            else if (element.ValueKind == JsonValueKind.String)
            {
                id = element.GetString();
            }

            if (!string.IsNullOrWhiteSpace(id) && !models.Contains(id))
                models.Add(id);
        }

