        private string HandleChatFilesystemAccessMutationRequest(NetworkConnection connection, HttpRequest request)
        {
            try
            {
                if (!IsDatabaseAdministrator(connection, request))
                {
                    return JsonSerializer.Serialize(new
                    {
                        ok = false,
                        canEdit = false,
                        error = "Filesystem access can only be changed from a host-local connection or by a WebAuth administrator."
                    });
                }

                string ownerKey = GetChatSessionOwnerKey(connection, request);
                string body = request?.Body ?? "{}";
                using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
                {
                    JsonElement root = document.RootElement;
                    string action = ExtractStringProperty(root, "action") ?? "";
                    string path = ExtractStringProperty(root, "path") ?? "";

                    if (action.Equals("add", StringComparison.OrdinalIgnoreCase))
                    {
                        if (!TryNormalizeAccessibleDirectory(path, requireExists: true, out string normalizedPath, out string error))
                            return JsonSerializer.Serialize(new { ok = false, canEdit = true, error });

                        SaveChatFilesystemAccess(ownerKey, normalizedPath);
                    }
                    else if (action.Equals("remove", StringComparison.OrdinalIgnoreCase))
                    {
                        if (!TryNormalizeAccessibleDirectory(path, requireExists: false, out string normalizedPath, out string error))
                            return JsonSerializer.Serialize(new { ok = false, canEdit = true, error });

                        RemoveChatFilesystemAccess(ownerKey, normalizedPath);
                        StopChatFtpServerIfRootRemoved(ownerKey, normalizedPath);
                    }
                    else
                    {
                        return JsonSerializer.Serialize(new { ok = false, canEdit = true, error = "Unknown filesystem access action." });
                    }

                    return JsonSerializer.Serialize(new
                    {
                        ok = true,
                        canEdit = true,
                        ownerKey,
                        directories = GetChatFilesystemAccess(ownerKey)
                    });
                }
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] Filesystem access update failed: " + ex.Message);
                return JsonSerializer.Serialize(new { ok = false, error = ex.Message });
            }
        }

