        private string HandleChatFtpConfigSaveRequest(NetworkConnection connection, HttpRequest request)
        {
            try
            {
                if (!IsDatabaseAdministrator(connection, request))
                {
                    return JsonSerializer.Serialize(new
                    {
                        ok = false,
                        canEdit = false,
                        error = "FTP configuration can only be changed from a host-local connection or by a WebAuth administrator."
                    });
                }

                string ownerKey = GetChatSessionOwnerKey(connection, request);
                ChatPermissionState permissions = GetChatPermissions(ownerKey);
                string body = request?.Body ?? "{}";
                using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
                {
                    JsonElement root = document.RootElement;
                    string action = (ExtractStringProperty(root, "action") ?? "save").Trim();
                    if (string.IsNullOrWhiteSpace(action))
                        action = "save";

                    ChatFtpServerConfig existing = GetChatFtpConfig(ownerKey);

                    if (action.Equals("stop", StringComparison.OrdinalIgnoreCase))
                    {
                        existing.enabled = false;
                        existing.updatedUtc = DateTimeOffset.UtcNow.ToString("O");
                        SaveChatFtpConfig(ownerKey, existing);
                        if (IsChatFtpServerActiveForOwner(ownerKey))
                            StopChatFtpServer();
                        LogMessage("[Chat UI] FTP stop requested for " + ownerKey + ".");
                            return BuildChatFtpConfigResponse(connection, request, ownerKey, permissions);
                    }

                    if (!permissions.ftpServer)
                    {
                        return JsonSerializer.Serialize(new
                        {
                            ok = false,
                            canEdit = true,
                            error = "Ftp Server permission is disabled."
                        });
                    }

                    ChatFtpServerConfig config = BuildChatFtpConfigFromJson(root, existing);
                    string validationError = NormalizeAndValidateChatFtpUsers(ownerKey, config);
                    if (!string.IsNullOrWhiteSpace(validationError))
                        return JsonSerializer.Serialize(new { ok = false, canEdit = true, error = validationError });
                    if (action.Equals("start", StringComparison.OrdinalIgnoreCase))
                    {
                        config.enabled = true;
                        SaveChatFtpConfig(ownerKey, config);
                        LogMessage("[Chat UI] FTP config saved for " + ownerKey + " before start; autostart=" + config.autoStart + ".");
                        StartChatFtpServer(ownerKey, config);
                    }
                    else if (action.Equals("save", StringComparison.OrdinalIgnoreCase))
                    {
                        config.enabled = existing.enabled;
                        SaveChatFtpConfig(ownerKey, config);
                        LogMessage("[Chat UI] FTP config saved for " + ownerKey + "; autostart=" + config.autoStart + ".");
                        if (config.enabled && IsChatFtpServerActiveForOwner(ownerKey))
                            StartChatFtpServer(ownerKey, config);
                    }
                    else
                    {
                        return JsonSerializer.Serialize(new { ok = false, canEdit = true, error = "Unknown FTP configuration action." });
                    }

                    return BuildChatFtpConfigResponse(connection, request, ownerKey, permissions);
                }
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] FTP config update failed: " + ex.Message);
                return JsonSerializer.Serialize(new { ok = false, error = ex.Message });
            }
        }

        private string BuildChatFtpConfigResponse(NetworkConnection connection, HttpRequest request, string ownerKey, ChatPermissionState permissions)
        {
            var directories = GetChatFilesystemAccess(ownerKey);
            ChatFtpServerConfig config = GetChatFtpConfig(ownerKey);
            ApplyDefaultChatFtpDirectory(config, directories);
            return JsonSerializer.Serialize(new
            {
                ok = true,
                canEdit = IsDatabaseAdministrator(connection, request),
                ownerKey,
                permissionEnabled = permissions != null && permissions.ftpServer,
                config,
                directories,
                status = GetChatFtpServerStatus()
            });
        }

        private string HandleChatSessionsListRequest(NetworkConnection connection, HttpRequest request)
        {
            try
            {
                string ownerKey = GetChatSessionOwnerKey(connection, request);
                bool isAdmin = IsDatabaseAdministrator(connection, request);
                var sessions = new List<ChatSessionSummary>();
                lock (_chatSessionLock)
                {
                    var table = GetChatSessionsTable();
                    foreach (object[] row in table.Rows)
                    {
                        string rowOwnerKey = GetRowValue(row, 7);
                        if (!isAdmin && !string.Equals(rowOwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase))
                            continue;

                        sessions.Add(new ChatSessionSummary
                        {
                            id = GetRowValue(row, 0),
                            title = GetRowValue(row, 1),
                            createdUtc = GetRowValue(row, 2),
                            updatedUtc = GetRowValue(row, 3),
                            model = GetRowValue(row, 4),
                            ownerKey = rowOwnerKey
                        });
                    }
                }

                sessions.Sort((a, b) => string.CompareOrdinal(b.updatedUtc, a.updatedUtc));
                return JsonSerializer.Serialize(new { ok = true, ownerKey, isAdmin, sessions });
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] Session list failed: " + ex.Message);
                return JsonSerializer.Serialize(new { ok = false, error = ex.Message });
            }
        }

        private string HandleChatSessionGetRequest(NetworkConnection connection, HttpRequest request)
        {
            try
            {
                string ownerKey = GetChatSessionOwnerKey(connection, request);
                string id = request != null &&
                            request.QueryParameters != null &&
                            request.QueryParameters.TryGetValue("id", out string queryId)
                    ? queryId
                    : null;
                if (string.IsNullOrWhiteSpace(id))
                    return JsonSerializer.Serialize(new { ok = false, error = "Session id is required." });

                lock (_chatSessionLock)
                {
                    var table = GetChatSessionsTable();
                    foreach (object[] row in table.Rows)
                    {
                        if (!string.Equals(GetRowValue(row, 0), id, StringComparison.Ordinal))
                            continue;
                        if (!string.Equals(GetRowValue(row, 7), ownerKey, StringComparison.OrdinalIgnoreCase))
                            return JsonSerializer.Serialize(new { ok = false, error = "Session not found." });

                        return JsonSerializer.Serialize(new
                        {
                            ok = true,
                            session = new
                            {
                                id = GetRowValue(row, 0),
                                title = GetRowValue(row, 1),
                                createdUtc = GetRowValue(row, 2),
                                updatedUtc = GetRowValue(row, 3),
                                model = GetRowValue(row, 4),
                                messages = DeserializeJsonElement(GetRowValue(row, 5), "[]"),
                                files = DeserializeJsonElement(GetRowValue(row, 6), "[]")
                            }
                        });
                    }
                }

                return JsonSerializer.Serialize(new { ok = false, error = "Session not found." });
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] Session get failed: " + ex.Message);
                return JsonSerializer.Serialize(new { ok = false, error = ex.Message });
            }
        }

        private string HandleChatSessionSaveRequest(NetworkConnection connection, HttpRequest request)
        {
            try
            {
                string ownerKey = GetChatSessionOwnerKey(connection, request);
                string body = request?.Body ?? "{}";
                using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
                {
                    JsonElement root = document.RootElement;
                    string action = (ExtractStringProperty(root, "action") ?? "save").Trim();
                    string id = ExtractStringProperty(root, "id");

                    if (action.Equals("delete", StringComparison.OrdinalIgnoreCase))
                    {
                        if (string.IsNullOrWhiteSpace(id))
                            return JsonSerializer.Serialize(new { ok = false, error = "Session id is required." });

                        bool deleted = false;
                        lock (_chatSessionLock)
                        {
                            var table = GetChatSessionsTable();
                            for (int i = table.Rows.Count - 1; i >= 0; i--)
                            {
                                object[] row = NormalizeChatSessionRow(table.Rows[i]);
                                table.Rows[i] = row;
                                if (!string.Equals(GetRowValue(row, 0), id, StringComparison.Ordinal))
                                    continue;
                                if (!string.Equals(GetRowValue(row, 7), ownerKey, StringComparison.OrdinalIgnoreCase))
                                    return JsonSerializer.Serialize(new { ok = false, error = "Session not found." });

                                table.Rows.RemoveAt(i);
                                deleted = true;
                                break;
                            }

                            if (deleted)
                                _chatSessionData.Save();
                        }

                        return JsonSerializer.Serialize(new { ok = deleted, id, ownerKey, deleted, error = deleted ? "" : "Session not found." });
                    }

                    if (string.IsNullOrWhiteSpace(id))
                        id = "sess_" + Guid.NewGuid().ToString("N");

                    string model = ExtractStringProperty(root, "model") ?? "";
                    string title = ExtractStringProperty(root, "title");
                    string messagesJson = root.TryGetProperty("messages", out JsonElement messages)
                        ? messages.GetRawText()
                        : "[]";
                    string filesJson = root.TryGetProperty("files", out JsonElement files)
                        ? files.GetRawText()
                        : "[]";
                    if (string.IsNullOrWhiteSpace(title))
                        title = InferChatSessionTitle(messagesJson);

                    string now = DateTimeOffset.UtcNow.ToString("O");
                    lock (_chatSessionLock)
                    {
                        var table = GetChatSessionsTable();
                        int existingIndex = -1;
                        for (int i = 0; i < table.Rows.Count; i++)
                        {
                            object[] row = NormalizeChatSessionRow(table.Rows[i]);
                            table.Rows[i] = row;
                            if (string.Equals(GetRowValue(row, 0), id, StringComparison.Ordinal))
                            {
                                existingIndex = i;
                                break;
                            }
                        }

                        if (existingIndex < 0)
                        {
                            table.Rows.Add(new object[] { id, title, now, now, model, messagesJson, filesJson, ownerKey });
                        }
                        else
                        {
                            object[] existing = table.Rows[existingIndex];
                            if (!string.Equals(GetRowValue(existing, 7), ownerKey, StringComparison.OrdinalIgnoreCase))
                                return JsonSerializer.Serialize(new { ok = false, error = "Session belongs to another client." });
                            existing[1] = title;
                            existing[3] = now;
                            existing[4] = model;
                            existing[5] = messagesJson;
                            existing[6] = MergeChatSessionFilesJson(filesJson, GetRowValue(existing, 6));
                            existing[7] = ownerKey;
                        }

                        _chatSessionData.Save();
                    }

                    return JsonSerializer.Serialize(new { ok = true, id, title, updatedUtc = now, ownerKey });
                }
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] Session save failed: " + ex.Message);
                return JsonSerializer.Serialize(new { ok = false, error = ex.Message });
            }
        }

        private string HandleChatFilePreviewRequest(NetworkConnection connection, HttpRequest request)
        {
            try
            {
                string ownerKey = GetChatSessionOwnerKey(connection, request);
                string requestedPath = GetQueryParameter(request, "path");
                string kind = (GetQueryParameter(request, "kind") ?? "").Trim();
                string sessionId = EnsureChatUiSessionId(GetQueryParameter(request, "sessionId"));

                if (!TryResolveSolutionExplorerFile(ownerKey, sessionId, kind, requestedPath, out string fullPath, out string error))
                {
                    return JsonSerializer.Serialize(new
                    {
                        ok = false,
                        ownerKey,
                        sessionId,
                        error
                    });
                }

                var info = new FileInfo(fullPath);
                string extension = Path.GetExtension(fullPath) ?? "";
                string mimeType = GetChatFilePreviewMimeType(extension);
                string previewKind = GetChatFilePreviewKind(extension, mimeType);
                const long maxTextPreviewBytes = 2L * 1024L * 1024L;
                const long maxImagePreviewBytes = 8L * 1024L * 1024L;

                if (previewKind.Equals("image", StringComparison.OrdinalIgnoreCase))
                {
                    if (info.Length > maxImagePreviewBytes)
                        return JsonSerializer.Serialize(new { ok = false, ownerKey, sessionId, error = "Image is too large to preview." });

                    byte[] bytes = File.ReadAllBytes(fullPath);
                    return JsonSerializer.Serialize(new
                    {
                        ok = true,
                        ownerKey,
                        sessionId,
                        file = BuildSolutionExplorerEntry(kind, fullPath, false, sessionId),
                        previewKind,
                        mimeType,
                        dataUrl = "data:" + mimeType + ";base64," + Convert.ToBase64String(bytes)
                    });
                }

                if (info.Length > maxTextPreviewBytes)
                    return JsonSerializer.Serialize(new { ok = false, ownerKey, sessionId, error = "File is too large to preview as text." });

                string text = File.ReadAllText(fullPath, Encoding.UTF8);
                return JsonSerializer.Serialize(new
                {
                    ok = true,
                    ownerKey,
                    sessionId,
                    file = BuildSolutionExplorerEntry(kind, fullPath, false, sessionId),
                    previewKind,
                    mimeType,
                    text
                });
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] File preview failed: " + ex.Message);
                return JsonSerializer.Serialize(new { ok = false, error = ex.Message });
            }
        }

        private string MergeChatSessionFilesJson(string primaryFilesJson, string secondaryFilesJson)
        {
            var files = new List<ChatSessionFile>();
            var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            AddChatSessionFilesFromJson(files, seen, primaryFilesJson);
            AddChatSessionFilesFromJson(files, seen, secondaryFilesJson);
            return JsonSerializer.Serialize(files);
        }

        private void AddChatSessionFilesFromJson(List<ChatSessionFile> files, HashSet<string> seen, string filesJson)
        {
            if (files == null || seen == null || string.IsNullOrWhiteSpace(filesJson))
                return;

            try
            {
                using (JsonDocument document = JsonDocument.Parse(filesJson))
                {
                    if (document.RootElement.ValueKind != JsonValueKind.Array)
                        return;

                    foreach (JsonElement element in document.RootElement.EnumerateArray())
                    {
                        ChatSessionFile file = ReadChatSessionFile(element);
                        if (file == null)
                            continue;

                        string key = GetChatSessionFileKey(file);
                        if (string.IsNullOrWhiteSpace(key) || !seen.Add(key))
                            continue;

                        files.Add(file);
                    }
                }
            }
            catch
            {
            }
        }

        private ChatSessionFile ReadChatSessionFile(JsonElement element)
        {
            if (element.ValueKind != JsonValueKind.Object)
                return null;

            string id = ExtractStringProperty(element, "id");
            string path = ExtractStringProperty(element, "path");
            if (string.IsNullOrWhiteSpace(id) && string.IsNullOrWhiteSpace(path))
                return null;

            return new ChatSessionFile
            {
                id = id ?? "",
                name = ExtractStringProperty(element, "name") ?? "file",
                type = ExtractStringProperty(element, "type") ?? "application/octet-stream",
                size = element.TryGetProperty("size", out JsonElement sizeElement)
                    ? ReadJsonInt(sizeElement, 0)
                    : 0,
                path = path ?? "",
                uploadedUtc = ExtractStringProperty(element, "uploadedUtc") ?? DateTimeOffset.UtcNow.ToString("O")
            };
        }

        private string GetChatSessionFileKey(ChatSessionFile file)
        {
            if (file == null)
                return null;
            if (!string.IsNullOrWhiteSpace(file.id))
                return "id:" + file.id.Trim();
            if (string.IsNullOrWhiteSpace(file.path))
                return null;

            try
            {
                return "path:" + Path.GetFullPath(file.path).TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
            }
            catch
            {
                return "path:" + file.path.Trim();
            }
        }

        private void RegisterChatSessionFile(string sessionId, string ownerKey, ChatSessionFile file)
        {
            if (file == null || string.IsNullOrWhiteSpace(sessionId))
                return;

            string now = DateTimeOffset.UtcNow.ToString("O");
            lock (_chatSessionLock)
            {
                var table = GetChatSessionsTable();
                for (int i = 0; i < table.Rows.Count; i++)
                {
                    object[] row = NormalizeChatSessionRow(table.Rows[i]);
                    table.Rows[i] = row;
                    if (!string.Equals(GetRowValue(row, 0), sessionId, StringComparison.Ordinal))
                        continue;

                    if (!string.IsNullOrWhiteSpace(ownerKey) &&
                        !string.Equals(GetRowValue(row, 7), ownerKey, StringComparison.OrdinalIgnoreCase))
                        return;

                    row[3] = now;
                    row[6] = MergeChatSessionFilesJson(JsonSerializer.Serialize(new[] { file }), GetRowValue(row, 6));
                    _chatSessionData.Save();
                    return;
                }

                string title = string.IsNullOrWhiteSpace(file.name) ? "Downloaded file" : file.name;
                table.Rows.Add(new object[]
                {
                    sessionId,
                    title,
                    now,
                    now,
                    "",
                    "[]",
                    JsonSerializer.Serialize(new[] { file }),
                    string.IsNullOrWhiteSpace(ownerKey) ? "legacy" : ownerKey
                });
                _chatSessionData.Save();
            }
        }

        private string HandleChatFileUploadRequest(NetworkConnection connection, HttpRequest request)
        {
            try
            {
                string ownerKey = GetChatSessionOwnerKey(connection, request);
                ChatPermissionState permissions = GetChatPermissions(ownerKey);
                string restriction = BuildChatRestrictionMessage(permissions);
                if (!string.IsNullOrWhiteSpace(restriction))
                {
                    SetHttpStatus(request, 403, "Forbidden");
                    return JsonSerializer.Serialize(new { ok = false, error = restriction });
                }

                string body = request?.Body ?? "{}";
                using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
                {
                    JsonElement root = document.RootElement;
                    string sessionId = EnsureChatUiSessionId(ExtractStringProperty(root, "sessionId"));

                    string name = SanitizeFileName(ExtractStringProperty(root, "name") ?? "attachment");
                    string type = ExtractStringProperty(root, "type") ?? "application/octet-stream";
                    string dataUrl = ExtractStringProperty(root, "dataUrl");
                    string text = ExtractStringProperty(root, "text");
                    bool asFile = root.TryGetProperty("asFile", out JsonElement asFileElement) &&
                                  ReadJsonBool(asFileElement, false);
                    bool isImage = !asFile &&
                                   (type.StartsWith("image/", StringComparison.OrdinalIgnoreCase) ||
                                    (!string.IsNullOrWhiteSpace(dataUrl) && dataUrl.StartsWith("data:image/", StringComparison.OrdinalIgnoreCase)));
                    if (isImage && !permissions.imageUploads)
                    {
                        SetHttpStatus(request, 403, "Forbidden");
                        return JsonSerializer.Serialize(new { ok = false, error = "Image uploads are disabled for this client." });
                    }
                    if (!isImage && !permissions.fileUploads)
                    {
                        SetHttpStatus(request, 403, "Forbidden");
                        return JsonSerializer.Serialize(new { ok = false, error = "File uploads are disabled for this client." });
                    }

                    byte[] bytes;
                    if (!string.IsNullOrWhiteSpace(dataUrl))
                    {
                        int comma = dataUrl.IndexOf(',');
                        string encoded = comma >= 0 ? dataUrl.Substring(comma + 1) : dataUrl;
                        bytes = Convert.FromBase64String(encoded);
                    }
                    else
                    {
                        bytes = Encoding.UTF8.GetBytes(text ?? "");
                    }

                    if (!EnsureChatStorageCanAdd(ownerKey, bytes.LongLength, out ChatUsageSnapshot usageSnapshot, out string storageError))
                    {
                        SetHttpStatus(request, 507, "Insufficient Storage");
                        return JsonSerializer.Serialize(new { ok = false, error = storageError, usage = usageSnapshot });
                    }

                    string fileId = "file_" + Guid.NewGuid().ToString("N");
                    string dir = Path.Combine(_chatSessionFilesRoot, SanitizeFileName(sessionId));
                    Directory.CreateDirectory(dir);
                    string path = Path.Combine(dir, fileId + "_" + name);
                    File.WriteAllBytes(path, bytes);

                    var file = new ChatSessionFile
                    {
                        id = fileId,
                        name = name,
                        type = type,
                        size = bytes.Length,
                        path = path,
                        uploadedUtc = DateTimeOffset.UtcNow.ToString("O")
                    };
                    RegisterChatSessionFile(sessionId, ownerKey, file);
                    return JsonSerializer.Serialize(new { ok = true, sessionId, ownerKey, file, usage = GetChatUsageSnapshot(ownerKey) });
                }
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] File upload failed: " + ex.Message);
                return JsonSerializer.Serialize(new { ok = false, error = ex.Message });
            }
        }

        private void EnsureChatSessionTables()
        {
            lock (_chatSessionLock)
            {
                GetChatSessionsTable();
                GetChatPermissionsTable();
                GetChatFilesystemAccessTable();
                GetChatFilesystemDeniedTable();
                GetChatFtpConfigTable();
                GetWebAuthTable();
                GetWebAuthIpLinksTable();
                GetWebAuthRegistrationRequestsTable();
                GetChatCostsTable();
                GetChatUserCostsTable();
                GetTerminalPermissionRulesTable();
                _chatSessionData.Save();
            }
        }

        private ChatPermissionState GetChatPermissions()
        {
            return GetStoredChatPermissions("global", createIfMissing: true) ?? new ChatPermissionState();
        }

        private ChatPermissionState GetChatPermissions(string ownerKey)
        {
            ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
            ChatPermissionState ownerPermissions = GetStoredChatPermissions(ownerKey, createIfMissing: false);
            return ownerPermissions ?? GetChatPermissions();
        }

        private ChatPermissionState GetStoredChatPermissions(string ownerKey, bool createIfMissing)
        {
            ownerKey = string.IsNullOrWhiteSpace(ownerKey) ? "global" : ownerKey.Trim();
            lock (_chatSessionLock)
            {
                var table = GetChatPermissionsTable();
                for (int i = 0; i < table.Rows.Count; i++)
                {
                    object[] row = NormalizeChatPermissionRow(table.Rows[i]);
                    table.Rows[i] = row;
                    if (string.Equals(GetRowValue(row, 0), ownerKey, StringComparison.OrdinalIgnoreCase))
                        return ChatPermissionStateFromRow(row);
                }

                if (!createIfMissing)
                    return null;

                object[] newRow = CreateDefaultChatPermissionRow();
                newRow[0] = ownerKey;
                table.Rows.Add(newRow);
                _chatSessionData.Save();
                return ChatPermissionStateFromRow(newRow);
            }
        }

        private void SaveChatPermissions(ChatPermissionState permissions)
        {
            SaveChatPermissions("global", permissions);
        }

        private void SaveChatPermissions(string ownerKey, ChatPermissionState permissions)
        {
            if (permissions == null)
                permissions = new ChatPermissionState();
            ownerKey = string.IsNullOrWhiteSpace(ownerKey) ? "global" : ownerKey.Trim();

            lock (_chatSessionLock)
            {
                var table = GetChatPermissionsTable();
                object[] row = ChatPermissionStateToRow(ownerKey, permissions);
                for (int i = 0; i < table.Rows.Count; i++)
                {
                    object[] existing = NormalizeChatPermissionRow(table.Rows[i]);
                    if (string.Equals(GetRowValue(existing, 0), ownerKey, StringComparison.OrdinalIgnoreCase))
                    {
                        table.Rows[i] = row;
                        _chatSessionData.Save();
                        return;
                    }
                }

                table.Rows.Add(row);
                _chatSessionData.Save();
            }
        }

        private ChatPermissionState ChatPermissionStateFromRow(object[] row)
        {
            row = NormalizeChatPermissionRow(row);
            return new ChatPermissionState
            {
                internetSearch = ParseStoredBool(GetRowValue(row, 1), false),
                vsCopilotTools = ParseStoredBool(GetRowValue(row, 2), true),
                fileDownloads = ParseStoredBool(GetRowValue(row, 3), false),
                updatedUtc = GetRowValue(row, 4),
                ftpServer = ParseStoredBool(GetRowValue(row, 5), false),
                sqlAdmin = ParseStoredBool(GetRowValue(row, 6), false),
                mutedUntilUtc = GetRowValue(row, 7),
                bannedUntilUtc = GetRowValue(row, 8),
                muteUntilEnabled = ParseStoredBool(GetRowValue(row, 9), false),
                banUntilEnabled = ParseStoredBool(GetRowValue(row, 10), false),
                agentAccess = ParseStoredBool(GetRowValue(row, 11), true),
                fileUploads = ParseStoredBool(GetRowValue(row, 12), true),
                imageUploads = ParseStoredBool(GetRowValue(row, 13), true),
                terminalCommands = ParseStoredBool(GetRowValue(row, 14), true),
                terminalForeverApproved = ParseStoredBool(GetRowValue(row, 15), false)
            };
        }

        private object[] ChatPermissionStateToRow(string ownerKey, ChatPermissionState permissions)
        {
            permissions = permissions ?? new ChatPermissionState();
            return NormalizeChatPermissionRow(new object[] {
                string.IsNullOrWhiteSpace(ownerKey) ? "global" : ownerKey.Trim(),
                permissions.internetSearch ? "true" : "false",
                permissions.vsCopilotTools ? "true" : "false",
                permissions.fileDownloads ? "true" : "false",
                DateTimeOffset.UtcNow.ToString("O"),
                permissions.ftpServer ? "true" : "false",
                permissions.sqlAdmin ? "true" : "false",
                permissions.mutedUntilUtc ?? "",
                permissions.bannedUntilUtc ?? "",
                permissions.muteUntilEnabled ? "true" : "false",
                permissions.banUntilEnabled ? "true" : "false",
                permissions.agentAccess ? "true" : "false",
                permissions.fileUploads ? "true" : "false",
                permissions.imageUploads ? "true" : "false",
                permissions.terminalCommands ? "true" : "false",
                permissions.terminalForeverApproved ? "true" : "false"
            });
        }

        private ChatPermissionState ChatPermissionStateFromJson(JsonElement root, ChatPermissionState fallback)
        {
            ChatPermissionState permissions = fallback ?? new ChatPermissionState();
            if (root.ValueKind != JsonValueKind.Object)
                return permissions;

            if (root.TryGetProperty("internetSearch", out JsonElement internetSearch))
                permissions.internetSearch = ReadJsonBool(internetSearch, permissions.internetSearch);
            if (root.TryGetProperty("vsCopilotTools", out JsonElement vsCopilotTools))
                permissions.vsCopilotTools = ReadJsonBool(vsCopilotTools, permissions.vsCopilotTools);
            if (root.TryGetProperty("fileDownloads", out JsonElement fileDownloads))
                permissions.fileDownloads = ReadJsonBool(fileDownloads, permissions.fileDownloads);
            if (root.TryGetProperty("ftpServer", out JsonElement ftpServer))
                permissions.ftpServer = ReadJsonBool(ftpServer, permissions.ftpServer);
            if (root.TryGetProperty("sqlAdmin", out JsonElement sqlAdmin))
                permissions.sqlAdmin = ReadJsonBool(sqlAdmin, permissions.sqlAdmin);
            if (root.TryGetProperty("agentAccess", out JsonElement agentAccess))
                permissions.agentAccess = ReadJsonBool(agentAccess, permissions.agentAccess);
            if (root.TryGetProperty("fileUploads", out JsonElement fileUploads))
                permissions.fileUploads = ReadJsonBool(fileUploads, permissions.fileUploads);
            if (root.TryGetProperty("imageUploads", out JsonElement imageUploads))
                permissions.imageUploads = ReadJsonBool(imageUploads, permissions.imageUploads);
            if (root.TryGetProperty("terminalCommands", out JsonElement terminalCommands))
                permissions.terminalCommands = ReadJsonBool(terminalCommands, permissions.terminalCommands);
            if (root.TryGetProperty("terminalForeverApproved", out JsonElement terminalForeverApproved))
                permissions.terminalForeverApproved = ReadJsonBool(terminalForeverApproved, permissions.terminalForeverApproved);
            if (root.TryGetProperty("muteUntilEnabled", out JsonElement muteUntilEnabled))
                permissions.muteUntilEnabled = ReadJsonBool(muteUntilEnabled, permissions.muteUntilEnabled);
            if (root.TryGetProperty("banUntilEnabled", out JsonElement banUntilEnabled))
                permissions.banUntilEnabled = ReadJsonBool(banUntilEnabled, permissions.banUntilEnabled);
            string mutedUntil = ExtractStringProperty(root, "mutedUntilUtc");
            if (mutedUntil != null)
                permissions.mutedUntilUtc = mutedUntil;
            string bannedUntil = ExtractStringProperty(root, "bannedUntilUtc");
            if (bannedUntil != null)
                permissions.bannedUntilUtc = bannedUntil;
            return permissions;
        }

        private ChatPermissionState ChatPermissionStateFromSnapshot(ChatClientPermissionSnapshot snapshot, ChatPermissionState fallback)
        {
            ChatPermissionState permissions = fallback ?? new ChatPermissionState();
            permissions.internetSearch = snapshot.InternetSearch;
            permissions.vsCopilotTools = snapshot.VsCopilotTools;
            permissions.fileDownloads = snapshot.FileDownloads;
            permissions.ftpServer = snapshot.FtpServer;
            permissions.sqlAdmin = snapshot.SqlAdmin;
            permissions.agentAccess = snapshot.AgentAccess;
            permissions.fileUploads = snapshot.FileUploads;
            permissions.imageUploads = snapshot.ImageUploads;
            permissions.terminalCommands = snapshot.TerminalCommands;
            permissions.terminalForeverApproved = snapshot.TerminalForeverApproved;
            permissions.mutedUntilUtc = snapshot.MutedUntilUtc ?? "";
            permissions.bannedUntilUtc = snapshot.BannedUntilUtc ?? "";
            permissions.muteUntilEnabled = snapshot.MuteUntilEnabled;
            permissions.banUntilEnabled = snapshot.BanUntilEnabled;
            return permissions;
        }

        private ChatClientPermissionSnapshot BuildChatClientPermissionSnapshot(string ownerKey, ChatPermissionState permissions)
        {
            permissions = permissions ?? new ChatPermissionState();
            return new ChatClientPermissionSnapshot
            {
                OwnerKey = NormalizeChatFilesystemOwnerKey(ownerKey),
                InternetSearch = permissions.internetSearch,
                VsCopilotTools = permissions.vsCopilotTools,
                FileDownloads = permissions.fileDownloads,
                FtpServer = permissions.ftpServer,
                SqlAdmin = permissions.sqlAdmin,
                AgentAccess = permissions.agentAccess,
                FileUploads = permissions.fileUploads,
                ImageUploads = permissions.imageUploads,
                TerminalCommands = permissions.terminalCommands,
                TerminalForeverApproved = permissions.terminalForeverApproved,
                MutedUntilUtc = permissions.mutedUntilUtc ?? "",
                BannedUntilUtc = permissions.bannedUntilUtc ?? "",
                MuteUntilEnabled = permissions.muteUntilEnabled,
                BanUntilEnabled = permissions.banUntilEnabled,
                IsMuted = IsChatMuted(permissions),
                IsBanned = IsChatBanned(permissions),
                UpdatedUtc = permissions.updatedUtc ?? ""
            };
        }

        private bool IsChatMuted(ChatPermissionState permissions)
        {
            if (permissions == null)
                return false;
            if (permissions.muteUntilEnabled)
                return true;
            return IsFutureUtc(permissions.mutedUntilUtc);
        }

        private bool IsChatBanned(ChatPermissionState permissions)
        {
            if (permissions == null)
                return false;
            if (permissions.banUntilEnabled)
                return true;
            return IsFutureUtc(permissions.bannedUntilUtc);
        }

        private bool IsFutureUtc(string value)
        {
            return DateTimeOffset.TryParse(value, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset parsed) &&
                   parsed.ToUniversalTime() > DateTimeOffset.UtcNow;
        }

        private string BuildChatRestrictionMessage(ChatPermissionState permissions)
        {
            if (IsChatBanned(permissions))
                return permissions.banUntilEnabled
                    ? "This client is banned until an administrator enables it."
                    : "This client is banned until " + FormatRestrictionUntil(permissions.bannedUntilUtc) + ".";
            if (IsChatMuted(permissions))
                return permissions.muteUntilEnabled
                    ? "This client is muted until an administrator enables it."
                    : "This client is muted until " + FormatRestrictionUntil(permissions.mutedUntilUtc) + ".";
            return "";
        }

        private string FormatRestrictionUntil(string value)
        {
            if (DateTimeOffset.TryParse(value, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out DateTimeOffset parsed))
                return parsed.ToLocalTime().ToString("g");
            return string.IsNullOrWhiteSpace(value) ? "the configured time" : value;
        }

        private List<ChatFilesystemAccessEntry> GetChatFilesystemAccess(string ownerKey)
        {
            var directories = new List<ChatFilesystemAccessEntry>();
            if (string.IsNullOrWhiteSpace(ownerKey))
                return directories;

            var ownerKeys = GetEquivalentFilesystemOwnerKeys(ownerKey);
            lock (_chatSessionLock)
            {
                var table = GetChatFilesystemAccessTable();
                foreach (object[] row in table.Rows)
                {
                    if (!OwnerKeyListContains(ownerKeys, GetRowValue(row, 0)))
                        continue;

                    string path = GetRowValue(row, 1);
                    if (string.IsNullOrWhiteSpace(path))
                        continue;
                    if (ContainsFilesystemEntry(directories, path))
                        continue;

                    directories.Add(new ChatFilesystemAccessEntry
                    {
                        path = path,
                        exists = Directory.Exists(path),
                        createdUtc = GetRowValue(row, 2)
                    });
                }
            }

            directories.Sort((a, b) => string.Compare(a.path, b.path, StringComparison.OrdinalIgnoreCase));
            return directories;
        }

        private void SaveChatFilesystemAccess(string ownerKey, string directoryPath)
        {
            if (string.IsNullOrWhiteSpace(ownerKey) || string.IsNullOrWhiteSpace(directoryPath))
                return;

            var ownerKeys = GetEquivalentFilesystemOwnerKeys(ownerKey);
            lock (_chatSessionLock)
            {
                var table = GetChatFilesystemAccessTable();
                foreach (object[] row in table.Rows)
                {
                    if (OwnerKeyListContains(ownerKeys, GetRowValue(row, 0)) &&
                        PathsEqual(GetRowValue(row, 1), directoryPath))
                        return;
                }

                table.Rows.Add(new object[] {
                    ownerKey,
                    directoryPath,
                    DateTimeOffset.UtcNow.ToString("O")
                });
                _chatSessionData.Save();
            }
        }

        private void RemoveChatFilesystemAccess(string ownerKey, string directoryPath)
        {
            if (string.IsNullOrWhiteSpace(ownerKey) || string.IsNullOrWhiteSpace(directoryPath))
                return;

            var ownerKeys = GetEquivalentFilesystemOwnerKeys(ownerKey);
            lock (_chatSessionLock)
            {
                var table = GetChatFilesystemAccessTable();
                int removed = table.Rows.RemoveAll(row =>
                    row != null &&
                    OwnerKeyListContains(ownerKeys, GetRowValue(row, 0)) &&
                    PathsEqual(GetRowValue(row, 1), directoryPath));
                if (removed > 0)
                    _chatSessionData.Save();
            }
        }

        private void AddTemporaryFilesystemAccess(string ownerKey, string directoryPath)
        {
            ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
            if (string.IsNullOrWhiteSpace(directoryPath))
                return;

            string normalized = Path.GetFullPath(directoryPath).TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
            lock (_filesystemPermissionLock)
            {
                if (!_temporaryFilesystemAccess.TryGetValue(ownerKey, out List<string> roots))
                {
                    roots = new List<string>();
                    _temporaryFilesystemAccess[ownerKey] = roots;
                }

                foreach (string root in roots)
                {
                    if (PathsEqual(root, normalized))
                        return;
                }

                roots.Add(normalized);
            }
        }

        private List<string> GetTemporaryFilesystemAccess(string ownerKey)
        {
            ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
            var roots = new List<string>();
            lock (_filesystemPermissionLock)
            {
                foreach (string key in GetEquivalentFilesystemOwnerKeys(ownerKey))
                {
                    if (!_temporaryFilesystemAccess.TryGetValue(key, out List<string> values))
                        continue;
                    foreach (string value in values)
                    {
                        if (!string.IsNullOrWhiteSpace(value) && Directory.Exists(value))
                            AddAllowedRoot(roots, value);
                    }
                }
            }

            return roots;
        }

        private void SaveChatFilesystemDeniedDirectory(string ownerKey, string directoryPath)
        {
            ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
            if (string.IsNullOrWhiteSpace(ownerKey) || string.IsNullOrWhiteSpace(directoryPath))
                return;

            string normalized = Path.GetFullPath(directoryPath).TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
            lock (_chatSessionLock)
            {
                var table = GetChatFilesystemDeniedTable();
                foreach (object[] row in table.Rows)
                {
                    if (OwnerKeyListContains(GetEquivalentFilesystemOwnerKeys(ownerKey), GetRowValue(row, 0)) &&
                        PathsEqual(GetRowValue(row, 1), normalized))
                        return;
                }

                table.Rows.Add(new object[] {
                    ownerKey,
                    normalized,
                    DateTimeOffset.UtcNow.ToString("O")
                });
                _chatSessionData.Save();
            }
        }

        private List<string> GetChatFilesystemDeniedDirectories(string ownerKey)
        {
            var directories = new List<string>();
            if (string.IsNullOrWhiteSpace(ownerKey))
                return directories;

            var ownerKeys = GetEquivalentFilesystemOwnerKeys(ownerKey);
            lock (_chatSessionLock)
            {
                var table = GetChatFilesystemDeniedTable();
                foreach (object[] row in table.Rows)
                {
                    if (!OwnerKeyListContains(ownerKeys, GetRowValue(row, 0)))
                        continue;

                    string path = GetRowValue(row, 1);
                    if (!string.IsNullOrWhiteSpace(path))
                        AddAllowedRoot(directories, path);
                }
            }

            return directories;
        }

        private void SaveTerminalPermissionRule(string ownerKey, string command, string decision)
        {
            ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
            command = NormalizeTerminalCommand(command);
            decision = (decision ?? "").Trim().ToLowerInvariant() == "allow" ? "allow" : "deny";
            if (string.IsNullOrWhiteSpace(ownerKey) || string.IsNullOrWhiteSpace(command))
                return;

            string commandHash = ComputeTerminalCommandHash(command);
            lock (_chatSessionLock)
            {
                var table = GetTerminalPermissionRulesTable();
                foreach (object[] sourceRow in table.Rows)
                {
                    object[] row = NormalizeTerminalPermissionRuleRow(sourceRow);
                    if (OwnerKeyListContains(GetEquivalentFilesystemOwnerKeys(ownerKey), GetRowValue(row, 0)) &&
                        string.Equals(GetRowValue(row, 1), commandHash, StringComparison.OrdinalIgnoreCase))
                    {
                        row[0] = ownerKey;
                        row[2] = command;
                        row[3] = decision;
                        row[4] = DateTimeOffset.UtcNow.ToString("O");
                        _chatSessionData.Save();
                        return;
                    }
                }

                table.Rows.Add(new object[] {
                    ownerKey,
                    commandHash,
                    command,
                    decision,
                    DateTimeOffset.UtcNow.ToString("O")
                });
                _chatSessionData.Save();
            }
        }

        private List<TerminalPermissionRuleSnapshot> GetTerminalPermissionRules(string ownerKey)
        {
            var rules = new List<TerminalPermissionRuleSnapshot>();
            ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
            var ownerKeys = GetEquivalentFilesystemOwnerKeys(ownerKey);

            lock (_chatSessionLock)
            {
                var table = GetTerminalPermissionRulesTable();
                foreach (object[] sourceRow in table.Rows)
                {
                    object[] row = NormalizeTerminalPermissionRuleRow(sourceRow);
                    if (!OwnerKeyListContains(ownerKeys, GetRowValue(row, 0)))
                        continue;

                    rules.Add(new TerminalPermissionRuleSnapshot
                    {
                        Id = GetRowValue(row, 1),
                        OwnerKey = GetRowValue(row, 0),
                        CommandHash = GetRowValue(row, 1),
                        Command = GetRowValue(row, 2),
                        Decision = GetRowValue(row, 3),
                        CreatedUtc = GetRowValue(row, 4)
                    });
                }
            }

            rules.Sort((a, b) => string.CompareOrdinal(b.CreatedUtc, a.CreatedUtc));
            return rules;
        }

        private bool TryGetTerminalPermissionRuleDecision(string ownerKey, string command, out bool approved)
        {
            approved = false;
            ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
            command = NormalizeTerminalCommand(command);
            if (string.IsNullOrWhiteSpace(command))
                return false;

            string commandHash = ComputeTerminalCommandHash(command);
            var ownerKeys = GetEquivalentFilesystemOwnerKeys(ownerKey);
            lock (_chatSessionLock)
            {
                var table = GetTerminalPermissionRulesTable();
                foreach (object[] sourceRow in table.Rows)
                {
                    object[] row = NormalizeTerminalPermissionRuleRow(sourceRow);
                    if (!OwnerKeyListContains(ownerKeys, GetRowValue(row, 0)))
                        continue;
                    if (!string.Equals(GetRowValue(row, 1), commandHash, StringComparison.OrdinalIgnoreCase))
                        continue;

                    approved = string.Equals(GetRowValue(row, 3), "allow", StringComparison.OrdinalIgnoreCase);
                    return true;
                }
            }

            return false;
        }

        private static string NormalizeTerminalCommand(string command)
        {
            command = (command ?? "").Trim();
            while (command.Contains("  ", StringComparison.Ordinal))
                command = command.Replace("  ", " ");
            return command;
        }

        private static string ComputeTerminalCommandHash(string command)
        {
            command = NormalizeTerminalCommand(command).ToLowerInvariant();
            using (SHA256 sha = SHA256.Create())
            {
                byte[] hash = sha.ComputeHash(Encoding.UTF8.GetBytes(command));
                var sb = new StringBuilder(hash.Length * 2);
                foreach (byte b in hash)
                    sb.Append(b.ToString("x2", CultureInfo.InvariantCulture));
                return sb.ToString();
            }
        }

        private bool ContainsFilesystemEntry(List<ChatFilesystemAccessEntry> directories, string path)
        {
            if (directories == null || string.IsNullOrWhiteSpace(path))
                return false;

            foreach (var entry in directories)
            {
                if (entry != null && PathsEqual(entry.path, path))
                    return true;
            }

            return false;
        }

        private List<string> GetEquivalentFilesystemOwnerKeys(string ownerKey)
        {
            var keys = new List<string>();
            AddOwnerKey(keys, ownerKey);
            string ip = ExtractIpFromOwnerKey(ownerKey);
            if (IsLoopbackClientIp(ip))
            {
                AddOwnerKey(keys, "ip:127.0.0.1");
                AddOwnerKey(keys, "ip:::1");
                AddOwnerKey(keys, "ip:localhost");
            }

            return keys;
        }

        private void AddOwnerKey(List<string> keys, string ownerKey)
        {
            if (keys == null || string.IsNullOrWhiteSpace(ownerKey))
                return;

            foreach (string key in keys)
            {
                if (string.Equals(key, ownerKey, StringComparison.OrdinalIgnoreCase))
                    return;
            }

            keys.Add(ownerKey);
        }

        private bool OwnerKeyListContains(List<string> keys, string ownerKey)
        {
            if (keys == null || string.IsNullOrWhiteSpace(ownerKey))
                return false;

            foreach (string key in keys)
            {
                if (string.Equals(key, ownerKey, StringComparison.OrdinalIgnoreCase))
                    return true;
            }

            return false;
        }

        private string ExtractIpFromOwnerKey(string ownerKey)
        {
            if (string.IsNullOrWhiteSpace(ownerKey))
                return null;
            return ownerKey.StartsWith("ip:", StringComparison.OrdinalIgnoreCase)
                ? ownerKey.Substring(3)
                : ownerKey;
        }

        private bool IsLoopbackClientIp(string ip)
        {
            if (string.IsNullOrWhiteSpace(ip))
                return false;
            ip = NormalizeClientIp(ip);
            if (string.Equals(ip, "localhost", StringComparison.OrdinalIgnoreCase))
                return true;
            if (IPAddress.TryParse(ip, out IPAddress address))
                return IsLocalAddress(address);
            return false;
        }

        private object BuildDirectoryBrowserModel(string requestedPath)
        {
            var roots = new List<DirectoryBrowserEntry>();
            try
            {
                foreach (string drive in Directory.GetLogicalDrives())
                {
                    roots.Add(new DirectoryBrowserEntry
                    {
                        name = drive,
                        path = drive,
                        exists = Directory.Exists(drive)
                    });
                }
            }
            catch
            {
                string root = Path.GetPathRoot(AppContext.BaseDirectory ?? Directory.GetCurrentDirectory());
                if (!string.IsNullOrWhiteSpace(root))
                {
                    roots.Add(new DirectoryBrowserEntry
                    {
                        name = root,
                        path = root,
                        exists = Directory.Exists(root)
                    });
                }
            }

            string currentPath = null;
            if (!string.IsNullOrWhiteSpace(requestedPath))
            {
                TryNormalizeAccessibleDirectory(requestedPath, requireExists: true, out currentPath, out _);
            }

            if (string.IsNullOrWhiteSpace(currentPath) && roots.Count == 1)
                currentPath = roots[0].path;

            var directories = new List<DirectoryBrowserEntry>();
            string parentPath = "";
            string error = null;
            if (!string.IsNullOrWhiteSpace(currentPath))
            {
                try
                {
                    var parent = Directory.GetParent(currentPath);
                    parentPath = parent != null ? parent.FullName : "";

                    foreach (string directory in Directory.GetDirectories(currentPath))
                    {
                        string name;
                        try
                        {
                            name = Path.GetFileName(directory.TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar));
                        }
                        catch
                        {
                            name = directory;
                        }

                        directories.Add(new DirectoryBrowserEntry
                        {
                            name = string.IsNullOrWhiteSpace(name) ? directory : name,
                            path = directory,
                            exists = Directory.Exists(directory)
                        });
                    }
                }
                catch (Exception ex)
                {
                    error = ex.Message;
                }
            }

            directories.Sort((a, b) => string.Compare(a.name, b.name, StringComparison.OrdinalIgnoreCase));
            return new
            {
                ok = true,
                canEdit = true,
                path = currentPath ?? "",
                parentPath = parentPath ?? "",
                roots,
                directories,
                canSelect = !string.IsNullOrWhiteSpace(currentPath) && Directory.Exists(currentPath),
                error
            };
        }

        private string GetQueryParameter(HttpRequest request, string name)
        {
            if (request == null || request.QueryParameters == null || string.IsNullOrWhiteSpace(name))
                return null;
            return request.QueryParameters.TryGetValue(name, out string value) ? value : null;
        }

        private List<SolutionExplorerEntry> BuildChatSolutionExplorerRoots(string ownerKey, string sessionId)
        {
            var roots = new List<SolutionExplorerEntry>();
            string sessionRoot = GetChatSessionFilesDirectory(sessionId);
            if (!string.IsNullOrWhiteSpace(sessionId) && !string.IsNullOrWhiteSpace(sessionRoot))
            {
                bool sessionExists;
                try
                {
                    Directory.CreateDirectory(sessionRoot);
                    sessionExists = Directory.Exists(sessionRoot);
                }
                catch
                {
                    sessionExists = Directory.Exists(sessionRoot);
                }

                roots.Add(new SolutionExplorerEntry
                {
                    name = "Current Session Files",
                    path = sessionRoot,
                    kind = "session",
                    sessionId = sessionId,
                    type = "directory",
                    exists = sessionExists,
                    hasChildren = sessionExists
                });
            }

            foreach (ChatFilesystemAccessEntry entry in GetChatFilesystemAccess(ownerKey))
            {
                if (entry == null || string.IsNullOrWhiteSpace(entry.path))
                    continue;

                roots.Add(new SolutionExplorerEntry
                {
                    name = GetExplorerDisplayName(entry.path),
                    path = entry.path,
                    kind = "accessible",
                    sessionId = sessionId,
                    type = "directory",
                    exists = entry.exists,
                    hasChildren = entry.exists
                });
            }

            return roots;
        }

        private string GetChatSessionFilesDirectory(string sessionId)
        {
            if (string.IsNullOrWhiteSpace(sessionId))
                return null;
            return Path.Combine(_chatSessionFilesRoot, SanitizeFileName(sessionId.Trim()));
        }

        private bool TryResolveSolutionExplorerDirectory(string ownerKey, string sessionId, string kind, string requestedPath, out string fullPath, out string error)
        {
            fullPath = null;
            error = null;
            if (string.IsNullOrWhiteSpace(requestedPath))
            {
                error = "path is required.";
                return false;
            }

            string candidate;
            try
            {
                candidate = Path.GetFullPath(NormalizeLoosePathEscapes(requestedPath).Trim().Trim('"', '\'', ',', ' '));
            }
            catch (Exception ex)
            {
                error = ex.Message;
                return false;
            }

            if (kind.Equals("session", StringComparison.OrdinalIgnoreCase))
            {
                string sessionRoot = GetChatSessionFilesDirectory(sessionId);
                if (string.IsNullOrWhiteSpace(sessionRoot) || !IsPathInsideRoot(candidate, sessionRoot))
                {
                    error = "path is outside the current session files.";
                    return false;
                }

                if (!Directory.Exists(candidate))
                {
                    error = "directory does not exist: " + candidate;
                    return false;
                }

                fullPath = candidate;
                return true;
            }

            var roots = new List<string>();
            foreach (ChatFilesystemAccessEntry entry in GetChatFilesystemAccess(ownerKey))
            {
                if (entry != null && entry.exists)
                    AddAllowedRoot(roots, entry.path);
            }

            if (!IsPathUnderAnyRoot(candidate, roots))
            {
                error = "path is outside the accessible directories.";
                return false;
            }

            if (!Directory.Exists(candidate))
            {
                error = "directory does not exist: " + candidate;
                return false;
            }

            fullPath = candidate;
            return true;
        }

        private bool TryResolveSolutionExplorerFile(string ownerKey, string sessionId, string kind, string requestedPath, out string fullPath, out string error)
        {
            fullPath = null;
            error = null;
            if (string.IsNullOrWhiteSpace(requestedPath))
            {
                error = "path is required.";
                return false;
            }

            string candidate;
            try
            {
                candidate = Path.GetFullPath(NormalizeLoosePathEscapes(requestedPath).Trim().Trim('"', '\'', ',', ' '));
            }
            catch (Exception ex)
            {
                error = ex.Message;
                return false;
            }

            if (kind.Equals("session", StringComparison.OrdinalIgnoreCase))
            {
                string sessionRoot = GetChatSessionFilesDirectory(sessionId);
                if (string.IsNullOrWhiteSpace(sessionRoot) || !IsPathInsideRoot(candidate, sessionRoot))
                {
                    error = "path is outside the current session files.";
                    return false;
                }

                if (!File.Exists(candidate))
                {
                    error = "file does not exist: " + candidate;
                    return false;
                }

                fullPath = candidate;
                return true;
            }

            var roots = new List<string>();
            foreach (ChatFilesystemAccessEntry entry in GetChatFilesystemAccess(ownerKey))
            {
                if (entry != null && entry.exists)
                    AddAllowedRoot(roots, entry.path);
            }

            if (!IsPathUnderAnyRoot(candidate, roots))
            {
                error = "path is outside the accessible directories.";
                return false;
            }

            if (!File.Exists(candidate))
            {
                error = "file does not exist: " + candidate;
                return false;
            }

            fullPath = candidate;
            return true;
        }

        private string GetChatFilePreviewKind(string extension, string mimeType)
        {
            extension = (extension ?? "").Trim().ToLowerInvariant();
            if (extension.Equals(".html", StringComparison.OrdinalIgnoreCase) ||
                extension.Equals(".htm", StringComparison.OrdinalIgnoreCase))
                return "html";

            if (!string.IsNullOrWhiteSpace(mimeType) &&
                mimeType.StartsWith("image/", StringComparison.OrdinalIgnoreCase))
                return "image";

            return "text";
        }

        private string GetChatFilePreviewMimeType(string extension)
        {
            switch ((extension ?? "").Trim().ToLowerInvariant())
            {
                case ".html":
                case ".htm":
                    return "text/html";
                case ".css":
                    return "text/css";
                case ".js":
                case ".mjs":
                case ".cjs":
                    return "text/javascript";
                case ".json":
                    return "application/json";
                case ".svg":
                    return "image/svg+xml";
                case ".png":
                    return "image/png";
                case ".jpg":
                case ".jpeg":
                    return "image/jpeg";
                case ".gif":
                    return "image/gif";
                case ".webp":
                    return "image/webp";
                case ".bmp":
                    return "image/bmp";
                case ".ico":
                    return "image/x-icon";
                case ".txt":
                case ".md":
                case ".cs":
                case ".vb":
                case ".xaml":
                case ".xml":
                case ".config":
                case ".csproj":
                case ".sln":
                case ".yml":
                case ".yaml":
                    return "text/plain";
                default:
                    return "text/plain";
            }
        }

        private List<SolutionExplorerEntry> BuildSolutionExplorerChildren(string kind, string directory, string sessionId)
        {
            var children = new List<SolutionExplorerEntry>();
            const int maxChildren = 180;

            var directories = new List<SolutionExplorerEntry>();
            try
            {
                foreach (string child in Directory.EnumerateDirectories(directory))
                {
                    if (ShouldFilterGeneratedOrBuildOutputPath(child, directory))
                        continue;
                    directories.Add(BuildSolutionExplorerEntry(kind, child, true, sessionId));
                    if (directories.Count >= maxChildren)
                        break;
                }
            }
            catch { }

            directories.Sort((a, b) => string.Compare(a.name, b.name, StringComparison.OrdinalIgnoreCase));
            foreach (SolutionExplorerEntry entry in directories)
                children.Add(entry);

            int remaining = maxChildren - children.Count;
            if (remaining <= 0)
                return children;

            var files = new List<SolutionExplorerEntry>();
            try
            {
                foreach (string child in Directory.EnumerateFiles(directory))
                {
                    if (ShouldFilterGeneratedOrBuildOutputPath(child, directory))
                        continue;
                    files.Add(BuildSolutionExplorerEntry(kind, child, false, sessionId));
                    if (files.Count >= remaining)
                        break;
                }
            }
            catch { }

            files.Sort((a, b) => string.Compare(a.name, b.name, StringComparison.OrdinalIgnoreCase));
            foreach (SolutionExplorerEntry entry in files)
                children.Add(entry);
            return children;
        }

        private SolutionExplorerEntry BuildSolutionExplorerEntry(string kind, string path, bool isDirectory, string sessionId = null)
        {
            var entry = new SolutionExplorerEntry
            {
                name = GetExplorerDisplayName(path),
                path = path,
                kind = string.IsNullOrWhiteSpace(kind) ? "accessible" : kind,
                sessionId = sessionId ?? "",
                type = isDirectory ? "directory" : "file",
                exists = isDirectory ? Directory.Exists(path) : File.Exists(path),
                hasChildren = isDirectory,
                extension = isDirectory ? "" : Path.GetExtension(path)
            };

            try
            {
                if (isDirectory)
                {
                    var info = new DirectoryInfo(path);
                    entry.modifiedUtc = info.Exists ? info.LastWriteTimeUtc.ToString("O") : "";
                }
                else
                {
                    var info = new FileInfo(path);
                    entry.size = info.Exists ? info.Length : 0;
                    entry.modifiedUtc = info.Exists ? info.LastWriteTimeUtc.ToString("O") : "";
                }
            }
            catch { }

            return entry;
        }

        private string GetExplorerDisplayName(string path)
        {
            if (string.IsNullOrWhiteSpace(path))
                return "";
            try
            {
                string trimmed = path.TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
                string name = Path.GetFileName(trimmed);
                return string.IsNullOrWhiteSpace(name) ? path : name;
            }
            catch
            {
                return path;
            }
        }

        private ChatFtpServerConfig GetChatFtpConfig(string ownerKey)
        {
            if (string.IsNullOrWhiteSpace(ownerKey))
                ownerKey = "ip:unknown";

            lock (_chatSessionLock)
            {
                var table = GetChatFtpConfigTable();
                for (int i = 0; i < table.Rows.Count; i++)
                {
                    object[] row = NormalizeChatFtpConfigRow(table.Rows[i]);
                    table.Rows[i] = row;
                    if (string.Equals(GetRowValue(row, 0), ownerKey, StringComparison.OrdinalIgnoreCase))
                        return ChatFtpConfigFromRow(row);
                }

                object[] newRow = NormalizeChatFtpConfigRow(new object[] {
                    ownerKey,
                    "false",
                    "",
                    "2121",
                    "lmvsproxy",
                    GenerateChatFtpPassword(),
                    "true",
                    DateTimeOffset.UtcNow.ToString("O"),
                    "false"
                });
                table.Rows.Add(newRow);
                _chatSessionData.Save();
                return ChatFtpConfigFromRow(newRow);
            }
        }

        private void SaveChatFtpConfig(string ownerKey, ChatFtpServerConfig config)
        {
            if (string.IsNullOrWhiteSpace(ownerKey) || config == null)
                return;

            lock (_chatSessionLock)
            {
                var table = GetChatFtpConfigTable();
                object[] row = NormalizeChatFtpConfigRow(new object[] {
                    ownerKey,
                    config.enabled ? "true" : "false",
                    config.rootPath ?? "",
                    NormalizeFtpPort(config.port).ToString(),
                    NormalizeFtpUserName(config.userName),
                    string.IsNullOrWhiteSpace(config.password) ? GenerateChatFtpPassword() : config.password,
                    config.allowWrite ? "true" : "false",
                    DateTimeOffset.UtcNow.ToString("O"),
                    config.autoStart ? "true" : "false",
                    SerializeChatFtpUsers(config)
                });

                for (int i = 0; i < table.Rows.Count; i++)
                {
                    object[] existing = NormalizeChatFtpConfigRow(table.Rows[i]);
                    if (string.Equals(GetRowValue(existing, 0), ownerKey, StringComparison.OrdinalIgnoreCase))
                    {
                        table.Rows[i] = row;
                        _chatSessionData.Save();
                        return;
                    }
                }

                table.Rows.Add(row);
                _chatSessionData.Save();
            }
        }

        private ChatFtpServerConfig ChatFtpConfigFromRow(object[] row)
        {
            var config = new ChatFtpServerConfig
            {
                enabled = ParseStoredBool(GetRowValue(row, 1), false),
                rootPath = GetRowValue(row, 2),
                port = NormalizeFtpPort(ParseStoredInt(GetRowValue(row, 3), 2121)),
                userName = NormalizeFtpUserName(GetRowValue(row, 4)),
                password = string.IsNullOrWhiteSpace(GetRowValue(row, 5)) ? GenerateChatFtpPassword() : GetRowValue(row, 5),
                allowWrite = ParseStoredBool(GetRowValue(row, 6), true),
                updatedUtc = GetRowValue(row, 7),
                autoStart = ParseStoredBool(GetRowValue(row, 8), false),
                users = ParseChatFtpUsers(GetRowValue(row, 9))
            };
            EnsureChatFtpUserList(config);
            return config;
        }

        private ChatFtpServerConfig BuildChatFtpConfigFromJson(JsonElement root, ChatFtpServerConfig existing)
        {
            var config = new ChatFtpServerConfig
            {
                enabled = existing != null && existing.enabled,
                rootPath = existing?.rootPath ?? "",
                port = existing != null ? existing.port : 2121,
                userName = existing?.userName ?? "lmvsproxy",
                password = existing?.password ?? "",
                allowWrite = existing == null || existing.allowWrite,
                autoStart = existing != null && existing.autoStart,
                users = existing?.users != null ? new List<ChatFtpUserConfig>(existing.users) : new List<ChatFtpUserConfig>(),
                updatedUtc = DateTimeOffset.UtcNow.ToString("O")
            };

            if (root.TryGetProperty("rootPath", out JsonElement rootPath))
                config.rootPath = ExtractJsonString(rootPath) ?? config.rootPath;
            if (root.TryGetProperty("port", out JsonElement port))
                config.port = NormalizeFtpPort(ReadJsonInt(port, config.port));
            if (root.TryGetProperty("userName", out JsonElement userName))
                config.userName = NormalizeFtpUserName(ExtractJsonString(userName) ?? config.userName);
            if (root.TryGetProperty("password", out JsonElement password))
                config.password = ExtractJsonString(password) ?? config.password;
            if (root.TryGetProperty("allowWrite", out JsonElement allowWrite))
                config.allowWrite = ReadJsonBool(allowWrite, config.allowWrite);
            if (root.TryGetProperty("autoStart", out JsonElement autoStart))
                config.autoStart = ReadJsonBool(autoStart, config.autoStart);
            if (root.TryGetProperty("users", out JsonElement users) && users.ValueKind == JsonValueKind.Array)
                config.users = ReadChatFtpUsers(users);

            config.port = NormalizeFtpPort(config.port);
            config.userName = NormalizeFtpUserName(config.userName);
            if (string.IsNullOrWhiteSpace(config.password))
                config.password = GenerateChatFtpPassword();
            EnsureChatFtpUserList(config);
            return config;
        }

        private void EnsureChatFtpUserList(ChatFtpServerConfig config)
        {
            if (config == null)
                return;

            if (config.users == null)
                config.users = new List<ChatFtpUserConfig>();

            var normalizedUsers = new List<ChatFtpUserConfig>();
            foreach (ChatFtpUserConfig user in config.users)
            {
                ChatFtpUserConfig normalized = NormalizeChatFtpUser(user);
                if (normalized != null && !ChatFtpUserNameExists(normalizedUsers, normalized.userName))
                    normalizedUsers.Add(normalized);
            }

            ChatFtpUserConfig primary = NormalizeChatFtpUser(new ChatFtpUserConfig
            {
                userName = config.userName,
                password = config.password,
                rootPath = config.rootPath,
                allowWrite = config.allowWrite
            });
            if (primary != null && !ChatFtpUserNameExists(normalizedUsers, primary.userName))
                normalizedUsers.Insert(0, primary);

            if (normalizedUsers.Count > 0)
            {
                config.userName = normalizedUsers[0].userName;
                config.password = normalizedUsers[0].password;
                config.rootPath = normalizedUsers[0].rootPath;
                config.allowWrite = normalizedUsers[0].allowWrite;
            }

            config.users = normalizedUsers;
        }

        private ChatFtpUserConfig NormalizeChatFtpUser(ChatFtpUserConfig user)
        {
            if (user == null)
                return null;

            string userName = NormalizeFtpUserName(user.userName);
            string password = string.IsNullOrWhiteSpace(user.password) ? GenerateChatFtpPassword() : user.password;
            string rootPath = user.rootPath ?? "";
            if (string.IsNullOrWhiteSpace(userName))
                return null;

            return new ChatFtpUserConfig
            {
                userName = userName,
                password = password,
                rootPath = rootPath,
                allowWrite = user.allowWrite
            };
        }

        private bool ChatFtpUserNameExists(List<ChatFtpUserConfig> users, string userName)
        {
            if (users == null || string.IsNullOrWhiteSpace(userName))
                return false;
            foreach (ChatFtpUserConfig user in users)
            {
                if (user != null && string.Equals(user.userName, userName, StringComparison.OrdinalIgnoreCase))
                    return true;
            }
            return false;
        }

        private List<ChatFtpUserConfig> ParseChatFtpUsers(string usersJson)
        {
            if (string.IsNullOrWhiteSpace(usersJson))
                return new List<ChatFtpUserConfig>();
            try
            {
                using (JsonDocument document = JsonDocument.Parse(usersJson))
                {
                    return document.RootElement.ValueKind == JsonValueKind.Array
                        ? ReadChatFtpUsers(document.RootElement)
                        : new List<ChatFtpUserConfig>();
                }
            }
            catch
            {
                return new List<ChatFtpUserConfig>();
            }
        }

        private List<ChatFtpUserConfig> ReadChatFtpUsers(JsonElement users)
        {
            var result = new List<ChatFtpUserConfig>();
            if (users.ValueKind != JsonValueKind.Array)
                return result;

            foreach (JsonElement item in users.EnumerateArray())
            {
                if (item.ValueKind != JsonValueKind.Object)
                    continue;

                var user = new ChatFtpUserConfig();
                if (item.TryGetProperty("userName", out JsonElement userName))
                    user.userName = NormalizeFtpUserName(ExtractJsonString(userName) ?? "");
                if (item.TryGetProperty("password", out JsonElement password))
                    user.password = ExtractJsonString(password) ?? "";
                if (item.TryGetProperty("rootPath", out JsonElement rootPath))
                    user.rootPath = ExtractJsonString(rootPath) ?? "";
                if (item.TryGetProperty("allowWrite", out JsonElement allowWrite))
                    user.allowWrite = ReadJsonBool(allowWrite, true);

                ChatFtpUserConfig normalized = NormalizeChatFtpUser(user);
                if (normalized != null && !ChatFtpUserNameExists(result, normalized.userName))
                    result.Add(normalized);
            }

            return result;
        }

        private string SerializeChatFtpUsers(ChatFtpServerConfig config)
        {
            EnsureChatFtpUserList(config);
            return JsonSerializer.Serialize(config?.users ?? new List<ChatFtpUserConfig>());
        }

        private string NormalizeAndValidateChatFtpUsers(string ownerKey, ChatFtpServerConfig config)
        {
            EnsureChatFtpUserList(config);
            if (config == null || config.users == null || config.users.Count == 0)
                return "At least one FTP user is required.";

            foreach (ChatFtpUserConfig user in config.users)
            {
                if (user == null)
                    continue;

                if (!TryNormalizeAccessibleDirectory(user.rootPath, requireExists: true, out string normalizedRoot, out string error))
                    return error;

                if (!IsDirectoryInChatFilesystemAccess(ownerKey, normalizedRoot))
                    return "FTP root must be one of the accessible directories for this client: " + normalizedRoot;

                user.rootPath = normalizedRoot;
            }

            config.userName = config.users[0].userName;
            config.password = config.users[0].password;
            config.rootPath = config.users[0].rootPath;
            config.allowWrite = config.users[0].allowWrite;
            return "";
        }

        private void ApplyDefaultChatFtpDirectory(ChatFtpServerConfig config, List<ChatFilesystemAccessEntry> directories)
        {
            if (config == null || !string.IsNullOrWhiteSpace(config.rootPath) || directories == null)
                return;

            foreach (var entry in directories)
            {
                if (entry != null && entry.exists && !string.IsNullOrWhiteSpace(entry.path))
                {
                    config.rootPath = entry.path;
                    return;
                }
            }
        }

        private bool IsDirectoryInChatFilesystemAccess(string ownerKey, string directoryPath)
        {
            if (string.IsNullOrWhiteSpace(ownerKey) || string.IsNullOrWhiteSpace(directoryPath))
                return false;

            foreach (var entry in GetChatFilesystemAccess(ownerKey))
            {
                if (entry != null && entry.exists && PathsEqual(entry.path, directoryPath))
                    return true;
            }

            return false;
        }

        private void ApplyRuntimeChatPermissions(ChatPermissionState permissions)
        {
            MutableTcpServer mutable = null;
            lock (_chatServerLock)
                mutable = _chatServer as MutableTcpServer;

            if (mutable != null)
                mutable.SqlAdminPanelEnabled = permissions != null && permissions.sqlAdmin;

            if (permissions == null || !permissions.ftpServer)
                StopChatFtpServer();
            else
                TryAutoStartChatFtpServer(permissions);
        }

        private void StartChatFtpServer(string ownerKey, ChatFtpServerConfig config)
        {
            if (config == null)
                throw new InvalidOperationException("FTP configuration is missing.");
            EnsureChatFtpUserList(config);
            if (config.users == null || config.users.Count == 0 || string.IsNullOrWhiteSpace(config.rootPath))
                throw new InvalidOperationException("At least one FTP user with a root directory is required.");

            var userStore = new FtpUserStore();
            foreach (ChatFtpUserConfig user in config.users)
            {
                userStore.Add(new FtpUser
                {
                    UserName = NormalizeFtpUserName(user.userName),
                    Password = user.password ?? "",
                    RootPath = user.rootPath,
                    CanRead = true,
                    CanWrite = user.allowWrite,
                    CanDelete = user.allowWrite,
                    CanCreateDirectory = user.allowWrite,
                    IsAnonymous = false
                });
            }

            var options = new FtpServerOptions
            {
                RootPath = config.rootPath,
                Authenticator = userStore,
                AllowAnonymous = false,
                Encoding = new UTF8Encoding(false),
                ServerName = "LmVsProxy FTP Server"
            };

            var ftpServer = new FtpServer(NormalizeFtpPort(config.port), options, "LmVsProxy FTP Server");
            ftpServer.Options.Logging = true;
            ftpServer.LogOutput += RelaySocketJackLogOutput;
            ftpServer.OnError += RelaySocketJackError;
            lock (_chatFtpServerLock)
            {
                StopChatFtpServerLocked();
                if (!ftpServer.Listen())
                {
                    try { ftpServer.StopListening(); } catch { }
                    ftpServer.LogOutput -= RelaySocketJackLogOutput;
                    ftpServer.OnError -= RelaySocketJackError;
                    throw new InvalidOperationException("Unable to start FTP server on port " + NormalizeFtpPort(config.port) + ".");
                }

                _chatFtpServer = ftpServer;
                _activeChatFtpOwnerKey = ownerKey;
                _activeChatFtpConfig = new ChatFtpServerConfig
                {
                    enabled = true,
                    rootPath = config.rootPath,
                    port = NormalizeFtpPort(config.port),
                    userName = NormalizeFtpUserName(config.userName),
                    password = config.password ?? "",
                    allowWrite = config.allowWrite,
                    autoStart = config.autoStart,
                    users = config.users != null ? new List<ChatFtpUserConfig>(config.users) : new List<ChatFtpUserConfig>(),
                    updatedUtc = DateTimeOffset.UtcNow.ToString("O")
                };
            }

            LogMessage($"[Chat UI] FTP server started on port {NormalizeFtpPort(config.port)} for {config.users.Count} user account(s). Autostart={config.autoStart}.");
        }

        private void TryAutoStartChatFtpServer(ChatPermissionState permissions)
        {
            if (permissions == null || !permissions.ftpServer)
                return;

            lock (_chatFtpServerLock)
            {
                if (_chatFtpServer != null && _chatFtpServer.IsListening)
                    return;
            }

            string ownerKey;
            ChatFtpServerConfig config;
            if (!TryGetAutoStartChatFtpConfig(out ownerKey, out config))
                return;

            try
            {
                config.enabled = true;
                StartChatFtpServer(ownerKey, config);
                SaveChatFtpConfig(ownerKey, config);
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] FTP auto-start skipped: " + ex.Message);
            }
        }

        private bool TryGetAutoStartChatFtpConfig(out string ownerKey, out ChatFtpServerConfig config)
        {
            ownerKey = null;
            config = null;

            var candidates = new List<Tuple<string, ChatFtpServerConfig>>();
            lock (_chatSessionLock)
            {
                var table = GetChatFtpConfigTable();
                for (int i = 0; i < table.Rows.Count; i++)
                {
                    object[] row = NormalizeChatFtpConfigRow(table.Rows[i]);
                    table.Rows[i] = row;
                    ChatFtpServerConfig candidate = ChatFtpConfigFromRow(row);
                    if (candidate.autoStart)
                        candidates.Add(Tuple.Create(GetRowValue(row, 0), candidate));
                }
            }

            DateTimeOffset bestUpdated = DateTimeOffset.MinValue;
            foreach (var candidate in candidates)
            {
                if (candidate == null || candidate.Item2 == null)
                    continue;
                string candidateOwnerKey = string.IsNullOrWhiteSpace(candidate.Item1) ? "ip:unknown" : candidate.Item1;
                ChatFtpServerConfig candidateConfig = candidate.Item2;
                if (string.IsNullOrWhiteSpace(candidateConfig.rootPath) || !Directory.Exists(candidateConfig.rootPath))
                    continue;
                if (!IsDirectoryInChatFilesystemAccess(candidateOwnerKey, candidateConfig.rootPath))
                    continue;

                DateTimeOffset updated;
                if (!DateTimeOffset.TryParse(candidateConfig.updatedUtc, out updated))
                    updated = DateTimeOffset.MinValue;

                if (config == null || updated >= bestUpdated)
                {
                    ownerKey = candidateOwnerKey;
                    config = candidateConfig;
                    bestUpdated = updated;
                }
            }

            return config != null;
        }

        private void StopChatFtpServer()
        {
            lock (_chatFtpServerLock)
                StopChatFtpServerLocked();
        }

        private void StopChatFtpServerLocked()
        {
            if (_chatFtpServer != null)
            {
                bool wasListening = _chatFtpServer.IsListening;
                try
                {
                    if (_chatFtpServer.IsListening)
                        _chatFtpServer.StopListening();
                }
                catch (Exception ex)
                {
                    LogMessage("[Chat UI] FTP stop failed: " + ex.Message);
                }
                _chatFtpServer.LogOutput -= RelaySocketJackLogOutput;
                _chatFtpServer.OnError -= RelaySocketJackError;
                if (wasListening)
                    LogMessage("[Chat UI] FTP server stopped.");
            }

            _chatFtpServer = null;
            _activeChatFtpOwnerKey = null;
            _activeChatFtpConfig = null;
        }

        private bool IsChatFtpServerActiveForOwner(string ownerKey)
        {
            lock (_chatFtpServerLock)
            {
                return _chatFtpServer != null &&
                       _chatFtpServer.IsListening &&
                       string.Equals(_activeChatFtpOwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase);
            }
        }

        private void StopChatFtpServerIfRootRemoved(string ownerKey, string directoryPath)
        {
            bool shouldStop;
            lock (_chatFtpServerLock)
            {
                shouldStop = _chatFtpServer != null &&
                             _chatFtpServer.IsListening &&
                             string.Equals(_activeChatFtpOwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase) &&
                             _activeChatFtpConfig != null &&
                             PathsEqual(_activeChatFtpConfig.rootPath, directoryPath);
            }

            if (!shouldStop)
                return;

            StopChatFtpServer();
            ChatFtpServerConfig config = GetChatFtpConfig(ownerKey);
            config.enabled = false;
            config.updatedUtc = DateTimeOffset.UtcNow.ToString("O");
            SaveChatFtpConfig(ownerKey, config);
        }

        private object GetChatFtpServerStatus()
        {
            lock (_chatFtpServerLock)
            {
                return new
                {
                    running = _chatFtpServer != null && _chatFtpServer.IsListening,
                    ownerKey = _activeChatFtpOwnerKey ?? "",
                    port = _activeChatFtpConfig != null ? _activeChatFtpConfig.port : 0,
                    rootPath = _activeChatFtpConfig != null ? _activeChatFtpConfig.rootPath : "",
                    userName = _activeChatFtpConfig != null ? _activeChatFtpConfig.userName : "",
                    userCount = _activeChatFtpConfig != null && _activeChatFtpConfig.users != null ? _activeChatFtpConfig.users.Count : 0
                };
            }
        }

        private bool TryNormalizeAccessibleDirectory(string path, bool requireExists, out string normalizedPath, out string error)
        {
            normalizedPath = null;
            error = null;
            if (string.IsNullOrWhiteSpace(path))
            {
                error = "Directory path is required.";
                return false;
            }

            try
            {
                normalizedPath = Path.GetFullPath(Environment.ExpandEnvironmentVariables(path.Trim().Trim('"')));
                if (requireExists && !Directory.Exists(normalizedPath))
                {
                    error = "Directory does not exist: " + normalizedPath;
                    return false;
                }

                return true;
            }
            catch (Exception ex)
            {
                error = "Invalid directory path: " + ex.Message;
                return false;
            }
        }

        private bool PathsEqual(string left, string right)
        {
            if (string.IsNullOrWhiteSpace(left) || string.IsNullOrWhiteSpace(right))
                return false;

            try
            {
                left = Path.GetFullPath(left.Trim()).TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
                right = Path.GetFullPath(right.Trim()).TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
            }
            catch { }

            return string.Equals(left, right, StringComparison.OrdinalIgnoreCase);
        }

        private bool ReadJsonBool(JsonElement element, bool fallback)
        {
            if (element.ValueKind == JsonValueKind.True)
                return true;
            if (element.ValueKind == JsonValueKind.False)
                return false;
            if (element.ValueKind == JsonValueKind.Number && element.TryGetInt32(out int number))
                return number != 0;
            if (element.ValueKind == JsonValueKind.String)
                return ParseStoredBool(element.GetString(), fallback);
            return fallback;
        }

        private int ReadJsonInt(JsonElement element, int fallback)
        {
            if (element.ValueKind == JsonValueKind.Number && element.TryGetInt32(out int number))
                return number;
            if (element.ValueKind == JsonValueKind.String)
                return ParseStoredInt(element.GetString(), fallback);
            return fallback;
        }

        private long ReadJsonLong(JsonElement element, long fallback)
        {
            if (element.ValueKind == JsonValueKind.Number && element.TryGetInt64(out long number))
                return number;
            if (element.ValueKind == JsonValueKind.String)
                return ParseStoredLong(element.GetString(), fallback);
            return fallback;
        }

        private double ReadJsonDouble(JsonElement element, double fallback)
        {
            if (element.ValueKind == JsonValueKind.Number && element.TryGetDouble(out double number))
                return number;
            if (element.ValueKind == JsonValueKind.String && double.TryParse(element.GetString(), NumberStyles.Float, CultureInfo.InvariantCulture, out double parsed))
                return parsed;
            return fallback;
        }

        private string ExtractJsonString(JsonElement element)
        {
            if (element.ValueKind == JsonValueKind.String)
                return element.GetString();
            if (element.ValueKind == JsonValueKind.Number || element.ValueKind == JsonValueKind.True || element.ValueKind == JsonValueKind.False)
                return element.ToString();
            return null;
        }

        private bool ParseStoredBool(string value, bool fallback)
        {
            if (string.IsNullOrWhiteSpace(value))
                return fallback;
            if (bool.TryParse(value, out bool parsed))
                return parsed;
            if (int.TryParse(value, out int number))
                return number != 0;
            return fallback;
        }

        private int ParseStoredInt(string value, int fallback)
        {
            if (string.IsNullOrWhiteSpace(value))
                return fallback;
            return int.TryParse(value, out int parsed) ? parsed : fallback;
        }

        private long ParseStoredLong(string value, long fallback)
        {
            if (string.IsNullOrWhiteSpace(value))
                return fallback;
            return long.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out long parsed) ? parsed : fallback;
        }

        private double ParseStoredDouble(string value, double fallback)
        {
            if (string.IsNullOrWhiteSpace(value))
                return fallback;
            return double.TryParse(value, NumberStyles.Float, CultureInfo.InvariantCulture, out double parsed) ? parsed : fallback;
        }

        private int NormalizeFtpPort(int port)
        {
            return port > 0 && port <= 65535 ? port : 2121;
        }

        private string NormalizeFtpUserName(string userName)
        {
            userName = (userName ?? "").Trim();
            if (string.IsNullOrWhiteSpace(userName))
                return "lmvsproxy";

            var sb = new StringBuilder(userName.Length);
            foreach (char ch in userName)
            {
                if (char.IsLetterOrDigit(ch) || ch == '_' || ch == '-' || ch == '.' || ch == '@')
                    sb.Append(ch);
            }

            return sb.Length == 0 ? "lmvsproxy" : sb.ToString();
        }

        private string GenerateChatFtpPassword()
        {
            return Guid.NewGuid().ToString("N").Substring(0, 12);
        }

        private bool IsLocalAdmin(NetworkConnection connection)
        {
            return IsLocalAdmin(connection, null);
        }

        private bool IsLocalAdmin(NetworkConnection connection, HttpRequest request)
        {
            try
            {
                IPAddress address = connection?.EndPoint?.Address;
                if (address == null && connection?.Socket?.RemoteEndPoint is IPEndPoint socketEndPoint)
                    address = socketEndPoint.Address;
                return IsLocalAddress(address) || IsHostAddress(address);
            }
            catch
            {
                return false;
            }
        }

        private bool IsLocalAddress(IPAddress address)
        {
            if (address == null)
                return false;
            if (IPAddress.IsLoopback(address))
                return true;
            if (address.IsIPv4MappedToIPv6)
                return IPAddress.IsLoopback(address.MapToIPv4());
            return false;
        }

        private bool IsHostAddress(string ip)
        {
            if (string.IsNullOrWhiteSpace(ip))
                return false;
            try
            {
                if (!IPAddress.TryParse(NormalizeClientIp(ip), out IPAddress address))
                    return false;
                return IsLocalAddress(address) || IsHostAddress(address);
            }
            catch { }
            return false;
        }

        private bool IsHostAddress(IPAddress address)
        {
            if (address == null)
                return false;
            if (address.IsIPv4MappedToIPv6)
                address = address.MapToIPv4();
            foreach (IPAddress hostAddress in Dns.GetHostAddresses(Dns.GetHostName()))
            {
                if (AddressesEqual(address, hostAddress))
                    return true;
            }
            return false;
        }

        private bool AddressesEqual(IPAddress left, IPAddress right)
        {
            if (left == null || right == null)
                return false;
            if (left.IsIPv4MappedToIPv6)
                left = left.MapToIPv4();
            if (right.IsIPv4MappedToIPv6)
                right = right.MapToIPv4();
            return left.Equals(right);
        }

        private string GetChatSessionOwnerKey(NetworkConnection connection, HttpRequest request)
        {
            string ip = ExtractClientIp(connection, request);
            if (string.IsNullOrWhiteSpace(ip))
                ip = "unknown";

            if (!IsLocalAdmin(connection, request) &&
                TryAuthenticateWebAuthRequest(request, out WebAuthPrincipal principal, out _) &&
                !string.IsNullOrWhiteSpace(principal?.UserName))
            {
                LinkWebAuthUserToIp(principal.UserName, ip);
                return "webauth:" + principal.UserName.Trim().ToLowerInvariant();
            }

            return "ip:" + ip.Trim().ToLowerInvariant();
        }

        private string ExtractClientIp(NetworkConnection connection, HttpRequest request)
        {
            string headerIp =
                GetHeaderIp(request, "CF-Connecting-IP") ??
                GetHeaderIp(request, "X-Real-IP") ??
                GetFirstForwardedIp(request) ??
                GetForwardedHeaderIp(request);
            if (!string.IsNullOrWhiteSpace(headerIp))
                return NormalizeClientIp(headerIp);

            try
            {
                string endpointIp = connection?.EndPoint?.Address?.ToString();
                if (!string.IsNullOrWhiteSpace(endpointIp))
                    return NormalizeClientIp(endpointIp);
            }
            catch { }

            try
            {
                string endpoint = connection?.Socket?.RemoteEndPoint?.ToString();
                if (!string.IsNullOrWhiteSpace(endpoint))
                {
                    int colon = endpoint.LastIndexOf(':');
                    if (colon > 0)
                        endpoint = endpoint.Substring(0, colon);
                    return NormalizeClientIp(endpoint);
                }
            }
            catch { }

            return "unknown";
        }

        private string GetHeaderIp(HttpRequest request, string headerName)
        {
            if (request?.Headers == null || string.IsNullOrWhiteSpace(headerName))
                return null;

            return request.Headers.TryGetValue(headerName, out string value)
                ? NormalizeClientIp(value)
                : null;
        }

        private string GetFirstForwardedIp(HttpRequest request)
        {
            string forwardedFor = GetHeaderIp(request, "X-Forwarded-For");
            if (string.IsNullOrWhiteSpace(forwardedFor))
                return null;

            int comma = forwardedFor.IndexOf(',');
            return NormalizeClientIp(comma >= 0 ? forwardedFor.Substring(0, comma) : forwardedFor);
        }

        private string GetForwardedHeaderIp(HttpRequest request)
        {
            if (request?.Headers == null || !request.Headers.TryGetValue("Forwarded", out string forwarded))
                return null;

            foreach (string segment in (forwarded ?? "").Split(';', ','))
            {
                string trimmed = segment.Trim();
                if (!trimmed.StartsWith("for=", StringComparison.OrdinalIgnoreCase))
                    continue;

                return NormalizeClientIp(trimmed.Substring(4).Trim().Trim('"'));
            }

            return null;
        }

        private string NormalizeClientIp(string ip)
        {
            ip = (ip ?? "").Trim().Trim('"', '[', ']');
            if (string.IsNullOrWhiteSpace(ip))
                return null;

            int comma = ip.IndexOf(',');
            if (comma >= 0)
                ip = ip.Substring(0, comma).Trim();

            if (ip.StartsWith("::ffff:", StringComparison.OrdinalIgnoreCase))
                ip = ip.Substring(7);

            return ip;
        }

        private void AddWebAuthCorsHeaders(HttpRequest request)
        {
            try
            {
                var headers = request?.Context?.Response?.Headers;
                if (headers == null)
                    return;
                headers["Access-Control-Allow-Origin"] = "*";
                headers["Access-Control-Allow-Methods"] = "GET, POST, OPTIONS";
                headers["Access-Control-Allow-Headers"] = "Content-Type, Authorization, X-LmVsProxy-Auth";
                headers["Access-Control-Max-Age"] = "600";
            }
            catch { }
        }

        private void SetHttpStatus(HttpRequest request, int statusCode, string reasonPhrase)
        {
            if (request?.Context == null)
                return;
            request.Context.StatusCodeNumber = statusCode;
            request.Context.ReasonPhrase = string.IsNullOrWhiteSpace(reasonPhrase) ? "OK" : reasonPhrase;
        }

        private string BuildJsonError(HttpRequest request, int statusCode, string reasonPhrase, string error)
        {
            SetHttpStatus(request, statusCode, reasonPhrase);
            AddWebAuthCorsHeaders(request);
            return JsonSerializer.Serialize(new
            {
                ok = false,
                status = statusCode,
                error = error ?? reasonPhrase ?? "Request failed."
            });
        }

        private string BuildLocalAdminOnlyJsonError(HttpRequest request, string error)
        {
            return BuildJsonError(request, 403, "Forbidden",
                (string.IsNullOrWhiteSpace(error) ? "This administrative API is only available from the host machine." : error) +
                " Connect from localhost, 127.0.0.1, ::1, or this computer's host IP.");
        }

        private string BuildDatabaseAdminOnlyJsonError(HttpRequest request, string error)
        {
            return BuildJsonError(request, 403, "Forbidden",
                string.IsNullOrWhiteSpace(error)
                    ? "This administrative API requires a host-local connection or a WebAuth user marked as administrator in the database."
                    : error);
        }

        private bool IsDatabaseAdministrator(NetworkConnection connection, HttpRequest request)
        {
            return TryAuthorizeDatabaseAdministrator(connection, request, out _, out _);
        }

        private bool TryAuthorizeDatabaseAdministrator(NetworkConnection connection, HttpRequest request, out WebAuthPrincipal principal, out string error)
        {
            principal = null;
            if (IsLocalAdmin(connection, request))
            {
                principal = new WebAuthPrincipal
                {
                    UserName = "localhost",
                    AuthType = "Localhost",
                    ExpiresUtc = "",
                    IsAdministrator = true
                };
                error = "";
                return true;
            }

            if (!TryAuthenticateWebAuthRequest(request, out WebAuthPrincipal authenticated, out error))
                return false;

            if (!IsWebAuthAdministrator(authenticated.UserName))
            {
                error = "Remote Admin requires a host-local connection or a WebAuth user marked as administrator in the database.";
                return false;
            }

            authenticated.IsAdministrator = true;
            principal = authenticated;
            error = "";
            return true;
        }

        private bool IsWebAuthAdministrator(string username)
        {
            WebAuthRecord record = GetWebAuthRecord(username);
            return record != null && record.enabled && record.isAdministrator;
        }

        private bool TryAuthenticateWebAuthRequest(HttpRequest request, out WebAuthPrincipal principal, out string error)
        {
            principal = null;
            error = "Missing Authorization header. Use Bearer token from /api/web-auth/login or HTTP Basic credentials.";

            string authorization = null;
            if (request?.Headers != null)
                request.Headers.TryGetValue("Authorization", out authorization);

            if (!string.IsNullOrWhiteSpace(authorization) &&
                authorization.StartsWith("Bearer ", StringComparison.OrdinalIgnoreCase))
            {
                string token = authorization.Substring("Bearer ".Length).Trim();
                return TryValidateWebAuthToken(token, out principal, out error);
            }

            if (!string.IsNullOrWhiteSpace(authorization) &&
                authorization.StartsWith("Basic ", StringComparison.OrdinalIgnoreCase))
            {
                try
                {
                    string encoded = authorization.Substring("Basic ".Length).Trim();
                    string decoded = Encoding.UTF8.GetString(Convert.FromBase64String(encoded));
                    int separator = decoded.IndexOf(':');
                    if (separator <= 0)
                    {
                        error = "Invalid Basic Authorization header.";
                        return false;
                    }

                    string username = decoded.Substring(0, separator);
                    string password = decoded.Substring(separator + 1);
                    if (!TryValidateWebAuthCredentials(username, password, out WebAuthRecord record, out error))
                        return false;

                    principal = new WebAuthPrincipal
                    {
                        UserName = record.userName,
                        AuthType = "Basic",
                        ExpiresUtc = "",
                        IsAdministrator = record.isAdministrator
                    };
                    return true;
                }
                catch
                {
                    error = "Invalid Basic Authorization header.";
                    return false;
                }
            }

            string headerToken = null;
            if (request?.Headers != null)
                request.Headers.TryGetValue("X-LmVsProxy-Auth", out headerToken);
            if (!string.IsNullOrWhiteSpace(headerToken))
                return TryValidateWebAuthToken(headerToken.Trim(), out principal, out error);

            string cookieToken = GetCookieValue(request, "LmVsProxyAuth");
            if (!string.IsNullOrWhiteSpace(cookieToken))
                return TryValidateWebAuthToken(cookieToken.Trim(), out principal, out error);

            return false;
        }

        private string GetCookieValue(HttpRequest request, string name)
        {
            if (request?.Headers == null || string.IsNullOrWhiteSpace(name))
                return null;
            if (!request.Headers.TryGetValue("Cookie", out string cookieHeader) || string.IsNullOrWhiteSpace(cookieHeader))
                return null;

            foreach (string part in cookieHeader.Split(';'))
            {
                string trimmed = part.Trim();
                int separator = trimmed.IndexOf('=');
                if (separator <= 0)
                    continue;
                string key = trimmed.Substring(0, separator).Trim();
                if (string.Equals(key, name, StringComparison.OrdinalIgnoreCase))
                    return WebUtility.UrlDecode(trimmed.Substring(separator + 1).Trim());
            }
            return null;
        }

        private bool TryValidateWebAuthToken(string token, out WebAuthPrincipal principal, out string error)
        {
            principal = null;
            error = "Invalid or expired auth token.";
            if (string.IsNullOrWhiteSpace(token))
                return false;

            string tokenHash = HashWebAuthToken(token);
            lock (_chatSessionLock)
            {
                var table = GetWebAuthTable();
                for (int i = 0; i < table.Rows.Count; i++)
                {
                    object[] row = NormalizeWebAuthRow(table.Rows[i]);
                    table.Rows[i] = row;
                    WebAuthRecord record = WebAuthRecordFromRow(row);
                    if (!record.enabled)
                        continue;
                    if (string.IsNullOrWhiteSpace(record.tokenHash) ||
                        !ConstantTimeEquals(record.tokenHash, tokenHash))
                        continue;

                    if (!DateTimeOffset.TryParse(record.tokenExpiresUtc, out DateTimeOffset expires) ||
                        expires <= DateTimeOffset.UtcNow)
                    {
                        row[6] = "";
                        row[7] = "";
                        _chatSessionData.Save();
                        error = "Auth token expired. Log in again.";
                        return false;
                    }

                    principal = new WebAuthPrincipal
                    {
                        UserName = record.userName,
                        AuthType = "Bearer",
                        ExpiresUtc = record.tokenExpiresUtc,
                        IsAdministrator = record.isAdministrator
                    };
                    return true;
                }
            }

            return false;
        }

        private bool TryValidateWebAuthCredentials(string username, string password, out WebAuthRecord record, out string error)
        {
            record = null;
            error = "Invalid username or password.";
            if (!TryNormalizeWebAuthUserName(username, out string normalizedUserName, out _))
                return false;
            if (string.IsNullOrEmpty(password))
                return false;

            lock (_chatSessionLock)
            {
                var table = GetWebAuthTable();
                for (int i = 0; i < table.Rows.Count; i++)
                {
                    object[] row = NormalizeWebAuthRow(table.Rows[i]);
                    table.Rows[i] = row;
                    WebAuthRecord candidate = WebAuthRecordFromRow(row);
                    if (!string.Equals(candidate.userName, normalizedUserName, StringComparison.OrdinalIgnoreCase))
                        continue;
                    if (!candidate.enabled)
                    {
                        error = "WebAuth user is disabled.";
                        return false;
                    }
                    if (!VerifyWebAuthPassword(password, candidate.passwordSalt, candidate.passwordHash))
                        return false;

                    record = candidate;
                    return true;
                }
            }

            return false;
        }

        private bool TryNormalizeWebAuthUserName(string username, out string normalized, out string error)
        {
            normalized = (username ?? "").Trim();
            error = null;
            if (normalized.Length < 3 || normalized.Length > 80)
            {
                error = "Username must be between 3 and 80 characters.";
                return false;
            }

            foreach (char ch in normalized)
            {
                if (!(char.IsLetterOrDigit(ch) || ch == '_' || ch == '-' || ch == '.' || ch == '@'))
                {
                    error = "Username can only contain letters, numbers, underscore, dash, dot, or @.";
                    return false;
                }
            }

            return true;
        }

        private bool IsValidWebAuthPassword(string password, out string error)
        {
            error = null;
            if (string.IsNullOrEmpty(password) || password.Length < 8)
            {
                error = "Password must be at least 8 characters.";
                return false;
            }

            return true;
        }

        private WebAuthRecord CreateWebAuthRecord(string username, string password)
        {
            byte[] salt = GenerateRandomBytes(16);
            string now = DateTimeOffset.UtcNow.ToString("O");
            return new WebAuthRecord
            {
                userName = username,
                passwordSalt = Convert.ToBase64String(salt),
                passwordHash = HashWebAuthPassword(password, salt),
                createdUtc = now,
                updatedUtc = now,
                lastLoginUtc = "",
                tokenHash = "",
                tokenExpiresUtc = "",
                enabled = true,
                lastClientIp = ""
            };
        }

        private bool SaveWebAuthRecord(WebAuthRecord record, bool overwrite)
        {
            lock (_chatSessionLock)
            {
                var table = GetWebAuthTable();
                for (int i = 0; i < table.Rows.Count; i++)
                {
                    object[] row = NormalizeWebAuthRow(table.Rows[i]);
                    table.Rows[i] = row;
                    if (!string.Equals(GetRowValue(row, 0), record.userName, StringComparison.OrdinalIgnoreCase))
                        continue;

                    if (!overwrite)
                        return false;

                    record.createdUtc = string.IsNullOrWhiteSpace(GetRowValue(row, 3))
                        ? record.createdUtc
                        : GetRowValue(row, 3);
                    table.Rows[i] = WebAuthRecordToRow(record);
                    _chatSessionData.Save();
                    return false;
                }

                table.Rows.Add(WebAuthRecordToRow(record));
                _chatSessionData.Save();
                return true;
            }
        }

        private void UpsertWebAuthRecord(WebAuthRecord record)
        {
            lock (_chatSessionLock)
            {
                var table = GetWebAuthTable();
                for (int i = 0; i < table.Rows.Count; i++)
                {
                    object[] row = NormalizeWebAuthRow(table.Rows[i]);
                    if (string.Equals(GetRowValue(row, 0), record.userName, StringComparison.OrdinalIgnoreCase))
                    {
                        table.Rows[i] = WebAuthRecordToRow(record);
                        _chatSessionData.Save();
                        return;
                    }
                }

                table.Rows.Add(WebAuthRecordToRow(record));
                _chatSessionData.Save();
            }
        }

        private void ClearWebAuthToken(string username)
        {
            if (!TryNormalizeWebAuthUserName(username, out string normalizedUserName, out _))
                return;

            lock (_chatSessionLock)
            {
                var table = GetWebAuthTable();
                for (int i = 0; i < table.Rows.Count; i++)
                {
                    object[] row = NormalizeWebAuthRow(table.Rows[i]);
                    if (!string.Equals(GetRowValue(row, 0), normalizedUserName, StringComparison.OrdinalIgnoreCase))
                        continue;
                    row[6] = "";
                    row[7] = "";
                    row[4] = DateTimeOffset.UtcNow.ToString("O");
                    table.Rows[i] = row;
                    _chatSessionData.Save();
                    return;
                }
            }
        }

        private WebAuthRecord GetWebAuthRecord(string username)
        {
            if (!TryNormalizeWebAuthUserName(username, out string normalizedUserName, out _))
                return null;

            lock (_chatSessionLock)
            {
                var table = GetWebAuthTable();
                for (int i = 0; i < table.Rows.Count; i++)
                {
                    object[] row = NormalizeWebAuthRow(table.Rows[i]);
                    table.Rows[i] = row;
                    WebAuthRecord record = WebAuthRecordFromRow(row);
                    if (string.Equals(record.userName, normalizedUserName, StringComparison.OrdinalIgnoreCase))
                        return record;
                }
            }

            return null;
        }

        private bool HasAnyWebAuthAdministrator()
        {
            lock (_chatSessionLock)
            {
                var table = GetWebAuthTable();
                for (int i = 0; i < table.Rows.Count; i++)
                {
                    object[] row = NormalizeWebAuthRow(table.Rows[i]);
                    table.Rows[i] = row;
                    WebAuthRecord record = WebAuthRecordFromRow(row);
                    if (record.enabled && record.isAdministrator)
                        return true;
                }
            }

            return false;
        }

        private void SetWebAuthCookie(HttpRequest request, string token, DateTimeOffset expires)
        {
            try
            {
                var headers = request?.Context?.Response?.Headers;
                if (headers == null || string.IsNullOrWhiteSpace(token))
                    return;
                int maxAge = Math.Max(1, (int)Math.Round((expires - DateTimeOffset.UtcNow).TotalSeconds));
                headers["Set-Cookie"] = WebAuthCookieName + "=" + WebUtility.UrlEncode(token) +
                                        "; Path=/; Max-Age=" + maxAge.ToString(CultureInfo.InvariantCulture) +
                                        "; SameSite=Lax; HttpOnly";
            }
            catch { }
        }

        private void ClearWebAuthCookie(HttpRequest request)
        {
            try
            {
                var headers = request?.Context?.Response?.Headers;
                if (headers == null)
                    return;
                headers["Set-Cookie"] = WebAuthCookieName + "=; Path=/; Max-Age=0; SameSite=Lax; HttpOnly";
            }
            catch { }
        }

        private string HashWebAuthPassword(string password, byte[] salt)
        {
            using (var derive = new Rfc2898DeriveBytes(password ?? "", salt, WebAuthPasswordHashIterations, HashAlgorithmName.SHA256))
            {
                return Convert.ToBase64String(derive.GetBytes(32));
            }
        }

        private bool VerifyWebAuthPassword(string password, string saltBase64, string expectedHash)
        {
            try
            {
                byte[] salt = Convert.FromBase64String(saltBase64 ?? "");
                string actualHash = HashWebAuthPassword(password, salt);
                return ConstantTimeEquals(actualHash, expectedHash);
            }
            catch
            {
                return false;
            }
        }

        private string GenerateWebAuthToken()
        {
            return Base64UrlEncode(GenerateRandomBytes(32));
        }

        private string HashWebAuthToken(string token)
        {
            using (var sha = SHA256.Create())
            {
                return Convert.ToBase64String(sha.ComputeHash(Encoding.UTF8.GetBytes(token ?? "")));
            }
        }

        private byte[] GenerateRandomBytes(int count)
        {
            byte[] bytes = new byte[Math.Max(1, count)];
            using (var rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(bytes);
            }
            return bytes;
        }

        private string Base64UrlEncode(byte[] bytes)
        {
            return Convert.ToBase64String(bytes ?? new byte[0]).TrimEnd('=').Replace('+', '-').Replace('/', '_');
        }

        private bool ConstantTimeEquals(string leftBase64, string rightBase64)
        {
            if (string.IsNullOrEmpty(leftBase64) || string.IsNullOrEmpty(rightBase64))
                return false;
            byte[] left;
            byte[] right;
            try
            {
                left = Convert.FromBase64String(leftBase64);
                right = Convert.FromBase64String(rightBase64);
            }
            catch
            {
                return false;
            }

            int diff = left.Length ^ right.Length;
            int max = Math.Max(left.Length, right.Length);
            for (int i = 0; i < max; i++)
            {
                byte l = i < left.Length ? left[i] : (byte)0;
                byte r = i < right.Length ? right[i] : (byte)0;
                diff |= l ^ r;
            }
            return diff == 0;
        }

