        private object[] NormalizeChatSessionRow(object[] row)
        {
            var normalized = new object[8];
            if (row != null)
            {
                int copy = Math.Min(row.Length, normalized.Length);
                for (int i = 0; i < copy; i++)
                    normalized[i] = row[i];
            }

            string now = DateTimeOffset.UtcNow.ToString("O");
            if (string.IsNullOrWhiteSpace(normalized[0]?.ToString()))
                normalized[0] = "sess_" + Guid.NewGuid().ToString("N");
            if (string.IsNullOrWhiteSpace(normalized[1]?.ToString()))
                normalized[1] = "New chat";
            if (string.IsNullOrWhiteSpace(normalized[2]?.ToString()))
                normalized[2] = now;
            if (string.IsNullOrWhiteSpace(normalized[3]?.ToString()))
                normalized[3] = normalized[2];
            if (normalized[4] == null)
                normalized[4] = "";
            if (string.IsNullOrWhiteSpace(normalized[5]?.ToString()))
                normalized[5] = "[]";
            if (string.IsNullOrWhiteSpace(normalized[6]?.ToString()))
                normalized[6] = "[]";
            if (string.IsNullOrWhiteSpace(normalized[7]?.ToString()))
                normalized[7] = "legacy";
            return normalized;
        }

        private static int CountJsonArrayItems(string json)
        {
            try
            {
                using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(json) ? "[]" : json))
                {
                    return document.RootElement.ValueKind == JsonValueKind.Array
                        ? document.RootElement.GetArrayLength()
                        : 0;
                }
            }
            catch
            {
                return 0;
            }
        }

        private object[] NormalizeChatPermissionRow(object[] row)
        {
            object[] normalized = CreateDefaultChatPermissionRow();
            if (row != null)
            {
                int copy = Math.Min(row.Length, normalized.Length);
                for (int i = 0; i < copy; i++)
                {
                    if (row[i] != null)
                        normalized[i] = row[i];
                }
            }

            if (string.IsNullOrWhiteSpace(normalized[0]?.ToString()))
                normalized[0] = "global";
            if (string.IsNullOrWhiteSpace(normalized[4]?.ToString()))
                normalized[4] = DateTimeOffset.UtcNow.ToString("O");

            normalized[1] = ParseStoredBool(normalized[1]?.ToString(), false) ? "true" : "false";
            normalized[2] = ParseStoredBool(normalized[2]?.ToString(), true) ? "true" : "false";
            normalized[3] = ParseStoredBool(normalized[3]?.ToString(), false) ? "true" : "false";
            normalized[5] = ParseStoredBool(normalized[5]?.ToString(), false) ? "true" : "false";
            normalized[6] = ParseStoredBool(normalized[6]?.ToString(), false) ? "true" : "false";
            if (normalized[7] == null)
                normalized[7] = "";
            if (normalized[8] == null)
                normalized[8] = "";
            normalized[9] = ParseStoredBool(normalized[9]?.ToString(), false) ? "true" : "false";
            normalized[10] = ParseStoredBool(normalized[10]?.ToString(), false) ? "true" : "false";
            normalized[11] = ParseStoredBool(normalized[11]?.ToString(), true) ? "true" : "false";
            normalized[12] = ParseStoredBool(normalized[12]?.ToString(), true) ? "true" : "false";
