            {
                userName = GetRowValue(row, 0),
                passwordSalt = GetRowValue(row, 1),
                passwordHash = GetRowValue(row, 2),
                createdUtc = GetRowValue(row, 3),
                updatedUtc = GetRowValue(row, 4),
                lastLoginUtc = GetRowValue(row, 5),
                tokenHash = GetRowValue(row, 6),
                tokenExpiresUtc = GetRowValue(row, 7),
                enabled = ParseStoredBool(GetRowValue(row, 8), true),
                lastClientIp = GetRowValue(row, 9),
                tokenLimit = Math.Max(0, ParseStoredLong(GetRowValue(row, 10), 0)),
                tokensUsed = Math.Max(0, ParseStoredLong(GetRowValue(row, 11), 0)),
                isAdministrator = ParseStoredBool(GetRowValue(row, 12), false)
            };
        }

        private object[] WebAuthRecordToRow(WebAuthRecord record)
        {
            record = record ?? new WebAuthRecord();
            return NormalizeWebAuthRow(new object[] {
                record.userName ?? "",
                record.passwordSalt ?? "",
                record.passwordHash ?? "",
                record.createdUtc ?? "",
                record.updatedUtc ?? "",
                record.lastLoginUtc ?? "",
                record.tokenHash ?? "",
                record.tokenExpiresUtc ?? "",
                record.enabled ? "true" : "false",
                record.lastClientIp ?? "",
                Math.Max(0, record.tokenLimit).ToString(CultureInfo.InvariantCulture),
                Math.Max(0, record.tokensUsed).ToString(CultureInfo.InvariantCulture),
                record.isAdministrator ? "true" : "false"
            });
        }

        private void LinkWebAuthUserToIp(string username, string clientIp)
        {
            if (!TryNormalizeWebAuthUserName(username, out string normalizedUserName, out _) ||
                string.IsNullOrWhiteSpace(clientIp))
                return;

            clientIp = NormalizeClientIp(clientIp);
            lock (_chatSessionLock)
            {
                var table = GetWebAuthIpLinksTable();
                string now = DateTimeOffset.UtcNow.ToString("O");
                for (int i = 0; i < table.Rows.Count; i++)
                {
                    object[] row = NormalizeWebAuthIpLinkRow(table.Rows[i]);
                    if (string.Equals(GetRowValue(row, 0), normalizedUserName, StringComparison.OrdinalIgnoreCase) &&
                        string.Equals(GetRowValue(row, 1), clientIp, StringComparison.OrdinalIgnoreCase))
                    {
                        row[2] = now;
                        table.Rows[i] = row;
                        _chatSessionData.Save();
                        return;
                    }
                }

                table.Rows.Add(new object[] { normalizedUserName, clientIp, now });
                _chatSessionData.Save();
            }
        }

