        private WebAuthRegistrationRequestRecord SaveWebAuthRegistrationRequest(string username, string password, string clientIp)
        {
            byte[] salt = GenerateRandomBytes(16);
            string now = DateTimeOffset.UtcNow.ToString("O");
            string passwordSalt = Convert.ToBase64String(salt);
            string passwordHash = HashWebAuthPassword(password, salt);
            clientIp = string.IsNullOrWhiteSpace(clientIp) ? "" : NormalizeClientIp(clientIp);

            lock (_chatSessionLock)
            {
                var table = GetWebAuthRegistrationRequestsTable();
                for (int i = 0; i < table.Rows.Count; i++)
                {
                    WebAuthRegistrationRequestRecord existing = WebAuthRegistrationRequestRecordFromRow(table.Rows[i]);
                    if (!existing.status.Equals("pending", StringComparison.OrdinalIgnoreCase) ||
                        !string.Equals(existing.userName, username, StringComparison.OrdinalIgnoreCase))
                        continue;

                    existing.passwordSalt = passwordSalt;
                    existing.passwordHash = passwordHash;
                    existing.clientIp = clientIp;
                    existing.requestedUtc = now;
                    existing.note = "Updated pending request.";
                    table.Rows[i] = WebAuthRegistrationRequestRecordToRow(existing);
                    _chatSessionData.Save();
                    return existing;
                }

                var record = new WebAuthRegistrationRequestRecord
                {
                    id = "regreq_" + Guid.NewGuid().ToString("N"),
                    userName = username,
                    passwordSalt = passwordSalt,
                    passwordHash = passwordHash,
                    clientIp = clientIp,
                    status = "pending",
                    requestedUtc = now,
                    decidedUtc = "",
                    decidedBy = "",
                    note = ""
                };
                table.Rows.Add(WebAuthRegistrationRequestRecordToRow(record));
                _chatSessionData.Save();
                return record;
            }
        }

        private WebAuthRegistrationRequestRecord DecideWebAuthRegistrationRequest(string requestId, bool approved, string decidedBy, string note)
        {
            if (string.IsNullOrWhiteSpace(requestId))
                throw new InvalidOperationException("Registration request id is required.");

            lock (_chatSessionLock)
            {
                var requestTable = GetWebAuthRegistrationRequestsTable();
                for (int i = 0; i < requestTable.Rows.Count; i++)
                {
                    WebAuthRegistrationRequestRecord request = WebAuthRegistrationRequestRecordFromRow(requestTable.Rows[i]);
                    if (!string.Equals(request.id, requestId, StringComparison.OrdinalIgnoreCase))
                        continue;
                    if (!request.status.Equals("pending", StringComparison.OrdinalIgnoreCase))
                        throw new InvalidOperationException("Registration request has already been decided.");

                    if (approved)
                    {
                        if (GetWebAuthRecord(request.userName) != null)
                            throw new InvalidOperationException("A WebAuth user with that name already exists.");

                        string now = DateTimeOffset.UtcNow.ToString("O");
                        var user = new WebAuthRecord
                        {
                            userName = request.userName,
                            passwordSalt = request.passwordSalt,
                            passwordHash = request.passwordHash,
                            createdUtc = now,
                            updatedUtc = now,
                            lastLoginUtc = "",
                            tokenHash = "",
                            tokenExpiresUtc = "",
                            enabled = true,
                            lastClientIp = request.clientIp,
                            tokenLimit = 0,
                            tokensUsed = 0
                        };
                        SaveWebAuthRecord(user, overwrite: false);
                        LinkWebAuthUserToIp(user.userName, request.clientIp);
                    }

                    request.status = approved ? "approved" : "denied";
                    request.decidedUtc = DateTimeOffset.UtcNow.ToString("O");
                    request.decidedBy = string.IsNullOrWhiteSpace(decidedBy) ? "admin" : decidedBy;
                    request.note = note ?? "";
                    requestTable.Rows[i] = WebAuthRegistrationRequestRecordToRow(request);
                    _chatSessionData.Save();
                    return request;
                }
            }

            throw new InvalidOperationException("Registration request was not found or is no longer pending.");
        }

        private void EnsureDefaultChatCostSettings(SocketJack.Net.Database.Table table)
        {
            if (table == null)
                return;

            bool changed = false;
            changed |= EnsureChatCostSetting(table, "tokenUsdPerToken", "0");
            changed |= EnsureChatCostSetting(table, "electricityCentsPerKwh", DefaultElectricityCentsPerKwh.ToString("0.####", CultureInfo.InvariantCulture));
            changed |= EnsureChatCostSetting(table, "electricityMultiplier", "1");
            changed |= EnsureChatCostSetting(table, "gpuTdpWatts", "0");
            changed |= EnsureChatCostSetting(table, "serviceTaxRate", DefaultServiceTaxRate.ToString("0.####", CultureInfo.InvariantCulture));
            changed |= EnsureChatCostSetting(table, "storageType", DefaultStorageType);
            changed |= EnsureChatCostSetting(table, "storageCostFactor", "0");
            changed |= EnsureChatCostSetting(table, "storageLimitBytes", DefaultStorageLimitBytes.ToString(CultureInfo.InvariantCulture));
            changed |= EnsureChatCostSetting(table, "allowOpenRegistration", "false");
            if (changed)
                _chatSessionData.Save();
        }

        private bool EnsureChatCostSetting(SocketJack.Net.Database.Table table, string key, string value)
        {
            if (table?.Rows == null || string.IsNullOrWhiteSpace(key))
                return false;

            for (int i = 0; i < table.Rows.Count; i++)
            {
                object[] row = NormalizeChatCostSettingRow(table.Rows[i]);
                table.Rows[i] = row;
                if (string.Equals(GetRowValue(row, 0), key, StringComparison.OrdinalIgnoreCase))
                    return false;
            }

            table.Rows.Add(new object[] { key, value ?? "", DateTimeOffset.UtcNow.ToString("O") });
            return true;
        }

        private ChatCostSettings GetChatCostSettings()
        {
            lock (_chatSessionLock)
            {
                var table = GetChatCostsTable();
                ChatCostSettings settings = new ChatCostSettings
                {
                    tokenUsdPerToken = ReadChatCostSetting(table, "tokenUsdPerToken", 0),
                    electricityCentsPerKwh = ReadChatCostSetting(table, "electricityCentsPerKwh", DefaultElectricityCentsPerKwh),
                    electricityMultiplier = ReadChatCostSetting(table, "electricityMultiplier", 1),
                    gpuTdpWatts = ReadChatCostSetting(table, "gpuTdpWatts", 0),
                    cpuTdpWatts = ReadChatCostSetting(table, "cpuTdpWatts", DefaultCpuTdpWatts),
                    ramWattsPerGb = ReadChatCostSetting(table, "ramWattsPerGb", DefaultRamWattsPerGb),
                    systemWatts = ReadChatCostSetting(table, "systemWatts", DefaultSystemWatts),
                    ioWattsPerGbps = ReadChatCostSetting(table, "ioWattsPerGbps", DefaultIoWattsPerGbps),
                    serviceTaxRate = ReadChatCostSetting(table, "serviceTaxRate", DefaultServiceTaxRate),
                    storageType = ReadChatCostSettingText(table, "storageType", DefaultStorageType),
                    storageCostFactor = ReadChatCostSetting(table, "storageCostFactor", 0),
                    storageLimitBytes = Math.Max(0, ParseStoredLong(ReadChatCostSettingRaw(table, "storageLimitBytes", DefaultStorageLimitBytes.ToString(CultureInfo.InvariantCulture)), DefaultStorageLimitBytes)),
                    allowOpenRegistration = ReadChatCostSettingBool(table, "allowOpenRegistration", false),
                    table = WebAuthDatabaseName + "." + ChatCostsTableName
                };

                settings.tokenUsdPerToken = NormalizeCostNumber(settings.tokenUsdPerToken);
                settings.electricityCentsPerKwh = NormalizeCostNumber(settings.electricityCentsPerKwh);
                settings.electricityMultiplier = NormalizeCostNumber(settings.electricityMultiplier);
                settings.gpuTdpWatts = NormalizeCostNumber(settings.gpuTdpWatts);
                settings.cpuTdpWatts = NormalizeCostNumber(settings.cpuTdpWatts);
                settings.ramWattsPerGb = NormalizeCostNumber(settings.ramWattsPerGb);
                settings.systemWatts = NormalizeCostNumber(settings.systemWatts);
                settings.ioWattsPerGbps = NormalizeCostNumber(settings.ioWattsPerGbps);
                settings.serviceTaxRate = NormalizeCostNumber(settings.serviceTaxRate);
                settings.gpuTdpWatts = GetEffectiveGpuTdpWatts(settings.gpuTdpWatts);
                if (settings.cpuTdpWatts <= 0)
                    settings.cpuTdpWatts = DefaultCpuTdpWatts;
                if (settings.ramWattsPerGb <= 0)
                    settings.ramWattsPerGb = DefaultRamWattsPerGb;
                if (settings.systemWatts <= 0)
                    settings.systemWatts = DefaultSystemWatts;
                if (settings.ioWattsPerGbps <= 0)
                    settings.ioWattsPerGbps = DefaultIoWattsPerGbps;
                settings.storageType = NormalizeStorageType(settings.storageType);
                settings.storageCostFactor = ClampStorageCostFactor(settings.storageCostFactor);
                if (settings.storageLimitBytes <= 0)
                    settings.storageLimitBytes = DefaultStorageLimitBytes;
                return settings;
            }
        }

        private void SaveChatCostSettings(ChatCostSettings settings)
        {
            settings = settings ?? new ChatCostSettings();
            lock (_chatSessionLock)
            {
                var table = GetChatCostsTable();
                UpsertChatCostSetting(table, "tokenUsdPerToken", settings.tokenUsdPerToken);
                UpsertChatCostSetting(table, "electricityCentsPerKwh", settings.electricityCentsPerKwh);
                UpsertChatCostSetting(table, "electricityMultiplier", settings.electricityMultiplier);
                UpsertChatCostSetting(table, "gpuTdpWatts", settings.gpuTdpWatts);
                UpsertChatCostSetting(table, "cpuTdpWatts", settings.cpuTdpWatts);
                UpsertChatCostSetting(table, "ramWattsPerGb", settings.ramWattsPerGb);
                UpsertChatCostSetting(table, "systemWatts", settings.systemWatts);
                UpsertChatCostSetting(table, "ioWattsPerGbps", settings.ioWattsPerGbps);
                UpsertChatCostSetting(table, "serviceTaxRate", settings.serviceTaxRate);
                UpsertChatCostSetting(table, "storageType", NormalizeStorageType(settings.storageType));
                UpsertChatCostSetting(table, "storageCostFactor", ClampStorageCostFactor(settings.storageCostFactor));
                UpsertChatCostSetting(table, "storageLimitBytes", Math.Max(0, settings.storageLimitBytes).ToString(CultureInfo.InvariantCulture));
                UpsertChatCostSetting(table, "allowOpenRegistration", settings.allowOpenRegistration ? "true" : "false");
                _chatSessionData.Save();
            }
        }

        private double ReadChatCostSetting(SocketJack.Net.Database.Table table, string key, double fallback)
        {
            return ParseStoredDouble(ReadChatCostSettingRaw(table, key, fallback.ToString(CultureInfo.InvariantCulture)), fallback);
        }

        private bool ReadChatCostSettingBool(SocketJack.Net.Database.Table table, string key, bool fallback)
        {
            return ParseStoredBool(ReadChatCostSettingRaw(table, key, fallback ? "true" : "false"), fallback);
        }

        private string ReadChatCostSettingText(SocketJack.Net.Database.Table table, string key, string fallback)
        {
            return ReadChatCostSettingRaw(table, key, fallback);
        }

        private string ReadChatCostSettingRaw(SocketJack.Net.Database.Table table, string key, string fallback)
        {
            if (table?.Rows == null || string.IsNullOrWhiteSpace(key))
                return fallback;

            foreach (object[] sourceRow in table.Rows)
            {
                object[] row = NormalizeChatCostSettingRow(sourceRow);
                if (string.Equals(GetRowValue(row, 0), key, StringComparison.OrdinalIgnoreCase))
                    return GetRowValue(row, 1);
            }

            return fallback;
        }

        private void UpsertChatCostSetting(SocketJack.Net.Database.Table table, string key, double value)
        {
            if (table?.Rows == null || string.IsNullOrWhiteSpace(key))
                return;

            string now = DateTimeOffset.UtcNow.ToString("O");
            string stored = NormalizeCostNumber(value).ToString("0.########", CultureInfo.InvariantCulture);
            for (int i = 0; i < table.Rows.Count; i++)
            {
                object[] row = NormalizeChatCostSettingRow(table.Rows[i]);
                if (!string.Equals(GetRowValue(row, 0), key, StringComparison.OrdinalIgnoreCase))
                    continue;

                row[1] = stored;
                row[2] = now;
                table.Rows[i] = row;
                return;
            }

            table.Rows.Add(new object[] { key, stored, now });
        }

        private void UpsertChatCostSetting(SocketJack.Net.Database.Table table, string key, string value)
        {
            if (table?.Rows == null || string.IsNullOrWhiteSpace(key))
                return;

            string now = DateTimeOffset.UtcNow.ToString("O");
            string stored = value ?? "";
            for (int i = 0; i < table.Rows.Count; i++)
            {
                object[] row = NormalizeChatCostSettingRow(table.Rows[i]);
                if (!string.Equals(GetRowValue(row, 0), key, StringComparison.OrdinalIgnoreCase))
                    continue;

                row[1] = stored;
                row[2] = now;
                table.Rows[i] = row;
                return;
            }

            table.Rows.Add(new object[] { key, stored, now });
        }

        private ChatCostTotals GetChatCostTotals(string ownerKey)
        {
            ownerKey = NormalizeCostOwnerKey(ownerKey);
            var totals = new ChatCostTotals { ownerKey = ownerKey };
            if (string.IsNullOrWhiteSpace(ownerKey))
                return totals;

            lock (_chatSessionLock)
            {
                var table = GetChatUserCostsTable();
                foreach (object[] sourceRow in table.Rows)
                {
                    object[] row = NormalizeChatUserCostRow(sourceRow);
                    if (!string.Equals(GetRowValue(row, 0), ownerKey, StringComparison.OrdinalIgnoreCase))
                        continue;

                    totals.gpuSecondsUsed = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 1), 0));
                    totals.tokenCostUsd = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 2), 0));
                    totals.electricityCostUsd = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 3), 0));
                    totals.serviceTaxCostUsd = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 4), 0));
                    totals.tokensUsed = Math.Max(0, ParseStoredLong(GetRowValue(row, 6), 0));
                    totals.cpuComputeSecondsUsed = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 7), 0));
                    totals.ramGbSecondsUsed = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 8), 0));
                    totals.systemSecondsUsed = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 9), 0));
                    totals.ioBytesProcessed = Math.Max(0, ParseStoredLong(GetRowValue(row, 10), 0));
                    totals.gpuElectricityCostUsd = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 11), 0));
                    totals.cpuElectricityCostUsd = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 12), 0));
                    totals.ramElectricityCostUsd = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 13), 0));
                    totals.systemElectricityCostUsd = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 14), 0));
                    totals.ioElectricityCostUsd = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 15), 0));
                    if (totals.gpuElectricityCostUsd + totals.cpuElectricityCostUsd + totals.ramElectricityCostUsd + totals.systemElectricityCostUsd + totals.ioElectricityCostUsd <= 0)
                        totals.gpuElectricityCostUsd = totals.electricityCostUsd;
                    totals.totalCostUsd = NormalizeCostNumber(totals.tokenCostUsd + totals.electricityCostUsd + totals.serviceTaxCostUsd);
                    return totals;
                }
            }

            return totals;
        }

        private long GetChatStorageUsageBytes(string ownerKey)
        {
            ownerKey = NormalizeCostOwnerKey(ownerKey);
            if (string.IsNullOrWhiteSpace(ownerKey))
                return 0;

            long total = 0;
            var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            List<string> ownerKeys = GetEquivalentFilesystemOwnerKeys(ownerKey);
            lock (_chatSessionLock)
            {
                var table = GetChatSessionsTable();
                foreach (object[] sourceRow in table.Rows)
                {
                    object[] row = NormalizeChatSessionRow(sourceRow);
                    if (!OwnerKeyListContains(ownerKeys, NormalizeCostOwnerKey(GetRowValue(row, 7))))
                        continue;

                    AddStorageUsageBytes(ref total, EstimateChatSessionRowStorageBytes(row));
                    AddChatStorageUsageFromFilesJson(GetRowValue(row, 6), seen, ref total);
                }
            }

            return Math.Max(0, total);
        }

        private long EstimateChatSessionRowStorageBytes(object[] row)
        {
            if (row == null)
                return 0;

            try
            {
                return Encoding.UTF8.GetByteCount(JsonSerializer.Serialize(row));
            }
            catch
            {
                long total = 0;
                foreach (object value in row)
                {
                    if (value == null)
                        continue;
                    AddStorageUsageBytes(ref total, Encoding.UTF8.GetByteCount(value.ToString() ?? ""));
                }

                return total;
            }
        }

        private void AddStorageUsageBytes(ref long total, long bytes)
        {
            if (bytes <= 0)
                return;

            if (total > long.MaxValue - bytes)
            {
                total = long.MaxValue;
                return;
            }

            total += bytes;
        }

        private void AddChatStorageUsageFromFilesJson(string filesJson, HashSet<string> seen, ref long total)
        {
            if (string.IsNullOrWhiteSpace(filesJson) || seen == null)
                return;

            try
            {
                using (JsonDocument document = JsonDocument.Parse(filesJson))
                {
                    if (document.RootElement.ValueKind != JsonValueKind.Array)
                        return;

                    foreach (JsonElement element in document.RootElement.EnumerateArray())
                    {
                        ChatSessionFile file = ReadChatSessionFile(element);
                        if (file == null || string.IsNullOrWhiteSpace(file.path))
                            continue;

                        string fullPath;
                        try
                        {
                            fullPath = Path.GetFullPath(file.path);
                        }
                        catch
                        {
                            continue;
                        }

                        if (!seen.Add(fullPath) || !File.Exists(fullPath) || !IsPathInsideRoot(fullPath, _chatSessionFilesRoot))
                            continue;

                        try
                        {
                            AddStorageUsageBytes(ref total, Math.Max(0, new FileInfo(fullPath).Length));
                        }
                        catch { }
                    }
                }
            }
            catch { }
        }

        private bool EnsureChatStorageCanAdd(string ownerKey, long bytesToAdd, out ChatUsageSnapshot snapshot, out string error)
        {
            snapshot = GetChatUsageSnapshot(ownerKey);
            error = null;
            if (snapshot.storageUnlimited)
                return true;

            long requested = Math.Max(0, bytesToAdd);
            if (snapshot.storageBytesRemaining < requested)
            {
                error = "Storage limit reached. Free space or buy more storage before saving this file.";
                return false;
            }

            return true;
        }

        private ChatCostTotals ApplyChatUsageCosts(string ownerKey, int tokenDelta, double gpuSecondsDelta, ChatResourceUsageDelta resourceDelta = null)
        {
            ownerKey = NormalizeCostOwnerKey(ownerKey);
            if (string.IsNullOrWhiteSpace(ownerKey))
                return GetChatCostTotals(ownerKey);

            tokenDelta = Math.Max(0, tokenDelta);
            gpuSecondsDelta = NormalizeCostNumber(gpuSecondsDelta);
            resourceDelta = resourceDelta ?? new ChatResourceUsageDelta { gpuSeconds = gpuSecondsDelta };
            resourceDelta.gpuSeconds = Math.Max(resourceDelta.gpuSeconds, gpuSecondsDelta);
            int processorCount = Math.Max(1, Environment.ProcessorCount);
            double cpuBillableSecondsDelta = NormalizeCostNumber(resourceDelta.cpuComputeSeconds / processorCount);
            long ioBytesDelta = Math.Max(0, resourceDelta.ioBytes);

            lock (_chatSessionLock)
            {
                ChatCostSettings settings = GetChatCostSettings();
                double tokenCostDelta = NormalizeCostNumber(tokenDelta * settings.tokenUsdPerToken);
                double gpuElectricityCostDelta = CalculateElectricityCostUsd(settings.gpuTdpWatts, resourceDelta.gpuSeconds, settings);
                double cpuElectricityCostDelta = CalculateElectricityCostUsd(settings.cpuTdpWatts, cpuBillableSecondsDelta, settings);
                double ramElectricityCostDelta = CalculateElectricityCostUsd(settings.ramWattsPerGb, resourceDelta.ramGbSeconds, settings);
                double systemElectricityCostDelta = CalculateElectricityCostUsd(settings.systemWatts, resourceDelta.systemSeconds, settings);
                double ioGbpsSeconds = NormalizeCostNumber(ioBytesDelta * 8.0 / 1000000000.0);
                double ioElectricityCostDelta = CalculateElectricityCostUsd(settings.ioWattsPerGbps, ioGbpsSeconds, settings);
                double electricityCostDelta = NormalizeCostNumber(
                    gpuElectricityCostDelta +
                    cpuElectricityCostDelta +
                    ramElectricityCostDelta +
                    systemElectricityCostDelta +
                    ioElectricityCostDelta);

                double serviceTaxDelta = NormalizeCostNumber((tokenCostDelta + electricityCostDelta) * settings.serviceTaxRate);
                var table = GetChatUserCostsTable();
                string now = DateTimeOffset.UtcNow.ToString("O");
                for (int i = 0; i < table.Rows.Count; i++)
                {
                    object[] row = NormalizeChatUserCostRow(table.Rows[i]);
                    if (!string.Equals(GetRowValue(row, 0), ownerKey, StringComparison.OrdinalIgnoreCase))
                        continue;

                    double gpuSeconds = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 1), 0) + gpuSecondsDelta);
                    double tokenCost = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 2), 0) + tokenCostDelta);
                    double electricityCost = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 3), 0) + electricityCostDelta);
                    double serviceTax = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 4), 0) + serviceTaxDelta);
                    long tokensUsed = AddUsageTokenCount(ParseStoredLong(GetRowValue(row, 6), 0), tokenDelta);
                    double cpuComputeSeconds = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 7), 0) + resourceDelta.cpuComputeSeconds);
                    double ramGbSeconds = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 8), 0) + resourceDelta.ramGbSeconds);
                    double systemSeconds = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 9), 0) + resourceDelta.systemSeconds);
                    long ioBytesProcessed = AddUsageByteCount(ParseStoredLong(GetRowValue(row, 10), 0), ioBytesDelta);
                    double gpuElectricityCost = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 11), 0) + gpuElectricityCostDelta);
                    double cpuElectricityCost = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 12), 0) + cpuElectricityCostDelta);
                    double ramElectricityCost = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 13), 0) + ramElectricityCostDelta);
                    double systemElectricityCost = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 14), 0) + systemElectricityCostDelta);
                    double ioElectricityCost = NormalizeCostNumber(ParseStoredDouble(GetRowValue(row, 15), 0) + ioElectricityCostDelta);
                    row[1] = gpuSeconds.ToString("0.######", CultureInfo.InvariantCulture);
                    row[2] = tokenCost.ToString("0.########", CultureInfo.InvariantCulture);
                    row[3] = electricityCost.ToString("0.########", CultureInfo.InvariantCulture);
                    row[4] = serviceTax.ToString("0.########", CultureInfo.InvariantCulture);
                    row[5] = now;
                    row[6] = tokensUsed.ToString(CultureInfo.InvariantCulture);
                    row[7] = cpuComputeSeconds.ToString("0.######", CultureInfo.InvariantCulture);
                    row[8] = ramGbSeconds.ToString("0.######", CultureInfo.InvariantCulture);
                    row[9] = systemSeconds.ToString("0.######", CultureInfo.InvariantCulture);
                    row[10] = ioBytesProcessed.ToString(CultureInfo.InvariantCulture);
                    row[11] = gpuElectricityCost.ToString("0.########", CultureInfo.InvariantCulture);
                    row[12] = cpuElectricityCost.ToString("0.########", CultureInfo.InvariantCulture);
                    row[13] = ramElectricityCost.ToString("0.########", CultureInfo.InvariantCulture);
                    row[14] = systemElectricityCost.ToString("0.########", CultureInfo.InvariantCulture);
                    row[15] = ioElectricityCost.ToString("0.########", CultureInfo.InvariantCulture);
                    table.Rows[i] = row;
                    _chatSessionData.Save();
                    return new ChatCostTotals
                    {
                        ownerKey = ownerKey,
                        tokensUsed = tokensUsed,
                        gpuSecondsUsed = gpuSeconds,
                        cpuComputeSecondsUsed = cpuComputeSeconds,
                        ramGbSecondsUsed = ramGbSeconds,
                        systemSecondsUsed = systemSeconds,
                        ioBytesProcessed = ioBytesProcessed,
                        tokenCostUsd = tokenCost,
                        electricityCostUsd = electricityCost,
                        gpuElectricityCostUsd = gpuElectricityCost,
                        cpuElectricityCostUsd = cpuElectricityCost,
                        ramElectricityCostUsd = ramElectricityCost,
                        systemElectricityCostUsd = systemElectricityCost,
                        ioElectricityCostUsd = ioElectricityCost,
                        serviceTaxCostUsd = serviceTax,
                        totalCostUsd = NormalizeCostNumber(tokenCost + electricityCost + serviceTax)
                    };
                }

                var totals = new ChatCostTotals
                {
                    ownerKey = ownerKey,
                    tokensUsed = tokenDelta,
                    gpuSecondsUsed = gpuSecondsDelta,
                    cpuComputeSecondsUsed = resourceDelta.cpuComputeSeconds,
                    ramGbSecondsUsed = resourceDelta.ramGbSeconds,
                    systemSecondsUsed = resourceDelta.systemSeconds,
                    ioBytesProcessed = ioBytesDelta,
                    tokenCostUsd = tokenCostDelta,
                    electricityCostUsd = electricityCostDelta,
                    gpuElectricityCostUsd = gpuElectricityCostDelta,
                    cpuElectricityCostUsd = cpuElectricityCostDelta,
                    ramElectricityCostUsd = ramElectricityCostDelta,
                    systemElectricityCostUsd = systemElectricityCostDelta,
                    ioElectricityCostUsd = ioElectricityCostDelta,
                    serviceTaxCostUsd = serviceTaxDelta,
                    totalCostUsd = NormalizeCostNumber(tokenCostDelta + electricityCostDelta + serviceTaxDelta)
                };
                table.Rows.Add(new object[] {
                    ownerKey,
                    totals.gpuSecondsUsed.ToString("0.######", CultureInfo.InvariantCulture),
                    totals.tokenCostUsd.ToString("0.########", CultureInfo.InvariantCulture),
                    totals.electricityCostUsd.ToString("0.########", CultureInfo.InvariantCulture),
                    totals.serviceTaxCostUsd.ToString("0.########", CultureInfo.InvariantCulture),
                    now,
                    totals.tokensUsed.ToString(CultureInfo.InvariantCulture),
                    totals.cpuComputeSecondsUsed.ToString("0.######", CultureInfo.InvariantCulture),
                    totals.ramGbSecondsUsed.ToString("0.######", CultureInfo.InvariantCulture),
                    totals.systemSecondsUsed.ToString("0.######", CultureInfo.InvariantCulture),
                    totals.ioBytesProcessed.ToString(CultureInfo.InvariantCulture),
                    totals.gpuElectricityCostUsd.ToString("0.########", CultureInfo.InvariantCulture),
                    totals.cpuElectricityCostUsd.ToString("0.########", CultureInfo.InvariantCulture),
                    totals.ramElectricityCostUsd.ToString("0.########", CultureInfo.InvariantCulture),
                    totals.systemElectricityCostUsd.ToString("0.########", CultureInfo.InvariantCulture),
                    totals.ioElectricityCostUsd.ToString("0.########", CultureInfo.InvariantCulture)
                });
                _chatSessionData.Save();
                return totals;
            }
        }

        private long AddUsageTokenCount(long current, int tokenDelta)
        {
            current = Math.Max(0, current);
            if (tokenDelta <= 0)
                return current;
            if (current > long.MaxValue - tokenDelta)
                return long.MaxValue;
            return current + tokenDelta;
        }

        private long AddUsageByteCount(long current, long byteDelta)
        {
            current = Math.Max(0, current);
            if (byteDelta <= 0)
                return current;
            if (current > long.MaxValue - byteDelta)
                return long.MaxValue;
            return current + byteDelta;
        }

        private double CalculateElectricityCostUsd(double watts, double seconds, ChatCostSettings settings)
        {
            settings = settings ?? GetChatCostSettings();
            watts = NormalizeCostNumber(watts);
            seconds = NormalizeCostNumber(seconds);
            if (watts <= 0 || seconds <= 0 || settings.electricityCentsPerKwh <= 0 || settings.electricityMultiplier <= 0)
                return 0;

            double kilowattHours = watts / 1000.0 * seconds / 3600.0;
            return NormalizeCostNumber(kilowattHours * (settings.electricityCentsPerKwh / 100.0) * settings.electricityMultiplier);
        }

        private ChatResourceUsageDelta BuildChatResourceUsageDelta(double gpuSecondsDelta, ChatUsageMeter meter, TimeSpan elapsed)
        {
            var delta = new ChatResourceUsageDelta
            {
                gpuSeconds = NormalizeCostNumber(gpuSecondsDelta),
                systemSeconds = NormalizeCostNumber(elapsed.TotalSeconds)
            };

            try
            {
                using (Process process = Process.GetCurrentProcess())
                {
                    TimeSpan cpuTime = process.TotalProcessorTime;
                    if (meter != null && meter.LastProcessCpuTime.HasValue && cpuTime >= meter.LastProcessCpuTime.Value)
                        delta.cpuComputeSeconds = NormalizeCostNumber((cpuTime - meter.LastProcessCpuTime.Value).TotalSeconds);
                    if (meter != null)
                        meter.LastProcessCpuTime = cpuTime;

                    delta.ramGbEstimated = NormalizeCostNumber(process.WorkingSet64 / (1024.0 * 1024.0 * 1024.0));
                    delta.ramGbSeconds = NormalizeCostNumber(delta.ramGbEstimated * delta.systemSeconds);

                    if (TryGetCurrentProcessIoBytes(process.Handle, out ulong readBytes, out ulong writeBytes))
                    {
                        ulong totalBytes = SaturatingAdd(readBytes, writeBytes);
                        if (meter != null && meter.LastIoBytes.HasValue && totalBytes >= meter.LastIoBytes.Value)
                        {
                            ulong ioDelta = totalBytes - meter.LastIoBytes.Value;
                            delta.ioBytes = ioDelta > (ulong)long.MaxValue ? long.MaxValue : (long)ioDelta;
                        }
                        if (meter != null)
                            meter.LastIoBytes = totalBytes;
                    }
                }
            }
            catch { }

            return delta;
        }

        private double GetCurrentProcessRamGbEstimate()
        {
            try
            {
                using (Process process = Process.GetCurrentProcess())
                    return NormalizeCostNumber(process.WorkingSet64 / (1024.0 * 1024.0 * 1024.0));
            }
            catch
            {
                return 0;
            }
        }

        private static ulong SaturatingAdd(ulong left, ulong right)
        {
            return left > ulong.MaxValue - right ? ulong.MaxValue : left + right;
        }

        private static bool TryGetCurrentProcessIoBytes(IntPtr processHandle, out ulong readBytes, out ulong writeBytes)
        {
            readBytes = 0;
            writeBytes = 0;
            try
            {
                if (!GetProcessIoCounters(processHandle, out ProcessIoCounters counters))
                    return false;

                readBytes = counters.ReadTransferCount;
                writeBytes = counters.WriteTransferCount;
                return true;
            }
            catch
            {
                return false;
            }
        }

        private string NormalizeCostOwnerKey(string ownerKey)
        {
            return string.IsNullOrWhiteSpace(ownerKey) ? "" : ownerKey.Trim().ToLowerInvariant();
        }

        private string NormalizeStorageType(string storageType)
        {
            string value = (storageType ?? "").Trim();
            if (value.Equals("NVMe", StringComparison.OrdinalIgnoreCase) ||
                value.Equals("Nvme", StringComparison.OrdinalIgnoreCase) ||
                value.Equals("M.2", StringComparison.OrdinalIgnoreCase))
                return "Nvme";
            if (value.Equals("SATA SSD", StringComparison.OrdinalIgnoreCase) ||
                value.Equals("SSD", StringComparison.OrdinalIgnoreCase) ||
                value.Equals("SataSsd", StringComparison.OrdinalIgnoreCase))
                return "SATA SSD";
            if (value.Equals("SATA HDD", StringComparison.OrdinalIgnoreCase) ||
                value.Equals("HDD", StringComparison.OrdinalIgnoreCase) ||
                value.Equals("SataHdd", StringComparison.OrdinalIgnoreCase))
                return "SATA HDD";
            return DefaultStorageType;
        }

        private double ClampStorageCostFactor(double value)
        {
            if (double.IsNaN(value) || double.IsInfinity(value))
                return 0;
            return Math.Max(-1, Math.Min(1, value));
        }

        private double GetStorageUsdPerGb(string storageType)
        {
            string normalized = NormalizeStorageType(storageType);
            if (normalized.Equals("SATA HDD", StringComparison.OrdinalIgnoreCase))
                return SataHddStorageUsdPerGb;
            if (normalized.Equals("SATA SSD", StringComparison.OrdinalIgnoreCase))
                return SataSsdStorageUsdPerGb;
            return NvmeStorageUsdPerGb;
        }

        private double CalculateStorageCostUsd(long storageBytes, ChatCostSettings settings)
        {
            settings = settings ?? GetChatCostSettings();
            double usedGb = Math.Max(0, storageBytes) / (1024.0 * 1024.0 * 1024.0);
            double baseCost = GetStorageUsdPerGb(settings.storageType);
            double multiplier = 1.0 + ClampStorageCostFactor(settings.storageCostFactor);
            return NormalizeCostNumber(usedGb * baseCost * multiplier);
        }

        private double NormalizeCostNumber(double value)
        {
            if (double.IsNaN(value) || double.IsInfinity(value) || value < 0)
                return 0;
            return value;
        }

        private double GetEffectiveGpuTdpWatts(double configuredGpuTdpWatts)
        {
            if (IsPlausibleGpuTdpWatts(configuredGpuTdpWatts))
                return configuredGpuTdpWatts;

            lock (_chatCostLock)
            {
                if (!_detectedGpuTdpWatts.HasValue)
                    _detectedGpuTdpWatts = DetectNvidiaGpuTdp().TdpWatts;
                return _detectedGpuTdpWatts.Value;
            }
        }

        private GpuTdpDetectionSnapshot DetectNvidiaGpuTdp()
        {
            string[] executables = { "nvidia-smi.exe", "nvidia-smi" };
            string[] queries =
            {
                "--query-gpu=index,name,power.limit,power.default_limit,power.max_limit --format=csv,noheader,nounits",
                "--query-gpu=index,name,power.limit --format=csv,noheader,nounits"
            };

            foreach (string executable in executables)
            {
                foreach (string query in queries)
                {
                    try
                    {
                        string output = RunGpuQuery(executable, query);
                        GpuTdpCandidate candidate = SelectBestNvidiaGpuTdpCandidate(output);
                        if (candidate != null)
                        {
                            return new GpuTdpDetectionSnapshot
                            {
                                GpuName = candidate.Name,
                                TdpWatts = candidate.TdpWatts,
                                Source = candidate.Source,
                                Detail = candidate.Detail,
                                IsNvidia = true
                            };
                        }
                    }
                    catch { }
                }
            }

            return new GpuTdpDetectionSnapshot
            {
                GpuName = "",
                TdpWatts = 0,
                Source = "none",
                Detail = "No NVIDIA GPU TDP was detected. Intel, AMD, and integrated graphics are ignored.",
                IsNvidia = false
            };
        }

        private string RunGpuQuery(string executable, string arguments)
        {
            using (var process = new System.Diagnostics.Process())
            {
                process.StartInfo = new System.Diagnostics.ProcessStartInfo
                {
                    FileName = executable,
                    Arguments = arguments,
                    UseShellExecute = false,
                    CreateNoWindow = true,
                    RedirectStandardOutput = true,
                    RedirectStandardError = true
                };
                if (!process.Start())
                    return "";

                string output = process.StandardOutput.ReadToEnd();
                if (!process.WaitForExit(1800))
                {
                    try { process.Kill(); } catch { }
                    return "";
                }

                return output ?? "";
            }
        }

        private GpuTdpCandidate SelectBestNvidiaGpuTdpCandidate(string output)
        {
            GpuTdpCandidate best = null;
            foreach (string[] row in ParseSimpleCsvRows(output))
            {
                GpuTdpCandidate candidate = BuildNvidiaGpuTdpCandidate(row);
                if (candidate == null)
                    continue;
                if (best == null || candidate.TdpWatts > best.TdpWatts)
                    best = candidate;
            }

            return best;
        }

        private GpuTdpCandidate BuildNvidiaGpuTdpCandidate(string[] row)
        {
            if (row == null || row.Length < 2)
                return null;

            int offset = LooksLikeInteger(row[0]) ? 1 : 0;
            if (row.Length <= offset)
                return null;

            string name = (row[offset] ?? "").Trim();
            if (!IsNvidiaGpuName(name))
                return null;

            string[] labels = { "power.limit", "power.default_limit", "power.max_limit" };
            for (int i = offset + 1; i < row.Length; i++)
            {
                double watts = ParsePlausibleGpuWatts(row[i]);
                if (watts <= 0)
                    continue;

                int labelIndex = i - offset - 1;
                string label = labelIndex >= 0 && labelIndex < labels.Length ? labels[labelIndex] : "power";
                return new GpuTdpCandidate
                {
                    Name = name,
                    TdpWatts = watts,
                    Source = "nvidia-smi",
                    Detail = label + "=" + watts.ToString("0.#", CultureInfo.InvariantCulture) + "W"
                };
            }

            double knownWatts = LookupKnownNvidiaGpuTdpWatts(name);
            if (knownWatts > 0)
            {
                return new GpuTdpCandidate
                {
                    Name = name,
                    TdpWatts = knownWatts,
                    Source = "known-nvidia-tdp",
                    Detail = "Matched " + name + " in the known NVIDIA TDP list."
                };
            }

            return null;
        }

        private List<string[]> ParseSimpleCsvRows(string output)
        {
            var rows = new List<string[]>();
            if (string.IsNullOrWhiteSpace(output))
                return rows;

            string[] lines = output.Replace("\r\n", "\n").Replace('\r', '\n').Split('\n');
            foreach (string sourceLine in lines)
            {
                if (string.IsNullOrWhiteSpace(sourceLine))
                    continue;

                string[] parts = sourceLine.Split(',');
                for (int i = 0; i < parts.Length; i++)
                    parts[i] = (parts[i] ?? "").Trim();
                rows.Add(parts);
            }

            return rows;
        }

        private bool LooksLikeInteger(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
                return false;

            foreach (char ch in value.Trim())
            {
                if (!char.IsDigit(ch))
                    return false;
            }

            return true;
        }

        private double ParsePlausibleGpuWatts(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
                return 0;

            var sb = new StringBuilder();
            foreach (char ch in text)
            {
                if (char.IsDigit(ch) || ch == '.')
                {
                    sb.Append(ch);
                    continue;
                }

                if (sb.Length > 0)
                {
                    double parsed = ParseStoredDouble(sb.ToString(), 0);
                    if (IsPlausibleGpuTdpWatts(parsed))
                        return parsed;
                    sb.Clear();
                }
            }

            if (sb.Length <= 0)
                return 0;

            double finalParsed = ParseStoredDouble(sb.ToString(), 0);
            return IsPlausibleGpuTdpWatts(finalParsed) ? finalParsed : 0;
        }

        private bool IsPlausibleGpuTdpWatts(double watts)
        {
            return watts > 0 && !double.IsNaN(watts) && !double.IsInfinity(watts) && watts <= MaxPlausibleNvidiaGpuTdpWatts;
        }

        private bool IsNvidiaGpuName(string name)
        {
            if (string.IsNullOrWhiteSpace(name))
                return false;

            string lower = name.ToLowerInvariant();
            if (lower.Contains("intel") || lower.Contains("amd") || lower.Contains("radeon") || lower.Contains("integrated") || lower.Contains("microsoft basic"))
                return false;

            return lower.Contains("nvidia") ||
                lower.Contains("geforce") ||
                lower.Contains("quadro") ||
                lower.Contains("tesla") ||
                lower.StartsWith("rtx ", StringComparison.Ordinal) ||
                lower.StartsWith("gtx ", StringComparison.Ordinal);
        }

        private bool IsVariablePowerMobileGpu(string name)
        {
            if (string.IsNullOrWhiteSpace(name))
                return false;

            string lower = name.ToLowerInvariant();
            return lower.Contains("laptop") ||
                lower.Contains("mobile") ||
                lower.Contains("notebook") ||
                lower.Contains("max-q");
        }

        private double LookupKnownNvidiaGpuTdpWatts(string name)
        {
            if (string.IsNullOrWhiteSpace(name) || IsVariablePowerMobileGpu(name))
                return 0;

            string normalized = NormalizeGpuNameForLookup(name);
            foreach (GpuTdpSpec spec in KnownNvidiaGpuTdps)
            {
                if (ContainsGpuSpecName(normalized, spec.NormalizedName))
                    return spec.TdpWatts;
            }

            return 0;
        }

        private static bool ContainsGpuSpecName(string normalizedName, string normalizedSpecName)
        {
            if (string.IsNullOrWhiteSpace(normalizedName) || string.IsNullOrWhiteSpace(normalizedSpecName))
                return false;

            int index = normalizedName.IndexOf(normalizedSpecName, StringComparison.Ordinal);
            while (index >= 0)
            {
                int end = index + normalizedSpecName.Length;
                bool startsOnBoundary = index == 0 || normalizedName[index - 1] == ' ';
                bool endsOnBoundary = end >= normalizedName.Length || normalizedName[end] == ' ';
                if (startsOnBoundary && endsOnBoundary)
                    return true;

                index = normalizedName.IndexOf(normalizedSpecName, index + 1, StringComparison.Ordinal);
            }

            return false;
        }

        private static string NormalizeGpuNameForLookup(string name)
        {
            if (string.IsNullOrWhiteSpace(name))
                return "";

            var sb = new StringBuilder();
            foreach (char ch in name.ToLowerInvariant())
            {
                if (char.IsLetterOrDigit(ch))
                    sb.Append(ch);
                else
                    sb.Append(' ');
            }

            string normalized = CollapseWhitespace(sb.ToString());
            normalized = normalized.Replace("nvidia ", "");
            normalized = normalized.Replace("geforce ", "");
            normalized = normalized.Replace("graphics ", "");
            normalized = normalized.Replace("gpu ", "");
            normalized = normalized.Replace("founders edition", "");
            normalized = normalized.Replace("desktop", "");
            return CollapseWhitespace(normalized);
        }

        private static string CollapseWhitespace(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
                return "";

            var sb = new StringBuilder();
            bool previousWhitespace = true;
            foreach (char ch in value)
            {
                if (char.IsWhiteSpace(ch))
                {
                    if (!previousWhitespace)
                        sb.Append(' ');
                    previousWhitespace = true;
                    continue;
                }

                sb.Append(ch);
                previousWhitespace = false;
            }

            return sb.ToString().Trim();
        }

        private sealed class GpuTdpSpec
        {
            public GpuTdpSpec(string name, double tdpWatts)
            {
                Name = name ?? "";
                TdpWatts = tdpWatts;
                NormalizedName = NormalizeGpuNameForLookup(Name);
            }

            public string Name { get; private set; }
            public string NormalizedName { get; private set; }
            public double TdpWatts { get; private set; }
        }

        private sealed class GpuTdpCandidate
        {
            public string Name { get; set; }
            public double TdpWatts { get; set; }
            public string Source { get; set; }
            public string Detail { get; set; }
        }

        private ChatUsageSnapshot BuildAdminChatUsageSnapshot(string ownerKey)
        {
            ChatCostSettings settings = GetChatCostSettings();
            ChatCostTotals totals = GetChatCostTotals(ownerKey);
            return AddCostFields(new ChatUsageSnapshot
            {
                ownerKey = ownerKey ?? "",
                username = "admin",
                authenticated = true,
                unlimited = true,
                tokensUsed = totals.tokensUsed,
                tokenLimit = -1,
                tokensRemaining = long.MaxValue
            }, settings, totals);
        }

        private ChatUsageSnapshot BuildAnonymousChatUsageSnapshot()
        {
            ChatCostSettings settings = GetChatCostSettings();
            return AddCostFields(new ChatUsageSnapshot
            {
                ownerKey = "",
                username = "",
                authenticated = false,
                unlimited = false,
                tokensUsed = 0,
                tokenLimit = 0,
                tokensRemaining = 0
            }, settings, new ChatCostTotals());
        }

        private ChatUsageSnapshot BuildChatUsageSnapshot(string ownerKey, WebAuthRecord record)
        {
            if (IsAdminOwnerKey(ownerKey))
                return BuildAdminChatUsageSnapshot(ownerKey);

            record = record ?? new WebAuthRecord();
            long limit = Math.Max(0, record.tokenLimit);
            long used = Math.Max(0, record.tokensUsed);
            return AddCostFields(new ChatUsageSnapshot
            {
                ownerKey = ownerKey ?? "",
                username = record.userName ?? "",
                authenticated = !string.IsNullOrWhiteSpace(record.userName),
                unlimited = false,
                tokensUsed = used,
                tokenLimit = limit,
                tokensRemaining = Math.Max(0, limit - used)
            }, GetChatCostSettings(), GetChatCostTotals(ownerKey));
        }

        private ChatUsageSnapshot AddCostFields(ChatUsageSnapshot snapshot, ChatCostSettings settings, ChatCostTotals totals)
        {
            snapshot = snapshot ?? new ChatUsageSnapshot();
            settings = settings ?? new ChatCostSettings();
            totals = totals ?? new ChatCostTotals();
            long storageBytes = GetChatStorageUsageBytes(snapshot.ownerKey);
            bool storageUnlimited = snapshot.unlimited || IsAdminOwnerKey(snapshot.ownerKey);
            long storageLimit = storageUnlimited ? -1 : Math.Max(0, settings.storageLimitBytes);
            double storageCost = CalculateStorageCostUsd(storageBytes, settings);
            double storageTax = NormalizeCostNumber(storageCost * settings.serviceTaxRate);
            snapshot.gpuSecondsUsed = totals.gpuSecondsUsed;
            snapshot.cpuComputeSecondsUsed = totals.cpuComputeSecondsUsed;
            snapshot.ramGbSecondsUsed = totals.ramGbSecondsUsed;
            snapshot.systemSecondsUsed = totals.systemSecondsUsed;
            snapshot.ioBytesProcessed = totals.ioBytesProcessed;
            snapshot.tokenCostUsd = totals.tokenCostUsd;
            snapshot.electricityCostUsd = totals.electricityCostUsd;
            snapshot.gpuElectricityCostUsd = totals.gpuElectricityCostUsd;
            snapshot.cpuElectricityCostUsd = totals.cpuElectricityCostUsd;
            snapshot.ramElectricityCostUsd = totals.ramElectricityCostUsd;
            snapshot.systemElectricityCostUsd = totals.systemElectricityCostUsd;
            snapshot.ioElectricityCostUsd = totals.ioElectricityCostUsd;
            snapshot.storageCostUsd = storageCost;
            snapshot.serviceTaxCostUsd = NormalizeCostNumber(totals.serviceTaxCostUsd + storageTax);
            snapshot.totalCostUsd = NormalizeCostNumber(totals.tokenCostUsd + totals.electricityCostUsd + storageCost + snapshot.serviceTaxCostUsd);
            snapshot.tokenUsdPerToken = settings.tokenUsdPerToken;
            snapshot.electricityCentsPerKwh = settings.electricityCentsPerKwh;
            snapshot.electricityMultiplier = settings.electricityMultiplier;
            snapshot.gpuTdpWatts = settings.gpuTdpWatts;
            snapshot.cpuTdpWatts = settings.cpuTdpWatts;
            snapshot.ramWattsPerGb = settings.ramWattsPerGb;
            snapshot.systemWatts = settings.systemWatts;
            snapshot.ioWattsPerGbps = settings.ioWattsPerGbps;
            snapshot.ramGbEstimated = GetCurrentProcessRamGbEstimate();
            snapshot.serviceTaxRate = settings.serviceTaxRate;
            snapshot.storageType = NormalizeStorageType(settings.storageType);
            snapshot.storageBaseUsdPerGb = GetStorageUsdPerGb(settings.storageType);
            snapshot.storageCostFactor = ClampStorageCostFactor(settings.storageCostFactor);
            snapshot.storageBytesUsed = storageBytes;
            snapshot.storageLimitBytes = storageLimit;
            snapshot.storageBytesRemaining = storageUnlimited ? long.MaxValue : Math.Max(0, storageLimit - storageBytes);
            snapshot.storageUnlimited = storageUnlimited;
            snapshot.costSettingsTable = settings.table ?? "";
            return snapshot;
        }

        private ChatUsageSnapshot GetChatUsageSnapshot(string ownerKey)
        {
            if (IsAdminOwnerKey(ownerKey))
                return BuildAdminChatUsageSnapshot(ownerKey);

            string username = GetUserNameFromOwnerKey(ownerKey);
            return BuildChatUsageSnapshot(ownerKey, GetWebAuthRecord(username));
        }

        private bool IsAdminOwnerKey(string ownerKey)
        {
            return string.Equals(ownerKey, "ip:127.0.0.1", StringComparison.OrdinalIgnoreCase) ||
                   string.Equals(ownerKey, "ip:::1", StringComparison.OrdinalIgnoreCase) ||
                   string.Equals(ownerKey, "ip:localhost", StringComparison.OrdinalIgnoreCase);
        }

        private string GetUserNameFromOwnerKey(string ownerKey)
        {
            if (string.IsNullOrWhiteSpace(ownerKey))
                return "";
            const string prefix = "webauth:";
            return ownerKey.StartsWith(prefix, StringComparison.OrdinalIgnoreCase)
                ? ownerKey.Substring(prefix.Length)
                : "";
        }

        private bool TryChargeChatUsageTokens(string ownerKey, int requestedTokens, out int chargedTokens, out ChatUsageSnapshot snapshot)
        {
            chargedTokens = 0;
            if (requestedTokens <= 0)
            {
                snapshot = GetChatUsageSnapshot(ownerKey);
                return true;
            }

            if (IsAdminOwnerKey(ownerKey))
            {
                chargedTokens = requestedTokens;
                ApplyChatUsageCosts(ownerKey, chargedTokens, 0);
                snapshot = BuildAdminChatUsageSnapshot(ownerKey);
                return true;
            }

            string username = GetUserNameFromOwnerKey(ownerKey);
            if (string.IsNullOrWhiteSpace(username))
            {
                snapshot = BuildAnonymousChatUsageSnapshot();
                return false;
            }

            lock (_chatSessionLock)
            {
                var table = GetWebAuthTable();
                for (int i = 0; i < table.Rows.Count; i++)
                {
                    object[] row = NormalizeWebAuthRow(table.Rows[i]);
                    WebAuthRecord record = WebAuthRecordFromRow(row);
                    if (!string.Equals(record.userName, username, StringComparison.OrdinalIgnoreCase))
                        continue;

                    long remaining = Math.Max(0, record.tokenLimit - record.tokensUsed);
                    chargedTokens = (int)Math.Min(Math.Max(0, requestedTokens), Math.Min(remaining, int.MaxValue));
                    if (chargedTokens > 0)
                    {
                        record.tokensUsed += chargedTokens;
                        record.updatedUtc = DateTimeOffset.UtcNow.ToString("O");
                        table.Rows[i] = WebAuthRecordToRow(record);
                        _chatSessionData.Save();
                        ApplyChatUsageCosts(ownerKey, chargedTokens, 0);
                    }

                    snapshot = BuildChatUsageSnapshot(ownerKey, record);
                    return chargedTokens == requestedTokens;
                }
            }

            snapshot = BuildAnonymousChatUsageSnapshot();
            return false;
        }

        private sealed class ChatUsageMeter
        {
            public DateTimeOffset LastGpuChargeUtc { get; set; } = DateTimeOffset.UtcNow;
            public TimeSpan? LastProcessCpuTime { get; set; }
            public ulong? LastIoBytes { get; set; }
        }

        private sealed class ChatResourceUsageDelta
        {
            public double gpuSeconds { get; set; }
            public double cpuComputeSeconds { get; set; }
            public double ramGbSeconds { get; set; }
            public double systemSeconds { get; set; }
            public long ioBytes { get; set; }
            public double ramGbEstimated { get; set; }
        }

        [StructLayout(LayoutKind.Sequential)]
        private struct ProcessIoCounters
        {
            public ulong ReadOperationCount;
            public ulong WriteOperationCount;
            public ulong OtherOperationCount;
            public ulong ReadTransferCount;
            public ulong WriteTransferCount;
            public ulong OtherTransferCount;
        }

        [DllImport("kernel32.dll", SetLastError = true)]
        [return: MarshalAs(UnmanagedType.Bool)]
        private static extern bool GetProcessIoCounters(IntPtr processHandle, out ProcessIoCounters counters);

        private ChatUsageMeter CreateChatUsageMeter()
        {
            var meter = new ChatUsageMeter();
            try
            {
                using (Process process = Process.GetCurrentProcess())
                {
                    meter.LastProcessCpuTime = process.TotalProcessorTime;
                    if (TryGetCurrentProcessIoBytes(process.Handle, out ulong readBytes, out ulong writeBytes))
                        meter.LastIoBytes = SaturatingAdd(readBytes, writeBytes);
                }
            }
            catch { }

            return meter;
        }

        private ChatUsageSnapshot ChargeChatGpuUsage(string ownerKey, ChatUsageMeter meter, out double gpuSecondsDelta)
        {
            gpuSecondsDelta = 0;
            if (meter == null || string.IsNullOrWhiteSpace(ownerKey))
                return GetChatUsageSnapshot(ownerKey);

            DateTimeOffset now = DateTimeOffset.UtcNow;
            TimeSpan elapsed = now - meter.LastGpuChargeUtc;
            meter.LastGpuChargeUtc = now;
            if (elapsed.TotalSeconds <= 0.01)
                return GetChatUsageSnapshot(ownerKey);

            gpuSecondsDelta = elapsed.TotalSeconds;
            ChatResourceUsageDelta resourceDelta = BuildChatResourceUsageDelta(gpuSecondsDelta, meter, elapsed);
            ApplyChatUsageCosts(ownerKey, 0, gpuSecondsDelta, resourceDelta);
            return GetChatUsageSnapshot(ownerKey);
        }

        private void WriteChatUiProgressWithUsage(ChunkedStream output, string ownerKey, ChatUsageMeter meter, double? progress, string phase, string status)
        {
            double gpuSecondsDelta;
            ChatUsageSnapshot snapshot = ChargeChatGpuUsage(ownerKey, meter, out gpuSecondsDelta);
            WriteChatUiStreamEvent(output, "progress", "", "", "", progress, phase, status, 0,
                snapshot.tokensUsed, snapshot.tokenLimit, snapshot.unlimited, snapshot.tokensRemaining,
                gpuSecondsDelta, snapshot.gpuSecondsUsed, snapshot.tokenCostUsd, snapshot.electricityCostUsd,
                snapshot.serviceTaxCostUsd, snapshot.totalCostUsd, snapshot.tokenUsdPerToken,
                snapshot.electricityCentsPerKwh, snapshot.electricityMultiplier, snapshot.gpuTdpWatts,
                snapshot.serviceTaxRate, snapshot.storageCostUsd, snapshot.storageBytesUsed,
                snapshot.storageLimitBytes, snapshot.storageBytesRemaining, snapshot.storageUnlimited,
                snapshot.storageType, snapshot.storageBaseUsdPerGb, snapshot.storageCostFactor,
                snapshot.cpuComputeSecondsUsed, snapshot.ramGbSecondsUsed, snapshot.systemSecondsUsed,
                snapshot.ioBytesProcessed, snapshot.gpuElectricityCostUsd, snapshot.cpuElectricityCostUsd,
                snapshot.ramElectricityCostUsd, snapshot.systemElectricityCostUsd, snapshot.ioElectricityCostUsd,
                snapshot.cpuTdpWatts, snapshot.ramWattsPerGb, snapshot.systemWatts, snapshot.ioWattsPerGbps,
                snapshot.ramGbEstimated);
        }

        private void FlushChatUsageMeter(ChunkedStream output, string ownerKey, ChatUsageMeter meter)
        {
            double gpuSecondsDelta;
            ChatUsageSnapshot snapshot = ChargeChatGpuUsage(ownerKey, meter, out gpuSecondsDelta);
            if (gpuSecondsDelta > 0)
                WriteChatUsageEvent(output, 0, snapshot, gpuSecondsDelta);
        }

        private int EstimateTokenCount(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
                return 0;

            int nonWhitespace = 0;
            int wordCount = 0;
            bool inWord = false;
            foreach (char ch in text)
            {
                if (!char.IsWhiteSpace(ch))
                    nonWhitespace++;
                if (char.IsLetterOrDigit(ch) || ch == '_' || ch == '-')
                {
                    if (!inWord)
                    {
                        wordCount++;
                        inWord = true;
                    }
                }
                else
                {
                    inWord = false;
                }
            }

            int charEstimate = (int)Math.Ceiling(nonWhitespace / 4.0);
            return Math.Max(1, Math.Max(wordCount, charEstimate));
        }

        private int EstimatePromptTokensFromRequestBody(string requestBody)
        {
            if (string.IsNullOrWhiteSpace(requestBody))
                return 1;

            try
            {
                var sb = new StringBuilder();
                using (JsonDocument document = JsonDocument.Parse(requestBody))
                {
                    if (document.RootElement.ValueKind == JsonValueKind.Object &&
                        document.RootElement.TryGetProperty("messages", out JsonElement messages) &&
                        messages.ValueKind == JsonValueKind.Array)
                    {
                        foreach (JsonElement message in messages.EnumerateArray())
                            AppendJsonTextForTokenEstimate(message, sb);
                    }
                    else
                    {
                        AppendJsonTextForTokenEstimate(document.RootElement, sb);
                    }
                }

                return Math.Max(1, EstimateTokenCount(sb.Length > 0 ? sb.ToString() : requestBody));
            }
            catch
            {
                return Math.Max(1, EstimateTokenCount(requestBody));
            }
        }

        private void AppendJsonTextForTokenEstimate(JsonElement element, StringBuilder sb)
        {
            if (sb == null)
                return;
            switch (element.ValueKind)
            {
                case JsonValueKind.String:
                    sb.Append(element.GetString()).Append(' ');
                    break;
                case JsonValueKind.Object:
                    foreach (JsonProperty property in element.EnumerateObject())
                        AppendJsonTextForTokenEstimate(property.Value, sb);
                    break;
                case JsonValueKind.Array:
                    foreach (JsonElement child in element.EnumerateArray())
                        AppendJsonTextForTokenEstimate(child, sb);
                    break;
            }
        }

        private bool EnsureChatUsageCanStart(ChunkedStream output, string ownerKey, string requestBody)
        {
            ChatUsageSnapshot snapshot = GetChatUsageSnapshot(ownerKey);
            WriteChatUsageEvent(output, 0, snapshot);
            if (snapshot.unlimited)
                return true;

            if (!snapshot.authenticated)
            {
                WriteChatUiStreamEvent(output, "error", "Login is required before using LmVsProxy Chat.", "", "");
                return false;
            }

            int promptTokens = EstimatePromptTokensFromRequestBody(requestBody);
            if (snapshot.tokensRemaining < promptTokens)
            {
                WriteChatUiStreamEvent(output, "error", "Token balance is empty or too low. Buy tokens before sending this prompt.", "", "");
                return false;
            }

            TryChargeChatUsageTokens(ownerKey, promptTokens, out int charged, out ChatUsageSnapshot chargedSnapshot);
            WriteChatUsageEvent(output, charged, chargedSnapshot);
            return true;
        }

        private bool EnsureChatUsageCanStart(HttpRequest request, string ownerKey, string requestBody, out ChatUsageSnapshot snapshot, out string error)
        {
            snapshot = GetChatUsageSnapshot(ownerKey);
            error = null;
            if (snapshot.unlimited)
                return true;

            if (!snapshot.authenticated)
            {
                error = "Login is required before using LmVsProxy Chat.";
                SetHttpStatus(request, 401, "Unauthorized");
                return false;
            }

            int promptTokens = EstimatePromptTokensFromRequestBody(requestBody);
            if (snapshot.tokensRemaining < promptTokens)
            {
                error = "Token balance is empty or too low. Buy tokens before sending this prompt.";
                SetHttpStatus(request, 402, "Payment Required");
                return false;
            }

            TryChargeChatUsageTokens(ownerKey, promptTokens, out _, out snapshot);
            return true;
        }

        private bool WriteChatUiDeltaWithUsage(ChunkedStream output, string ownerKey, string content, string reasoning, string body, ChatUsageMeter meter = null)
        {
            double gpuSecondsDelta;
            ChargeChatGpuUsage(ownerKey, meter, out gpuSecondsDelta);
            int tokenDelta = EstimateTokenCount(content) + EstimateTokenCount(reasoning);
            if (tokenDelta > 0)
            {
                ChatUsageSnapshot snapshot = GetChatUsageSnapshot(ownerKey);
                if (!snapshot.unlimited)
                {
                    if (!snapshot.authenticated)
                    {
                        WriteChatUiStreamEvent(output, "error", "Login is required before using LmVsProxy Chat.", "", "");
                        return false;
                    }
                    if (snapshot.tokensRemaining < tokenDelta)
                    {
                        WriteChatUiStreamEvent(output, "error", "Token limit reached. Buy more tokens to continue.", "", "");
                        return false;
                    }
                }
            }

            WriteChatUiStreamEvent(output, "delta", content ?? "", reasoning ?? "", body ?? "");
            if (tokenDelta > 0)
            {
                TryChargeChatUsageTokens(ownerKey, tokenDelta, out int charged, out ChatUsageSnapshot chargedSnapshot);
                WriteChatUsageEvent(output, charged, chargedSnapshot, gpuSecondsDelta);
            }
            else if (gpuSecondsDelta > 0)
            {
                WriteChatUsageEvent(output, 0, GetChatUsageSnapshot(ownerKey), gpuSecondsDelta);
            }
            return true;
        }

        private void WriteChatUsageEvent(ChunkedStream output, int tokenDelta, ChatUsageSnapshot snapshot, double gpuSecondsDelta = 0)
        {
            snapshot = snapshot ?? BuildAnonymousChatUsageSnapshot();
            WriteChatUiStreamEvent(output, "usage", "", "", "", null, "token_usage", "Token usage", tokenDelta,
                snapshot.tokensUsed, snapshot.tokenLimit, snapshot.unlimited, snapshot.tokensRemaining,
                gpuSecondsDelta, snapshot.gpuSecondsUsed, snapshot.tokenCostUsd, snapshot.electricityCostUsd,
                snapshot.serviceTaxCostUsd, snapshot.totalCostUsd, snapshot.tokenUsdPerToken,
                snapshot.electricityCentsPerKwh, snapshot.electricityMultiplier, snapshot.gpuTdpWatts,
                snapshot.serviceTaxRate, snapshot.storageCostUsd, snapshot.storageBytesUsed,
                snapshot.storageLimitBytes, snapshot.storageBytesRemaining, snapshot.storageUnlimited,
                snapshot.storageType, snapshot.storageBaseUsdPerGb, snapshot.storageCostFactor,
                snapshot.cpuComputeSecondsUsed, snapshot.ramGbSecondsUsed, snapshot.systemSecondsUsed,
                snapshot.ioBytesProcessed, snapshot.gpuElectricityCostUsd, snapshot.cpuElectricityCostUsd,
                snapshot.ramElectricityCostUsd, snapshot.systemElectricityCostUsd, snapshot.ioElectricityCostUsd,
                snapshot.cpuTdpWatts, snapshot.ramWattsPerGb, snapshot.systemWatts, snapshot.ioWattsPerGbps,
                snapshot.ramGbEstimated);
        }

        private string GetRowValue(object[] row, int index)
        {
            return row != null && row.Length > index && row[index] != null ? row[index].ToString() : "";
        }

        private JsonElement DeserializeJsonElement(string json, string fallback)
        {
            try
            {
                using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(json) ? fallback : json))
                {
                    return document.RootElement.Clone();
                }
            }
            catch
            {
                using (JsonDocument document = JsonDocument.Parse(fallback))
                {
                    return document.RootElement.Clone();
                }
            }
        }

        private string InferChatSessionTitle(string messagesJson)
        {
            try
            {
                using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(messagesJson) ? "[]" : messagesJson))
                {
                    if (document.RootElement.ValueKind == JsonValueKind.Array)
                    {
                        foreach (JsonElement message in document.RootElement.EnumerateArray())
                        {
                            if (!message.TryGetProperty("role", out JsonElement role) ||
                                !role.GetString().Equals("user", StringComparison.OrdinalIgnoreCase))
                                continue;

                            string text = ExtractMessageTextForTitle(message);
                            if (!string.IsNullOrWhiteSpace(text))
                                return TruncateForLog(text.Replace("\r", " ").Replace("\n", " "), 64);
                        }
                    }
                }
            }
            catch { }

            return "New chat " + DateTime.Now.ToString("g");
        }

        private string ExtractMessageTextForTitle(JsonElement message)
        {
            if (!message.TryGetProperty("content", out JsonElement content))
                return null;

            if (content.ValueKind == JsonValueKind.String)
                return content.GetString();

            if (content.ValueKind == JsonValueKind.Array)
            {
                foreach (JsonElement part in content.EnumerateArray())
                {
                    if (part.ValueKind == JsonValueKind.Object &&
                        part.TryGetProperty("type", out JsonElement type) &&
                        type.GetString() == "text" &&
                        part.TryGetProperty("text", out JsonElement text))
                        return text.GetString();
                }
            }

            return null;
        }

        private string SanitizeFileName(string fileName)
        {
            if (string.IsNullOrWhiteSpace(fileName))
                return "attachment";

            foreach (char invalid in Path.GetInvalidFileNameChars())
                fileName = fileName.Replace(invalid, '_');
            return fileName.Trim();
        }

        private string HandleChatUiRequest(HttpRequest request, CancellationToken cancellationToken)
        {
            try
            {
                string ownerKey = GetChatSessionOwnerKey(request?.Context?.Connection, request);
                ChatPermissionState permissions = GetChatPermissions(ownerKey);
                string restriction = BuildChatRestrictionMessage(permissions);
                if (!string.IsNullOrWhiteSpace(restriction))
                {
                    SetHttpStatus(request, 403, "Forbidden");
                    return JsonSerializer.Serialize(new { ok = false, error = restriction });
                }
                bool agentMode = IsChatAgentServiceSelected(request?.Body);
                bool terminalMode = IsChatTerminalServiceSelected(request?.Body);
                bool imageRequest = ChatUiRequestContainsImageContent(request?.Body);
                string sessionId = EnsureChatUiSessionId(ExtractChatUiSessionId(request?.Body));
                if (agentMode && !permissions.agentAccess)
                {
                    SetHttpStatus(request, 403, "Forbidden");
                    return JsonSerializer.Serialize(new { ok = false, error = "Agent access is disabled for this client." });
                }
                if (terminalMode && !permissions.terminalCommands)
                {
                    SetHttpStatus(request, 403, "Forbidden");
                    return JsonSerializer.Serialize(new { ok = false, error = "Terminal Commands permission is disabled for this client." });
                }
                if (!EnsureChatUsageCanStart(request, ownerKey, request?.Body, out ChatUsageSnapshot usageSnapshot, out string usageError))
                    return JsonSerializer.Serialize(new { ok = false, error = usageError, usage = usageSnapshot });
                string lmRequestJson = BuildChatUiCompletionRequestJson(request?.Body, streamResponses: false, permissions);
                if (agentMode || terminalMode)
                    lmRequestJson = AddProxyResearchTools(lmRequestJson, permissions, includeVsTools: agentMode, includeTerminalTools: agentMode || terminalMode);
                string promptSessionId = BeginActivePromptSession(agentMode ? "Web UI Agent" : terminalMode ? "Web UI Terminal" : "Web UI Chat", ownerKey, lmRequestJson);
                ChatUsageMeter usageMeter = CreateChatUsageMeter();
                DateTimeOffset promptStartedUtc = DateTimeOffset.UtcNow;
                ChatUiCompletion completion;
                try
                {
                    completion = ExecuteChatUiCompletionWithProxyToolsAsync(lmRequestJson, ownerKey, sessionId, cancellationToken).GetAwaiter().GetResult();
                    TimeSpan elapsed = DateTimeOffset.UtcNow - promptStartedUtc;
                    double gpuSeconds = Math.Max(0, elapsed.TotalSeconds);
                    if (gpuSeconds > 0)
                        ApplyChatUsageCosts(ownerKey, 0, gpuSeconds, BuildChatResourceUsageDelta(gpuSeconds, usageMeter, elapsed));
                    int completionTokens = EstimateTokenCount(completion?.Content) + EstimateTokenCount(completion?.Reasoning);
                    if (completionTokens > 0)
                        TryChargeChatUsageTokens(ownerKey, completionTokens, out _, out usageSnapshot);
                    else
                        usageSnapshot = GetChatUsageSnapshot(ownerKey);
                    CompleteActivePromptSession(promptSessionId, "Completed");
                }
                catch
                {
                    CompleteActivePromptSession(promptSessionId, "Failed");
                    throw;
                }
                return JsonSerializer.Serialize(new
                {
                    ok = true,
                    content = completion.Content,
                    reasoning = completion.Reasoning,
                    raw = completion.Raw,
                    usage = usageSnapshot
                });
            }
            catch (OperationCanceledException)
            {
                return JsonSerializer.Serialize(new
                {
                    ok = false,
                    error = "The chat request was cancelled."
                });
            }
            catch (Exception ex)
            {
                LogMessage($"[Chat UI] Request failed: {ex}");
                return JsonSerializer.Serialize(new
                {
                    ok = false,
                    error = ex.Message
                });
            }
        }

        private async Task HandleChatUiStreamRequest(NetworkConnection connection, HttpRequest request, ChunkedStream output, CancellationToken cancellationToken)
        {
            output.ContentType = "application/x-ndjson";
            string promptSessionId = null;
            ActiveChatStreamCancellation activeStreamCancellation = null;
            CancellationTokenSource linkedStreamCancellation = null;

            try
            {
                string streamOwnerKey = GetChatSessionOwnerKey(connection, request);
                activeStreamCancellation = RegisterActiveChatStreamCancellation(streamOwnerKey, ExtractChatUiStreamId(request?.Body));
                linkedStreamCancellation = CancellationTokenSource.CreateLinkedTokenSource(cancellationToken, activeStreamCancellation.Cancellation.Token);
                cancellationToken = linkedStreamCancellation.Token;
                var usageMeter = CreateChatUsageMeter();
                bool imageRequest = ChatUiRequestContainsImageContent(request?.Body);
                ChatPermissionState permissions = GetChatPermissions(streamOwnerKey);
                string restriction = BuildChatRestrictionMessage(permissions);
                if (!string.IsNullOrWhiteSpace(restriction))
                {
                    WriteChatUiStreamEvent(output, "error", restriction, "", "");
                    return;
                }
                bool agentMode = IsChatAgentServiceSelected(request?.Body);
                bool terminalMode = IsChatTerminalServiceSelected(request?.Body);
                string sessionId = EnsureChatUiSessionId(ExtractChatUiSessionId(request?.Body));
                if (agentMode && !permissions.agentAccess)
                {
                    WriteChatUiStreamEvent(output, "error", "Agent access is disabled for this client.", "", "");
                    return;
                }
                if (terminalMode && !permissions.terminalCommands)
                {
                    WriteChatUiStreamEvent(output, "error", "Terminal Commands permission is disabled for this client.", "", "");
                    return;
                }
                if (!EnsureChatUsageCanStart(output, streamOwnerKey, request?.Body))
                    return;
                if ((agentMode && (permissions.internetSearch || permissions.fileDownloads || permissions.vsCopilotTools || permissions.terminalCommands)) ||
                    (terminalMode && permissions.terminalCommands))
                {
                    string toolRequestJson = BuildChatUiCompletionRequestJson(request?.Body, streamResponses: false, permissions);
                    toolRequestJson = AddProxyResearchTools(toolRequestJson, permissions, includeVsTools: agentMode, includeTerminalTools: agentMode || terminalMode);
                    promptSessionId = BeginActivePromptSession(agentMode ? "Web UI Agent" : "Web UI Terminal", streamOwnerKey, toolRequestJson);
                    string agentStatus = imageRequest ? "Processing image in LM Studio..." : "Processing prompt...";
                    WriteChatUiProgressWithUsage(output, streamOwnerKey, usageMeter, null, "prompt_processing", agentStatus);
                    ChatUiCompletion completion = await AwaitChatUiOperationWithProgressAsync(
                        ExecuteChatUiCompletionWithProxyToolsAsync(toolRequestJson, streamOwnerKey, sessionId, cancellationToken),
                        output,
                        promptSessionId,
                        "prompt_processing",
                        agentStatus,
                        cancellationToken,
                        streamOwnerKey,
                        usageMeter);
                    if (!string.IsNullOrEmpty(completion.Content) || !string.IsNullOrEmpty(completion.Reasoning))
                    {
                        if (!WriteChatUiDeltaWithUsage(output, streamOwnerKey, completion.Content ?? "", completion.Reasoning ?? "", completion.Raw ?? "", usageMeter))
                        {
                            CompleteActivePromptSession(promptSessionId, "Failed");
                            return;
                        }
                    }
                    FlushChatUsageMeter(output, streamOwnerKey, usageMeter);
                    WriteChatUiStreamEvent(output, "done", "", "", "");
                    CompleteActivePromptSession(promptSessionId, "Completed");
                    return;
                }

                if (!agentMode)
                {
                    try
                    {
                        string nativeRequestJson = BuildChatUiNativeChatRequestJson(request?.Body, permissions);
                        promptSessionId = BeginActivePromptSession("Web UI Chat", streamOwnerKey, nativeRequestJson);
                        ChatUiNativeStreamResult nativeResult = await TryForwardChatUiNativeChatStreamAsync(output, nativeRequestJson, promptSessionId, streamOwnerKey, usageMeter, imageRequest, cancellationToken);
                        if (nativeResult == ChatUiNativeStreamResult.Completed)
                        {
                            FlushChatUsageMeter(output, streamOwnerKey, usageMeter);
                            WriteChatUiStreamEvent(output, "done", "", "", "");
                            CompleteActivePromptSession(promptSessionId, "Completed");
                            return;
                        }
                        if (nativeResult == ChatUiNativeStreamResult.Failed)
                        {
                            CompleteActivePromptSession(promptSessionId, "Failed");
                            return;
                        }

                        UpdateActivePromptSessionPhase(promptSessionId, "Falling back to OpenAI-compatible stream");
                    }
                    catch (Exception ex)
                    {
                        if (ex is OperationCanceledException)
                            throw;
                        LogMessage("[Chat UI] Native LM Studio stream unavailable: " + ex.Message);
                    }
                }

                string lmRequestJson = BuildChatUiCompletionRequestJson(request?.Body, streamResponses: true, permissions);
                string url = $"http://{_lmStudioHost}:{_lmStudioPort}/v1/chat/completions";
                if (string.IsNullOrWhiteSpace(promptSessionId))
                    promptSessionId = BeginActivePromptSession("Web UI Chat", streamOwnerKey, lmRequestJson);
                string waitStatus = imageRequest ? "Processing image in LM Studio..." : "Waiting for LM Studio...";
                WriteChatUiProgressWithUsage(output, streamOwnerKey, usageMeter, null, "prompt_processing", waitStatus);

                using (var content = new StringContent(lmRequestJson, Encoding.UTF8, "application/json"))
                using (var upstreamRequest = new HttpRequestMessage(HttpMethod.Post, url))
                {
                    upstreamRequest.Content = content;

                    using (var response = await AwaitChatUiOperationWithProgressAsync(
                        _httpClient.SendAsync(upstreamRequest, HttpCompletionOption.ResponseHeadersRead, cancellationToken),
                        output,
                        promptSessionId,
                        "prompt_processing",
                        waitStatus,
                        cancellationToken,
                        streamOwnerKey,
                        usageMeter))
                    {
                        if (!response.IsSuccessStatusCode)
                        {
                            string body = response.Content == null ? "" : await response.Content.ReadAsStringAsync();
                            LogMessage($"[Chat UI] Streaming LM Studio returned {(int)response.StatusCode} {response.ReasonPhrase}: {TruncateForLog(body, 1000)}");
                            WriteChatUiStreamEvent(output, "error", response.ReasonPhrase ?? "LM Studio streaming request failed.", "", body);
                            return;
                        }

                        using (var upstreamStream = await response.Content.ReadAsStreamAsync())
                        using (var reader = new StreamReader(upstreamStream, Encoding.UTF8))
                        {
                            string line;
                            while (!cancellationToken.IsCancellationRequested)
                            {
                                line = await AwaitChatUiOperationWithProgressAsync(
                                    reader.ReadLineAsync(),
                                    output,
                                    promptSessionId,
                                    "prompt_processing",
                                    imageRequest ? "Processing image in LM Studio..." : "Waiting for LM Studio stream...",
                                    cancellationToken,
                                    streamOwnerKey,
                                    usageMeter);
                                if (line == null)
                                    break;

                                if (string.IsNullOrWhiteSpace(line))
                                    continue;

                                if (!line.StartsWith("data:", StringComparison.OrdinalIgnoreCase))
                                    continue;

                                string payload = line.Substring(5).Trim();
                                if (payload.Equals("[DONE]", StringComparison.OrdinalIgnoreCase))
                                    break;

                                foreach (var delta in ExtractChatUiStreamingDeltas(payload))
                                {
                                    if (!string.IsNullOrEmpty(delta.Content) || !string.IsNullOrEmpty(delta.Reasoning))
                                    {
                                        if (!WriteChatUiDeltaWithUsage(output, streamOwnerKey, delta.Content, delta.Reasoning, "", usageMeter))
                                        {
                                            CompleteActivePromptSession(promptSessionId, "Failed");
                                            return;
                                        }
                                    }
                                }
                            }
                        }
                    }
                }

                FlushChatUsageMeter(output, streamOwnerKey, usageMeter);
                WriteChatUiStreamEvent(output, "done", "", "", "");
                CompleteActivePromptSession(promptSessionId, "Completed");
            }
            catch (OperationCanceledException)
            {
                CompleteActivePromptSession(promptSessionId, "Cancelled");
                WriteChatUiStreamEvent(output, "done", "", "", "");
            }
            catch (Exception ex)
            {
                CompleteActivePromptSession(promptSessionId, "Failed");
                LogMessage($"[Chat UI] Streaming request failed: {ex}");
                WriteChatUiStreamEvent(output, "error", ex.Message, "", "");
            }
            finally
            {
                if (linkedStreamCancellation != null)
                    linkedStreamCancellation.Dispose();
                UnregisterActiveChatStreamCancellation(activeStreamCancellation);
            }
        }

        private void WriteChatUiStreamEvent(ChunkedStream output, string type, string content, string reasoning, string body, double? progress = null, string phase = null, string status = null, int tokenDelta = 0, long tokensUsed = 0, long tokenLimit = 0, bool tokenUnlimited = false, long tokensRemaining = 0, double gpuSecondsDelta = 0, double gpuSecondsUsed = 0, double tokenCostUsd = 0, double electricityCostUsd = 0, double serviceTaxCostUsd = 0, double totalCostUsd = 0, double tokenUsdPerToken = 0, double electricityCentsPerKwh = 0, double electricityMultiplier = 0, double gpuTdpWatts = 0, double serviceTaxRate = 0, double storageCostUsd = 0, long storageBytesUsed = 0, long storageLimitBytes = 0, long storageBytesRemaining = 0, bool storageUnlimited = false, string storageType = "", double storageBaseUsdPerGb = 0, double storageCostFactor = 0, double cpuComputeSecondsUsed = 0, double ramGbSecondsUsed = 0, double systemSecondsUsed = 0, long ioBytesProcessed = 0, double gpuElectricityCostUsd = 0, double cpuElectricityCostUsd = 0, double ramElectricityCostUsd = 0, double systemElectricityCostUsd = 0, double ioElectricityCostUsd = 0, double cpuTdpWatts = 0, double ramWattsPerGb = 0, double systemWatts = 0, double ioWattsPerGbps = 0, double ramGbEstimated = 0)
        {
            output.WriteLine(JsonSerializer.Serialize(new
            {
                type = type ?? "delta",
                content = content ?? "",
                reasoning = reasoning ?? "",
                body = body ?? "",
                progress,
                phase = phase ?? "",
                status = status ?? "",
                tokenDelta,
                tokensUsed,
                tokenLimit,
                tokenUnlimited,
                tokensRemaining,
                gpuSecondsDelta,
                gpuSecondsUsed,
                cpuComputeSecondsUsed,
                ramGbSecondsUsed,
                systemSecondsUsed,
                ioBytesProcessed,
                tokenCostUsd,
                electricityCostUsd,
                gpuElectricityCostUsd,
                cpuElectricityCostUsd,
                ramElectricityCostUsd,
                systemElectricityCostUsd,
                ioElectricityCostUsd,
                serviceTaxCostUsd,
                totalCostUsd,
                tokenUsdPerToken,
                electricityCentsPerKwh,
                electricityMultiplier,
                gpuTdpWatts,
                cpuTdpWatts,
                ramWattsPerGb,
                systemWatts,
                ioWattsPerGbps,
                ramGbEstimated,
                serviceTaxRate,
                storageCostUsd,
                storageBytesUsed,
                storageLimitBytes,
                storageBytesRemaining,
                storageUnlimited,
                storageType = storageType ?? "",
                storageBaseUsdPerGb,
                storageCostFactor
            }));
        }

        private async Task<T> AwaitChatUiOperationWithProgressAsync<T>(Task<T> operation, ChunkedStream output, string promptSessionId, string phase, string status, CancellationToken cancellationToken, string ownerKey = null, ChatUsageMeter usageMeter = null)
        {
            if (operation == null)
                throw new ArgumentNullException(nameof(operation));

            DateTimeOffset startedUtc = DateTimeOffset.UtcNow;
            while (!operation.IsCompleted)
            {
                Task completed = await Task.WhenAny(operation, Task.Delay(ChatUiKeepAliveInterval, cancellationToken));
                if (completed == operation)
                    break;

                cancellationToken.ThrowIfCancellationRequested();
                TimeSpan elapsed = DateTimeOffset.UtcNow - startedUtc;
                string heartbeatStatus = BuildChatUiKeepAliveStatus(status, elapsed);
                double progress = CalculateEstimatedChatUiProgress(elapsed);
                UpdateActivePromptSessionPhase(promptSessionId, heartbeatStatus);
                WriteChatUiProgressWithUsage(output, ownerKey, usageMeter, progress, phase, heartbeatStatus);
            }

            return await operation;
        }

        private double CalculateEstimatedChatUiProgress(TimeSpan elapsed)
        {
            double elapsedSeconds = Math.Max(elapsed.TotalSeconds, 0);
            double progress = (1.0 - Math.Exp(-elapsedSeconds / 45.0)) * 0.95;

            if (progress <= 0)
                return 0.01;

            return Math.Max(0.01, Math.Min(0.95, progress));
        }

        private string BuildChatUiKeepAliveStatus(string status, TimeSpan elapsed)
        {
            string text = string.IsNullOrWhiteSpace(status) ? "Still processing..." : status.Trim();
            return text + " Still connected after " + FormatShortElapsed(elapsed) + ".";
        }

        private string FormatShortElapsed(TimeSpan elapsed)
        {
            int totalSeconds = Math.Max(0, (int)Math.Round(elapsed.TotalSeconds));
            if (totalSeconds < 60)
                return totalSeconds.ToString(CultureInfo.InvariantCulture) + "s";

            int minutes = totalSeconds / 60;
            int seconds = totalSeconds % 60;
            if (minutes < 60)
                return minutes.ToString(CultureInfo.InvariantCulture) + "m " + seconds.ToString("00", CultureInfo.InvariantCulture) + "s";

            int hours = minutes / 60;
            minutes %= 60;
            return hours.ToString(CultureInfo.InvariantCulture) + "h " + minutes.ToString("00", CultureInfo.InvariantCulture) + "m";
        }

        private bool ChatUiRequestContainsImageContent(string requestBody)
        {
            if (string.IsNullOrWhiteSpace(requestBody))
                return false;

            return requestBody.IndexOf("\"image_url\"", StringComparison.OrdinalIgnoreCase) >= 0 ||
                   requestBody.IndexOf("data:image/", StringComparison.OrdinalIgnoreCase) >= 0;
        }

        private async Task<ChatUiNativeStreamResult> TryForwardChatUiNativeChatStreamAsync(ChunkedStream output, string nativeRequestJson, string promptSessionId, string ownerKey, ChatUsageMeter usageMeter, bool imageRequest, CancellationToken cancellationToken)
        {
            string url = $"http://{_lmStudioHost}:{_lmStudioPort}/api/v1/chat";
            using (var content = new StringContent(nativeRequestJson, Encoding.UTF8, "application/json"))
            using (var upstreamRequest = new HttpRequestMessage(HttpMethod.Post, url))
            {
                upstreamRequest.Content = content;

                string waitStatus = imageRequest ? "Processing image in LM Studio..." : "Waiting for LM Studio...";
                using (var response = await AwaitChatUiOperationWithProgressAsync(
                    _httpClient.SendAsync(upstreamRequest, HttpCompletionOption.ResponseHeadersRead, cancellationToken),
                    output,
                    promptSessionId,
                    "prompt_processing",
                    waitStatus,
                    cancellationToken,
                    ownerKey,
                    usageMeter))
                {
                    if (!response.IsSuccessStatusCode)
                    {
                        string body = response.Content == null ? "" : await response.Content.ReadAsStringAsync();
                        LogMessage($"[Chat UI] Native LM Studio stream returned {(int)response.StatusCode} {response.ReasonPhrase}: {TruncateForLog(body, 1000)}");
                        return ChatUiNativeStreamResult.Unavailable;
                    }

                    using (var upstreamStream = await response.Content.ReadAsStreamAsync())
                    using (var reader = new StreamReader(upstreamStream, Encoding.UTF8))
                    {
                        string eventName = "";
                        var data = new StringBuilder();
                        var nativeState = new ChatUiNativeStreamState();
                        string line;
                        while (!cancellationToken.IsCancellationRequested)
                        {
                            line = await AwaitChatUiOperationWithProgressAsync(
                                reader.ReadLineAsync(),
                                output,
                                promptSessionId,
                                "prompt_processing",
                                imageRequest ? "Processing image in LM Studio..." : "Waiting for native LM Studio stream...",
                                cancellationToken,
                                ownerKey,
                                usageMeter);
                            if (line == null)
                                break;

                            if (string.IsNullOrWhiteSpace(line))
                            {
                                ChatUiNativeFrameResult frameResult = HandleChatUiNativeStreamFrame(output, eventName, data.ToString(), promptSessionId, nativeState, ownerKey, usageMeter);
                                if (frameResult == ChatUiNativeFrameResult.Complete)
                                    return ChatUiNativeStreamResult.Completed;
                                if (frameResult == ChatUiNativeFrameResult.Failed)
                                    return ChatUiNativeStreamResult.Failed;
                                eventName = "";
                                data.Clear();
                                continue;
                            }

                            if (line.StartsWith("event:", StringComparison.OrdinalIgnoreCase))
                            {
                                eventName = line.Substring(6).Trim();
                                continue;
                            }

                            if (line.StartsWith("data:", StringComparison.OrdinalIgnoreCase))
                            {
                                if (data.Length > 0)
                                    data.AppendLine();
                                data.Append(line.Substring(5).Trim());
                            }
                        }

                        ChatUiNativeFrameResult finalFrameResult = HandleChatUiNativeStreamFrame(output, eventName, data.ToString(), promptSessionId, nativeState, ownerKey, usageMeter);
                        if (finalFrameResult == ChatUiNativeFrameResult.Failed)
                            return ChatUiNativeStreamResult.Failed;
                    }
                }
            }

            return ChatUiNativeStreamResult.Completed;
        }

        private ChatUiNativeFrameResult HandleChatUiNativeStreamFrame(ChunkedStream output, string eventName, string payload, string promptSessionId, ChatUiNativeStreamState nativeState, string ownerKey, ChatUsageMeter usageMeter)
        {
            if (string.IsNullOrWhiteSpace(eventName) && string.IsNullOrWhiteSpace(payload))
                return ChatUiNativeFrameResult.Continue;

            try
            {
                using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(payload) ? "{}" : payload))
                {
                    JsonElement root = document.RootElement;
                    string type = string.IsNullOrWhiteSpace(eventName)
                        ? ExtractStringProperty(root, "type") ?? ""
                        : eventName.Trim();

                    if (NativeEventTypeEquals(type, "model_load.start"))
                    {
                        UpdateActivePromptSessionPhase(promptSessionId, "Loading model");
                        WriteChatUiProgressWithUsage(output, ownerKey, usageMeter, null, "model_load", "Loading model...");
                    }
                    else if (NativeEventTypeEquals(type, "model_load.progress"))
                    {
                        double? progress = ExtractNativeProgress(root);
                        string status = "Loading model" + (progress.HasValue ? " " + FormatPromptProgressPercent(progress.Value) : "...");
                        UpdateActivePromptSessionPhase(promptSessionId, status);
                        WriteChatUiProgressWithUsage(output, ownerKey, usageMeter, ClampProgress(progress), "model_load", status);
                    }
                    else if (NativeEventTypeEquals(type, "prompt_processing.start"))
                    {
                        UpdateActivePromptSessionPhase(promptSessionId, "Processing prompt 0%");
                        WriteChatUiProgressWithUsage(output, ownerKey, usageMeter, 0, "prompt_processing", "Processing prompt 0%");
                    }
                    else if (NativeEventTypeEquals(type, "prompt_processing.progress"))
                    {
                        double? progress = ExtractNativeProgress(root);
                        string status = "Processing prompt" + (progress.HasValue ? " " + FormatPromptProgressPercent(progress.Value) : "...");
                        UpdateActivePromptSessionPhase(promptSessionId, status);
                        WriteChatUiProgressWithUsage(output, ownerKey, usageMeter, ClampProgress(progress), "prompt_processing", status);
                    }
                    else if (NativeEventTypeEquals(type, "prompt_processing.end"))
                    {
                        UpdateActivePromptSessionPhase(promptSessionId, "Processing prompt 100%");
                        WriteChatUiProgressWithUsage(output, ownerKey, usageMeter, 1, "prompt_processing", "Processing prompt 100%");
                    }
                    else if (IsNativeReasoningDeltaType(type))
                    {
                        string reasoning = ExtractNativeChatContent(root);
                        if (!string.IsNullOrEmpty(reasoning))
                        {
                            nativeState?.Reasoning.Append(reasoning);
                            if (!WriteChatUiDeltaWithUsage(output, ownerKey, "", reasoning, "", usageMeter))
                                return ChatUiNativeFrameResult.Failed;
                        }
                    }
                    else if (IsNativeMessageDeltaType(type))
                    {
                        string content = ExtractNativeChatContent(root);
                        if (!string.IsNullOrEmpty(content))
                        {
                            nativeState?.Content.Append(content);
                            if (!WriteChatUiDeltaWithUsage(output, ownerKey, content, "", "", usageMeter))
                                return ChatUiNativeFrameResult.Failed;
                        }
                    }
                    else if (NativeEventTypeEquals(type, "error"))
                    {
                        WriteChatUiStreamEvent(output, "error", ExtractNativeChatErrorMessage(root), "", payload ?? "");
                        return ChatUiNativeFrameResult.Failed;
                    }
                    else if (NativeEventTypeEquals(type, "chat.end"))
                    {
                        if (!FlushNativeChatEndResult(output, root, nativeState, ownerKey, usageMeter))
                            return ChatUiNativeFrameResult.Failed;
                        return ChatUiNativeFrameResult.Complete;
                    }
                    else
                    {
                        string content = ExtractNativeChatContent(root);
                        if (!string.IsNullOrEmpty(content) && type.IndexOf("reason", StringComparison.OrdinalIgnoreCase) >= 0)
                        {
                            nativeState?.Reasoning.Append(content);
                            if (!WriteChatUiDeltaWithUsage(output, ownerKey, "", content, "", usageMeter))
                                return ChatUiNativeFrameResult.Failed;
                        }
                        else if (!string.IsNullOrEmpty(content) && type.IndexOf("delta", StringComparison.OrdinalIgnoreCase) >= 0)
                        {
                            nativeState?.Content.Append(content);
                            if (!WriteChatUiDeltaWithUsage(output, ownerKey, content, "", "", usageMeter))
                                return ChatUiNativeFrameResult.Failed;
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] Could not parse native LM Studio stream event: " + ex.Message + "; payload=" + TruncateForLog(payload, 400));
            }

            return ChatUiNativeFrameResult.Continue;
        }

        private bool NativeEventTypeEquals(string actual, string expected)
        {
            return string.Equals(NormalizeNativeEventType(actual), NormalizeNativeEventType(expected), StringComparison.Ordinal);
        }

        private string NormalizeNativeEventType(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
                return "";

            var sb = new StringBuilder(value.Length);
            foreach (char ch in value)
            {
                if (char.IsLetterOrDigit(ch))
                    sb.Append(char.ToLowerInvariant(ch));
            }

            return sb.ToString();
        }

        private sealed class ChatUiNativeStreamState
        {
            public StringBuilder Content { get; } = new StringBuilder();
            public StringBuilder Reasoning { get; } = new StringBuilder();
        }

        private bool IsNativeReasoningDeltaType(string type)
        {
            return NativeEventTypeEquals(type, "reasoning.delta") ||
                   NativeEventTypeEquals(type, "response.reasoning.delta") ||
                   (type ?? "").IndexOf("reasoning", StringComparison.OrdinalIgnoreCase) >= 0 &&
                   (type ?? "").IndexOf("delta", StringComparison.OrdinalIgnoreCase) >= 0;
        }

        private bool IsNativeMessageDeltaType(string type)
        {
            return NativeEventTypeEquals(type, "message.delta") ||
                   NativeEventTypeEquals(type, "response.output_text.delta") ||
                   NativeEventTypeEquals(type, "response.message.delta") ||
                   ((type ?? "").IndexOf("message", StringComparison.OrdinalIgnoreCase) >= 0 ||
                    (type ?? "").IndexOf("output_text", StringComparison.OrdinalIgnoreCase) >= 0) &&
                   (type ?? "").IndexOf("delta", StringComparison.OrdinalIgnoreCase) >= 0;
        }

        private string ExtractNativeChatContent(JsonElement root)
        {
            if (root.ValueKind == JsonValueKind.String)
                return root.GetString() ?? "";

            if (root.ValueKind != JsonValueKind.Object)
                return "";

            if (TryExtractNativeChatTextProperty(root, "content", out string text) ||
                TryExtractNativeChatTextProperty(root, "text", out text) ||
                TryExtractNativeChatTextProperty(root, "delta", out text) ||
                TryExtractNativeChatTextProperty(root, "message", out text))
                return text;

            if (root.TryGetProperty("data", out JsonElement data) &&
                TryExtractNativeChatText(data, out text))
                return text;

            return "";
        }

        private double? ExtractNativeProgress(JsonElement root)
        {
            double? progress = ExtractJsonDoubleProperty(root, "progress") ??
                               ExtractJsonDoubleProperty(root, "percent") ??
                               ExtractJsonDoubleProperty(root, "percentage");
            if (progress.HasValue)
                return progress;

            if (root.ValueKind == JsonValueKind.Object &&
                root.TryGetProperty("data", out JsonElement data))
            {
                return ExtractJsonDoubleProperty(data, "progress") ??
                       ExtractJsonDoubleProperty(data, "percent") ??
                       ExtractJsonDoubleProperty(data, "percentage");
            }

            return null;
        }

        private bool TryExtractNativeChatTextProperty(JsonElement element, string propertyName, out string text)
        {
            text = "";
            if (element.ValueKind != JsonValueKind.Object ||
                !element.TryGetProperty(propertyName, out JsonElement value))
                return false;

            return TryExtractNativeChatText(value, out text);
        }

        private bool TryExtractNativeChatText(JsonElement element, out string text)
        {
            text = "";
            if (element.ValueKind == JsonValueKind.String)
            {
                text = element.GetString() ?? "";
                return !string.IsNullOrEmpty(text);
            }

            if (element.ValueKind == JsonValueKind.Array)
            {
                text = ExtractResponsesContentText(element);
                return !string.IsNullOrEmpty(text);
            }

            if (element.ValueKind == JsonValueKind.Object)
            {
                if (TryExtractNativeChatTextProperty(element, "content", out text) ||
                    TryExtractNativeChatTextProperty(element, "text", out text) ||
                    TryExtractNativeChatTextProperty(element, "delta", out text))
                    return true;
            }

            return false;
        }

        private bool FlushNativeChatEndResult(ChunkedStream output, JsonElement root, ChatUiNativeStreamState nativeState, string ownerKey, ChatUsageMeter usageMeter)
        {
            if (nativeState == null || root.ValueKind != JsonValueKind.Object)
                return true;

            ChatUiCompletion completion = ExtractNativeChatEndCompletion(root);
            string contentDelta = ExtractUnsentNativeSuffix(completion.Content, nativeState.Content.ToString());
            string reasoningDelta = ExtractUnsentNativeSuffix(completion.Reasoning, nativeState.Reasoning.ToString());
            if (string.IsNullOrEmpty(contentDelta) && string.IsNullOrEmpty(reasoningDelta))
                return true;

            nativeState.Content.Append(contentDelta);
            nativeState.Reasoning.Append(reasoningDelta);
            return WriteChatUiDeltaWithUsage(output, ownerKey, contentDelta, reasoningDelta, "", usageMeter);
        }

        private ChatUiCompletion ExtractNativeChatEndCompletion(JsonElement root)
        {
            var completion = new ChatUiCompletion();
            if (root.ValueKind != JsonValueKind.Object ||
                !root.TryGetProperty("result", out JsonElement result))
                return completion;

            if (result.ValueKind == JsonValueKind.Object &&
                result.TryGetProperty("output", out JsonElement output))
                ExtractNativeOutputParts(output, completion);
            else
                ExtractNativeOutputParts(result, completion);

            return completion;
        }

        private void ExtractNativeOutputParts(JsonElement element, ChatUiCompletion completion)
        {
            if (completion == null)
                return;

            if (element.ValueKind == JsonValueKind.Array)
            {
                foreach (JsonElement part in element.EnumerateArray())
                    ExtractNativeOutputParts(part, completion);
                return;
            }

            if (element.ValueKind == JsonValueKind.String)
            {
                completion.Content += element.GetString() ?? "";
                return;
            }

            if (element.ValueKind != JsonValueKind.Object)
                return;

            string type = ExtractStringProperty(element, "type") ?? "";
            string text = ExtractNativeChatContent(element);
            bool appendedText = false;
            if (!string.IsNullOrEmpty(text))
            {
                if (type.IndexOf("reason", StringComparison.OrdinalIgnoreCase) >= 0)
                    completion.Reasoning += text;
                else
                    completion.Content += text;
                appendedText = true;
            }

            if (element.TryGetProperty("content", out JsonElement content) &&
                content.ValueKind != JsonValueKind.String &&
                !appendedText)
                ExtractNativeOutputParts(content, completion);
        }

        private string ExtractUnsentNativeSuffix(string aggregate, string alreadySent)
        {
            aggregate = aggregate ?? "";
            alreadySent = alreadySent ?? "";
            if (string.IsNullOrEmpty(aggregate))
                return "";
            if (string.IsNullOrEmpty(alreadySent))
                return aggregate;
            if (aggregate.StartsWith(alreadySent, StringComparison.Ordinal))
                return aggregate.Substring(alreadySent.Length);
            return "";
        }

        private double? ClampProgress(double? progress)
        {
            if (!progress.HasValue)
                return null;

            double value = progress.Value;
            if (value > 1 && value <= 100)
                value /= 100;

            if (value < 0)
                return 0;
            if (value > 1)
                return 1;
            return value;
        }

        private string FormatPromptProgressPercent(double progress)
        {
            progress = ClampProgress(progress).GetValueOrDefault();
            return Math.Round(progress * 100, MidpointRounding.AwayFromZero).ToString("0", CultureInfo.InvariantCulture) + "%";
        }

        private string ExtractNativeChatErrorMessage(JsonElement root)
        {
            if (root.ValueKind == JsonValueKind.Object &&
                root.TryGetProperty("error", out JsonElement error))
            {
                string message = ExtractStringProperty(error, "message");
                if (!string.IsNullOrWhiteSpace(message))
                    return message;
                if (error.ValueKind == JsonValueKind.String)
                    return error.GetString();
            }

            return ExtractStringProperty(root, "message") ?? "LM Studio streaming request failed.";
        }

        private double? ExtractJsonDoubleProperty(JsonElement element, string propertyName)
        {
            if (element.ValueKind != JsonValueKind.Object ||
                !element.TryGetProperty(propertyName, out JsonElement value))
                return null;

            if (value.ValueKind == JsonValueKind.Number && value.TryGetDouble(out double number))
                return number;

            if (value.ValueKind == JsonValueKind.String &&
                double.TryParse(value.GetString(), NumberStyles.Float, CultureInfo.InvariantCulture, out number))
                return number;

            return null;
        }

        private async Task<ChatUiCompletion> ExecuteChatUiCompletionWithProxyToolsAsync(string lmRequestJson, string ownerKey, string sessionId, CancellationToken cancellationToken)
        {
            string url = $"http://{_lmStudioHost}:{_lmStudioPort}/v1/chat/completions";
            string currentRequestJson = lmRequestJson;
            sessionId = EnsureChatUiSessionId(sessionId);
            const int maxProxyToolRounds = 6;

            for (int toolRound = 0; toolRound < maxProxyToolRounds; toolRound++)
            {
                using (var content = new StringContent(currentRequestJson, Encoding.UTF8, "application/json"))
                using (var response = await _httpClient.PostAsync(url, content, cancellationToken))
                {
                    string responseBody = response.Content == null ? "" : await response.Content.ReadAsStringAsync();
                    if (!response.IsSuccessStatusCode)
                    {
                        LogMessage($"[Chat UI] LM Studio returned {(int)response.StatusCode} {response.ReasonPhrase}: {TruncateForLog(responseBody, 1000)}");
                        throw new InvalidOperationException((response.ReasonPhrase ?? "LM Studio request failed.") + ": " + TruncateForLog(responseBody, 1000));
                    }

                    var toolCalls = ExtractProxyToolCallsFromChatCompletion(responseBody);
                    if (toolCalls.Count > 0 && ContainsProxyOwnedToolCall(toolCalls))
                    {
                        LogToolCalls("chat ui proxy tools", toolCalls);
                        bool finalAnswerRound = toolRound >= maxProxyToolRounds - 2;
                        string continuationRequest = await BuildProxyToolContinuationRequestAsync(
                            currentRequestJson,
                            toolCalls,
                            keepProxyTools: !finalAnswerRound,
                            ownerKey: ownerKey,
                            sessionId: sessionId);
                        if (!string.IsNullOrWhiteSpace(continuationRequest))
                        {
                            currentRequestJson = finalAnswerRound
                                ? AddProxyToolFinalAnswerInstruction(continuationRequest)
                                : continuationRequest;
                            continue;
                        }
                    }

                    ChatUiCompletion direct = ExtractChatUiCompletionFromChatCompletion(responseBody);
                    direct.Raw = responseBody;
                    return direct;
                }
            }

            LogMessage("[Chat UI] Proxy agent tool loop reached the maximum; returning latest tool results instead of an error.");
            return BuildProxyToolLoopFallbackCompletion(currentRequestJson);
        }

        private string AddProxyToolFinalAnswerInstruction(string requestBody)
        {
            if (string.IsNullOrWhiteSpace(requestBody))
                return requestBody;

            const string marker = "[LmVsProxy proxy tool final answer]";
            if (requestBody.Contains(marker))
                return requestBody;

            try
            {
                return AppendSystemMessage(requestBody,
                    marker + " You have enough tool output to answer now. Do not call any more tools. " +
                    "Use the most recent tool result(s) to answer the user's request directly and concisely.");
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] Could not add proxy tool final-answer instruction: " + ex.Message);
                return requestBody;
            }
        }

        private ChatUiCompletion BuildProxyToolLoopFallbackCompletion(string requestBody)
        {
            var toolResults = ExtractLatestProxyToolResultText(requestBody, 4);
            string content;
            if (toolResults.Count == 0)
            {
                content = "The agent tool loop reached its limit before the model produced a final answer.";
            }
            else
            {
                content = "The model kept requesting tools, so I stopped the loop and returned the latest tool result:\n\n" +
                          string.Join("\n\n", toolResults);
            }

            return new ChatUiCompletion
            {
                Content = content,
                Reasoning = "",
                Raw = requestBody ?? ""
            };
        }

        private List<string> ExtractLatestProxyToolResultText(string requestBody, int take)
        {
            var results = new List<string>();
            if (string.IsNullOrWhiteSpace(requestBody))
                return results;

            try
            {
                using (JsonDocument document = JsonDocument.Parse(requestBody))
                {
                    if (!document.RootElement.TryGetProperty("messages", out JsonElement messages) ||
                        messages.ValueKind != JsonValueKind.Array)
                        return results;

                    var toolNamesById = new Dictionary<string, string>(StringComparer.Ordinal);
                    foreach (JsonElement message in messages.EnumerateArray())
                    {
                        string role = message.TryGetProperty("role", out JsonElement roleElement) &&
                                      roleElement.ValueKind == JsonValueKind.String
                            ? roleElement.GetString()
                            : "";

                        if (role.Equals("assistant", StringComparison.OrdinalIgnoreCase) &&
                            message.TryGetProperty("tool_calls", out JsonElement toolCalls) &&
                            toolCalls.ValueKind == JsonValueKind.Array)
                        {
                            foreach (JsonElement toolCall in toolCalls.EnumerateArray())
                            {
                                string id = toolCall.TryGetProperty("id", out JsonElement idElement) &&
                                            idElement.ValueKind == JsonValueKind.String
                                    ? idElement.GetString()
                                    : "";
                                string name = "";
                                if (toolCall.TryGetProperty("function", out JsonElement function) &&
                                    function.ValueKind == JsonValueKind.Object &&
                                    function.TryGetProperty("name", out JsonElement nameElement) &&
                                    nameElement.ValueKind == JsonValueKind.String)
                                {
                                    name = nameElement.GetString();
                                }

                                if (!string.IsNullOrWhiteSpace(id) && IsProxyOwnedResearchTool(name))
                                    toolNamesById[id] = name;
                            }
                        }
                        else if (role.Equals("tool", StringComparison.OrdinalIgnoreCase))
                        {
                            string toolCallId = message.TryGetProperty("tool_call_id", out JsonElement toolCallIdElement) &&
                                                toolCallIdElement.ValueKind == JsonValueKind.String
                                ? toolCallIdElement.GetString()
                                : "";
                            if (string.IsNullOrWhiteSpace(toolCallId) || !toolNamesById.TryGetValue(toolCallId, out string name))
                                continue;

                            string toolContent = message.TryGetProperty("content", out JsonElement contentElement)
                                ? contentElement.ToString()
                                : "";
                            if (string.IsNullOrWhiteSpace(toolContent))
                                continue;

                            results.Add(name + " result:\n" + TruncateForLog(toolContent.Trim(), 12000));
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] Could not extract latest proxy tool result: " + ex.Message);
            }

            if (results.Count <= take)
                return results;

            return results.GetRange(results.Count - take, take);
        }

        private List<ToolCallData> ExtractProxyToolCallsFromChatCompletion(string responseBody)
        {
            var result = new List<ToolCallData>();
            if (string.IsNullOrWhiteSpace(responseBody))
                return result;

            try
            {
                using (JsonDocument document = JsonDocument.Parse(responseBody))
                {
                    if (!document.RootElement.TryGetProperty("choices", out JsonElement choices) ||
                        choices.ValueKind != JsonValueKind.Array)
                        return result;

                    foreach (JsonElement choice in choices.EnumerateArray())
                    {
                        if (!choice.TryGetProperty("message", out JsonElement message) ||
                            message.ValueKind != JsonValueKind.Object)
                            continue;

                        if (message.TryGetProperty("tool_calls", out JsonElement toolCalls) &&
                            toolCalls.ValueKind == JsonValueKind.Array)
                        {
                            foreach (JsonElement toolCall in toolCalls.EnumerateArray())
                            {
                                ToolCallData parsed = ParseOpenAiToolCall(toolCall);
                                if (parsed != null && IsProxyOwnedResearchTool(parsed.Name))
                                    result.Add(parsed);
                            }
                        }

                        if (message.TryGetProperty("content", out JsonElement contentElement) &&
                            contentElement.ValueKind == JsonValueKind.String &&
                            !string.IsNullOrWhiteSpace(contentElement.GetString()))
                        {
                            foreach (ToolCallData parsed in ExtractQwenToolCalls(contentElement.GetString()))
                            {
                                if (parsed != null && IsProxyOwnedResearchTool(parsed.Name))
                                    result.Add(parsed);
                            }
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] Could not parse proxy tool calls: " + ex.Message);
            }

            return result;
        }

        private ToolCallData ParseOpenAiToolCall(JsonElement toolCall)
        {
            if (toolCall.ValueKind != JsonValueKind.Object)
                return null;

            string id = ExtractStringProperty(toolCall, "id");
            if (!toolCall.TryGetProperty("function", out JsonElement function) ||
                function.ValueKind != JsonValueKind.Object)
                return null;

            string name = ExtractStringProperty(function, "name");
            if (string.IsNullOrWhiteSpace(name))
                return null;

            string arguments = "{}";
            if (function.TryGetProperty("arguments", out JsonElement argumentsElement))
                arguments = argumentsElement.ValueKind == JsonValueKind.String
                    ? argumentsElement.GetString()
                    : argumentsElement.GetRawText();
            if (string.IsNullOrWhiteSpace(arguments))
                arguments = "{}";

            return new ToolCallData
            {
                Id = id,
                Name = name,
                ArgumentsJson = RepairKnownToolArguments(name, arguments),
                ArgumentsWereMalformed = !IsValidJsonObject(arguments)
            };
        }

        private IEnumerable<ChatUiCompletion> ExtractChatUiStreamingDeltas(string payload)
        {
            if (string.IsNullOrWhiteSpace(payload))
                yield break;

            JsonDocument document = null;
            try
            {
                document = JsonDocument.Parse(payload);
                JsonElement root = document.RootElement;
                if (!root.TryGetProperty("choices", out JsonElement choices) ||
                    choices.ValueKind != JsonValueKind.Array ||
                    choices.GetArrayLength() == 0)
                    yield break;

                foreach (JsonElement choice in choices.EnumerateArray())
                {
                    JsonElement delta;
                    if (choice.TryGetProperty("delta", out delta) && delta.ValueKind == JsonValueKind.Object)
                    {
                        yield return ExtractChatUiDelta(delta);
                    }
                    else if (choice.TryGetProperty("message", out delta) && delta.ValueKind == JsonValueKind.Object)
                    {
                        yield return ExtractChatUiDelta(delta);
                    }
                }
            }
            finally
            {
                document?.Dispose();
            }
        }

        private ChatUiCompletion ExtractChatUiDelta(JsonElement delta)
        {
            string content = delta.TryGetProperty("content", out JsonElement contentElement)
                ? ExtractResponsesContentText(contentElement)
                : "";
            string reasoning = ExtractReasoningText(delta);
            return new ChatUiCompletion
            {
                Content = content ?? "",
                Reasoning = reasoning ?? ""
            };
        }

        private string BuildChatUiCompletionRequestJson(string requestBody, bool streamResponses, ChatPermissionState permissions = null)
        {
            if (string.IsNullOrWhiteSpace(requestBody))
                throw new InvalidOperationException("Chat UI request body was empty.");

            using (JsonDocument document = JsonDocument.Parse(requestBody))
            using (var jsonStream = new MemoryStream())
            using (var writer = new Utf8JsonWriter(jsonStream))
            {
                JsonElement root = document.RootElement;
                if (root.ValueKind != JsonValueKind.Object)
                    throw new InvalidOperationException("Chat UI request body must be a JSON object.");

                writer.WriteStartObject();
                string requestedModel = ExtractStringProperty(root, "model");
                writer.WriteString("model", string.IsNullOrWhiteSpace(requestedModel)
                    ? (string.IsNullOrWhiteSpace(ChatModel) ? "lm-studio" : ChatModel)
                    : requestedModel);
                writer.WriteBoolean("stream", streamResponses);

                if (root.TryGetProperty("temperature", out JsonElement temperature))
                    WritePropertyIfSimple(writer, "temperature", temperature);
                if (root.TryGetProperty("top_p", out JsonElement topP))
                    WritePropertyIfSimple(writer, "top_p", topP);
                if (root.TryGetProperty("max_tokens", out JsonElement maxTokens))
                    WritePropertyIfSimple(writer, "max_tokens", maxTokens);
                else if (root.TryGetProperty("max_completion_tokens", out JsonElement maxCompletionTokens))
                    WritePropertyIfSimple(writer, "max_completion_tokens", maxCompletionTokens);

                writer.WritePropertyName("messages");
                writer.WriteStartArray();

                int messageCount = 0;
                if (root.TryGetProperty("messages", out JsonElement messages) &&
                    messages.ValueKind == JsonValueKind.Array)
                {
                    foreach (JsonElement message in messages.EnumerateArray())
                        WriteChatUiMessage(writer, message, ref messageCount);
                }

                if (messageCount == 0)
                {
                    string message = ExtractStringProperty(root, "message") ??
                                     ExtractStringProperty(root, "prompt") ??
                                     "";
                    if (!string.IsNullOrWhiteSpace(message))
                    {
                        writer.WriteStartObject();
                        writer.WriteString("role", "user");
                        writer.WriteString("content", message);
                        writer.WriteEndObject();
                        messageCount++;
                    }
                }

                if (messageCount == 0)
                    throw new InvalidOperationException("Chat UI request did not include a message.");

                string availableServicesHint = BuildAvailableChatServicesSystemHint(permissions);
                if (!string.IsNullOrWhiteSpace(availableServicesHint))
                {
                    writer.WriteStartObject();
                    writer.WriteString("role", "system");
                    writer.WriteString("content", availableServicesHint);
                    writer.WriteEndObject();
                }

                string selectedServiceHint = BuildSelectedChatServiceSystemHint(ExtractStringProperty(root, "service"), permissions);
                if (!string.IsNullOrWhiteSpace(selectedServiceHint))
                {
                    writer.WriteStartObject();
                    writer.WriteString("role", "system");
                    writer.WriteString("content", selectedServiceHint);
                    writer.WriteEndObject();
                }

                bool agentMode = string.Equals(ExtractStringProperty(root, "service"), "agent", StringComparison.OrdinalIgnoreCase);
                string uploadedFilesHint = BuildChatUploadedFilesSystemHint(root, agentMode);
                if (!string.IsNullOrWhiteSpace(uploadedFilesHint))
                {
                    writer.WriteStartObject();
                    writer.WriteString("role", "system");
                    writer.WriteString("content", uploadedFilesHint);
                    writer.WriteEndObject();
                }

                writer.WriteEndArray();
                writer.WriteEndObject();
                writer.Flush();
                return Encoding.UTF8.GetString(jsonStream.ToArray());
            }
        }

        private string BuildChatUiNativeChatRequestJson(string requestBody, ChatPermissionState permissions = null)
        {
            if (string.IsNullOrWhiteSpace(requestBody))
                throw new InvalidOperationException("Chat UI request body was empty.");

            using (JsonDocument document = JsonDocument.Parse(requestBody))
            using (var jsonStream = new MemoryStream())
            using (var writer = new Utf8JsonWriter(jsonStream))
            {
                JsonElement root = document.RootElement;
                if (root.ValueKind != JsonValueKind.Object)
                    throw new InvalidOperationException("Chat UI request body must be a JSON object.");

                var messageList = new List<JsonElement>();
                if (root.TryGetProperty("messages", out JsonElement messages) &&
                    messages.ValueKind == JsonValueKind.Array)
                {
                    foreach (JsonElement message in messages.EnumerateArray())
                    {
                        string role = ExtractStringProperty(message, "role") ?? "";
                        if (message.ValueKind == JsonValueKind.Object && IsAllowedChatUiRole(role.Trim().ToLowerInvariant()))
                            messageList.Add(message);
                    }
                }

                int lastUserIndex = -1;
                for (int i = messageList.Count - 1; i >= 0; i--)
                {
                    string role = ExtractStringProperty(messageList[i], "role") ?? "";
                    if (role.Equals("user", StringComparison.OrdinalIgnoreCase))
                    {
                        lastUserIndex = i;
                        break;
                    }
                }

                string fallbackInput = ExtractStringProperty(root, "message") ??
                                       ExtractStringProperty(root, "prompt") ??
                                       "";
                if (lastUserIndex < 0 && string.IsNullOrWhiteSpace(fallbackInput))
                    throw new InvalidOperationException("Chat UI request did not include a message.");

                writer.WriteStartObject();
                string requestedModel = ExtractStringProperty(root, "model");
                writer.WriteString("model", string.IsNullOrWhiteSpace(requestedModel)
                    ? (string.IsNullOrWhiteSpace(ChatModel) ? "lm-studio" : ChatModel)
                    : requestedModel);
                writer.WriteBoolean("stream", true);
                writer.WriteBoolean("store", false);

                if (root.TryGetProperty("temperature", out JsonElement temperature))
                    WritePropertyIfSimple(writer, "temperature", temperature);
                if (root.TryGetProperty("top_p", out JsonElement topP))
                    WritePropertyIfSimple(writer, "top_p", topP);
                if (root.TryGetProperty("max_tokens", out JsonElement maxTokens))
                    WritePropertyIfSimple(writer, "max_output_tokens", maxTokens);
                else if (root.TryGetProperty("max_completion_tokens", out JsonElement maxCompletionTokens))
                    WritePropertyIfSimple(writer, "max_output_tokens", maxCompletionTokens);

                string systemPrompt = BuildChatUiNativeSystemPrompt(root, messageList, lastUserIndex, permissions);
                if (!string.IsNullOrWhiteSpace(systemPrompt))
                    writer.WriteString("system_prompt", systemPrompt);

                writer.WritePropertyName("input");
                if (lastUserIndex >= 0)
                {
                    if (!WriteChatUiNativeInputValue(writer, messageList[lastUserIndex]))
                    {
                        string currentText = ExtractChatUiMessageContentText(messageList[lastUserIndex]);
                        writer.WriteStringValue(string.IsNullOrWhiteSpace(currentText) ? fallbackInput : currentText);
                    }
                }
                else
                {
                    writer.WriteStringValue(fallbackInput);
                }

                writer.WriteEndObject();
                writer.Flush();
                return Encoding.UTF8.GetString(jsonStream.ToArray());
            }
        }

        private string BuildChatUiNativeSystemPrompt(JsonElement root, List<JsonElement> messages, int lastUserIndex, ChatPermissionState permissions = null)
        {
            var parts = new List<string>();
            foreach (JsonElement message in messages)
            {
                string role = ExtractStringProperty(message, "role") ?? "";
                if (!role.Equals("system", StringComparison.OrdinalIgnoreCase))
                    continue;

                string text = ExtractChatUiMessageContentText(message);
                if (!string.IsNullOrWhiteSpace(text))
                    parts.Add(text.Trim());
            }

            string availableServicesHint = BuildAvailableChatServicesSystemHint(permissions);
            if (!string.IsNullOrWhiteSpace(availableServicesHint))
                parts.Add(availableServicesHint.Trim());

            string selectedServiceHint = BuildSelectedChatServiceSystemHint(ExtractStringProperty(root, "service"), permissions);
            if (!string.IsNullOrWhiteSpace(selectedServiceHint))
                parts.Add(selectedServiceHint.Trim());

            string uploadedFilesHint = BuildChatUploadedFilesSystemHint(root, requireReadFile: false);
            if (!string.IsNullOrWhiteSpace(uploadedFilesHint))
                parts.Add(uploadedFilesHint.Trim());

            var transcript = new StringBuilder();
            int transcriptEnd = lastUserIndex >= 0 ? lastUserIndex : messages.Count;
            for (int i = 0; i < transcriptEnd; i++)
            {
                JsonElement message = messages[i];
                string role = (ExtractStringProperty(message, "role") ?? "").Trim().ToLowerInvariant();
                if (role.Equals("system", StringComparison.OrdinalIgnoreCase))
                    continue;

                string text = ExtractChatUiMessageContentText(message);
                if (string.IsNullOrWhiteSpace(text))
                    continue;

                if (transcript.Length == 0)
                    transcript.AppendLine("[Prior conversation]");
                transcript.Append(role.Equals("assistant", StringComparison.OrdinalIgnoreCase) ? "Assistant: " : "User: ");
                transcript.AppendLine(text.Trim());
            }

            if (transcript.Length > 0)
                parts.Add(transcript.ToString().Trim());

            return string.Join(Environment.NewLine + Environment.NewLine, parts);
        }

        private bool WriteChatUiNativeInputValue(Utf8JsonWriter writer, JsonElement message)
        {
            if (message.ValueKind != JsonValueKind.Object)
                return false;

            if (!message.TryGetProperty("content", out JsonElement contentElement))
                return false;

            if (contentElement.ValueKind == JsonValueKind.String)
            {
                string content = contentElement.GetString();
                if (string.IsNullOrWhiteSpace(content))
                    return false;
                writer.WriteStringValue(content);
                return true;
            }

            if (contentElement.ValueKind != JsonValueKind.Array)
                return false;

            var validParts = new List<JsonElement>();
            foreach (JsonElement part in contentElement.EnumerateArray())
            {
                if (IsSupportedChatUiNativeInputPart(part))
                    validParts.Add(part);
            }

            if (validParts.Count == 0)
                return false;

            writer.WriteStartArray();
            foreach (JsonElement part in validParts)
                WriteChatUiNativeInputPart(writer, part);
            writer.WriteEndArray();
            return true;
        }

        private bool IsSupportedChatUiNativeInputPart(JsonElement part)
        {
            if (part.ValueKind != JsonValueKind.Object)
                return false;

            string type = ExtractStringProperty(part, "type") ?? "";
            if (type.Equals("text", StringComparison.OrdinalIgnoreCase))
                return !string.IsNullOrWhiteSpace(ExtractStringProperty(part, "text") ?? ExtractStringProperty(part, "content"));

            if (type.Equals("image_url", StringComparison.OrdinalIgnoreCase) &&
                TryExtractChatUiImageUrl(part, out string imageUrl))
                return imageUrl.StartsWith("data:image/", StringComparison.OrdinalIgnoreCase);

            return false;
        }

        private void WriteChatUiNativeInputPart(Utf8JsonWriter writer, JsonElement part)
        {
            string type = ExtractStringProperty(part, "type") ?? "";
            writer.WriteStartObject();
            if (type.Equals("text", StringComparison.OrdinalIgnoreCase))
            {
                writer.WriteString("type", "text");
                writer.WriteString("text", ExtractStringProperty(part, "text") ?? ExtractStringProperty(part, "content") ?? "");
            }
            else if (type.Equals("image_url", StringComparison.OrdinalIgnoreCase) &&
                       TryExtractChatUiImageUrl(part, out string imageUrl))
            {
                writer.WriteString("type", "image");
                writer.WriteString("data_url", imageUrl);
            }
            writer.WriteEndObject();
        }

        private string ExtractChatUiMessageContentText(JsonElement message)
        {
            if (message.ValueKind != JsonValueKind.Object)
                return "";

            if (!message.TryGetProperty("content", out JsonElement contentElement))
                return ExtractStringProperty(message, "text") ?? "";

            if (contentElement.ValueKind == JsonValueKind.String)
                return contentElement.GetString() ?? "";

            if (contentElement.ValueKind != JsonValueKind.Array)
                return ExtractResponsesContentText(contentElement);

            var sb = new StringBuilder();
            foreach (JsonElement part in contentElement.EnumerateArray())
            {
                if (part.ValueKind == JsonValueKind.String)
                {
                    sb.Append(part.GetString());
                    continue;
                }

                if (part.ValueKind != JsonValueKind.Object)
                    continue;

                string type = ExtractStringProperty(part, "type") ?? "";
                if (type.Equals("text", StringComparison.OrdinalIgnoreCase))
                {
                    string text = ExtractStringProperty(part, "text") ?? ExtractStringProperty(part, "content");
                    if (!string.IsNullOrEmpty(text))
                        sb.Append(text);
                }
                else if (type.Equals("image_url", StringComparison.OrdinalIgnoreCase))
                {
                    if (sb.Length > 0 && !char.IsWhiteSpace(sb[sb.Length - 1]))
                        sb.AppendLine();
                    sb.Append("[Attached image]");
                }
            }

            return sb.ToString();
        }

        private string BuildChatUploadedFilesSystemHint(JsonElement root, bool requireReadFile)
        {
            try
            {
                if (root.ValueKind != JsonValueKind.Object ||
                    !root.TryGetProperty("files", out JsonElement files) ||
                    files.ValueKind != JsonValueKind.Array)
                    return "";

                const long inlineTextLimit = 128 * 1024;
                var sb = new StringBuilder();
                int count = 0;
                foreach (JsonElement file in files.EnumerateArray())
                {
                    if (file.ValueKind != JsonValueKind.Object)
                        continue;

                    string name = ExtractStringProperty(file, "name") ?? "attachment";
                    string type = ExtractStringProperty(file, "type") ?? "file";
                    string path = ExtractStringProperty(file, "path");
                    if (string.IsNullOrWhiteSpace(path))
                        continue;

                    string fullPath;
                    try
                    {
                        fullPath = Path.GetFullPath(path);
                    }
                    catch
                    {
                        continue;
                    }

                    if (!File.Exists(fullPath) || !IsPathInsideRoot(fullPath, _chatSessionFilesRoot))
                        continue;

                    if (count == 0)
                    {
                        sb.AppendLine("[LmVsProxy uploaded session files]");
                        sb.AppendLine(requireReadFile
                            ? "The user uploaded files for this Agent turn. Do not treat uploaded files as image_url or vision input. You must call read_file with the exact saved path before answering about any uploaded file."
                            : "The user uploaded files for this turn. Use read_file with the exact saved path when you need to inspect an uploaded file.");
                    }

                    var info = new FileInfo(fullPath);
                    sb.AppendLine();
                    sb.Append("- ").Append(name).Append(" (").Append(type).Append(", ")
                      .Append(info.Length.ToString()).Append(" bytes)");
                    sb.AppendLine();
                    sb.Append("  Saved path: ").Append(fullPath).AppendLine();
                    sb.Append("  read_file arguments: {\"path\":\"").Append(EscapeJson(fullPath)).Append("\"}").AppendLine();

                    if (!requireReadFile && info.Length <= inlineTextLimit && IsLikelyTextFile(fullPath))
                    {
                        string content = File.ReadAllText(fullPath);
                        sb.Append("```").Append(GetMarkdownLanguageForPath(fullPath)).Append(" ")
                          .Append(name).Append(" (uploaded file content)\n")
                          .Append(content)
                          .Append(content.EndsWith("\n", StringComparison.Ordinal) ? "" : "\n")
                          .AppendLine("```");
                    }

                    count++;
                }

                return count == 0 ? "" : sb.ToString().Trim();
            }
            catch (Exception ex)
            {
                LogMessage("[Chat UI] Could not build uploaded file prompt context: " + ex.Message);
                return "";
            }
        }

        private void WriteChatUiMessage(Utf8JsonWriter writer, JsonElement message, ref int messageCount)
        {
            if (message.ValueKind != JsonValueKind.Object)
                return;

            string role = ExtractStringProperty(message, "role");
            if (string.IsNullOrWhiteSpace(role))
                role = "user";
            role = role.Trim().ToLowerInvariant();

            if (!IsAllowedChatUiRole(role))
                return;

            writer.WriteStartObject();
            writer.WriteString("role", role);

            bool wroteContent = false;
            if (message.TryGetProperty("content", out JsonElement contentElement))
                wroteContent = WriteChatUiContent(writer, contentElement);

            if (!wroteContent)
            {
                string content = ExtractStringProperty(message, "text") ?? "";
                if (string.IsNullOrWhiteSpace(content))
                {
                    writer.WriteEndObject();
                    return;
                }

                writer.WriteString("content", content);
            }

            writer.WriteEndObject();
            messageCount++;
        }

        private bool WriteChatUiContent(Utf8JsonWriter writer, JsonElement contentElement)
        {
            if (contentElement.ValueKind == JsonValueKind.String)
            {
                string content = contentElement.GetString();
                if (string.IsNullOrWhiteSpace(content))
                    return false;

                writer.WriteString("content", content);
                return true;
            }

            if (contentElement.ValueKind != JsonValueKind.Array)
                return false;

            var validParts = new List<JsonElement>();
            foreach (JsonElement part in contentElement.EnumerateArray())
            {
                if (IsSupportedChatUiContentPart(part))
                    validParts.Add(part);
            }

            if (validParts.Count == 0)
                return false;

            writer.WritePropertyName("content");
            writer.WriteStartArray();
            foreach (JsonElement part in validParts)
                WriteChatUiContentPart(writer, part);
            writer.WriteEndArray();
            return true;
        }

        private bool IsSupportedChatUiContentPart(JsonElement part)
        {
            if (part.ValueKind != JsonValueKind.Object)
                return false;

            string type = ExtractStringProperty(part, "type") ?? "";
            if (type.Equals("text", StringComparison.OrdinalIgnoreCase))
                return !string.IsNullOrWhiteSpace(ExtractStringProperty(part, "text") ?? ExtractStringProperty(part, "content"));

            if (type.Equals("image_url", StringComparison.OrdinalIgnoreCase))
                return TryExtractChatUiImageUrl(part, out _);

            return false;
        }

        private void WriteChatUiContentPart(Utf8JsonWriter writer, JsonElement part)
        {
            string type = ExtractStringProperty(part, "type") ?? "";
            writer.WriteStartObject();

            if (type.Equals("text", StringComparison.OrdinalIgnoreCase))
            {
                writer.WriteString("type", "text");
                writer.WriteString("text", ExtractStringProperty(part, "text") ?? ExtractStringProperty(part, "content") ?? "");
            }
            else if (type.Equals("image_url", StringComparison.OrdinalIgnoreCase) &&
                       TryExtractChatUiImageUrl(part, out string imageUrl))
            {
                writer.WriteString("type", "image_url");
                writer.WritePropertyName("image_url");
                writer.WriteStartObject();
                writer.WriteString("url", imageUrl);
                writer.WriteEndObject();
            }

            writer.WriteEndObject();
        }

        private bool TryExtractChatUiImageUrl(JsonElement part, out string imageUrl)
        {
            imageUrl = null;
            if (part.ValueKind != JsonValueKind.Object)
                return false;

            if (part.TryGetProperty("image_url", out JsonElement imageUrlElement))
            {
                if (imageUrlElement.ValueKind == JsonValueKind.String)
                {
                    imageUrl = imageUrlElement.GetString();
                }
                else if (imageUrlElement.ValueKind == JsonValueKind.Object)
                {
                    imageUrl = ExtractStringProperty(imageUrlElement, "url");
                }
            }

            if (string.IsNullOrWhiteSpace(imageUrl))
                imageUrl = ExtractStringProperty(part, "url");

            return !string.IsNullOrWhiteSpace(imageUrl) &&
                   (imageUrl.StartsWith("data:image/", StringComparison.OrdinalIgnoreCase) ||
                    imageUrl.StartsWith("http://", StringComparison.OrdinalIgnoreCase) ||
                    imageUrl.StartsWith("https://", StringComparison.OrdinalIgnoreCase));
        }

        private static bool IsAllowedChatUiRole(string role)
        {
            return role.Equals("system", StringComparison.OrdinalIgnoreCase) ||
                   role.Equals("user", StringComparison.OrdinalIgnoreCase) ||
                   role.Equals("assistant", StringComparison.OrdinalIgnoreCase);
        }

        private ChatUiCompletion ExtractChatUiCompletionFromChatCompletion(string responseBody)
        {
            if (string.IsNullOrWhiteSpace(responseBody))
                return new ChatUiCompletion();

            try
            {
                using (JsonDocument document = JsonDocument.Parse(responseBody))
                {
                    JsonElement root = document.RootElement;
                    if (!root.TryGetProperty("choices", out JsonElement choices) ||
                        choices.ValueKind != JsonValueKind.Array ||
                        choices.GetArrayLength() == 0)
                        return SplitThinkTags(responseBody, "");

                    JsonElement choice = choices[0];
                    if (choice.TryGetProperty("message", out JsonElement message) &&
                        message.ValueKind == JsonValueKind.Object)
                    {
                        string content = message.TryGetProperty("content", out JsonElement messageContent)
                            ? ExtractResponsesContentText(messageContent)
                            : "";
                        string reasoning = ExtractReasoningText(message);
                        return SplitThinkTags(content, reasoning);
                    }

                    if (choice.TryGetProperty("delta", out JsonElement delta) &&
                        delta.ValueKind == JsonValueKind.Object)
                    {
                        string content = delta.TryGetProperty("content", out JsonElement deltaContent)
                            ? ExtractResponsesContentText(deltaContent)
                            : "";
                        string reasoning = ExtractReasoningText(delta);
                        return SplitThinkTags(content, reasoning);
                    }
                }
            }
            catch
            {
                return SplitThinkTags(responseBody, "");
            }

            return new ChatUiCompletion();
        }

        private string ExtractReasoningText(JsonElement element)
        {
            string reasoning =
                ExtractStringProperty(element, "reasoning_content") ??
                ExtractStringProperty(element, "reasoning") ??
                ExtractStringProperty(element, "thinking") ??
                ExtractStringProperty(element, "thought") ??
                ExtractStringProperty(element, "analysis");

            if (!string.IsNullOrWhiteSpace(reasoning))
                return reasoning;

            if (element.TryGetProperty("reasoning", out JsonElement reasoningElement))
                return ExtractResponsesContentText(reasoningElement);

            return "";
        }

        private ChatUiCompletion SplitThinkTags(string content, string reasoning)
        {
            content = content ?? "";
            reasoning = reasoning ?? "";

            const string openTag = "<think>";
            const string closeTag = "</think>";
            int openIndex = content.IndexOf(openTag, StringComparison.OrdinalIgnoreCase);
            int closeIndex = content.IndexOf(closeTag, StringComparison.OrdinalIgnoreCase);

            if (openIndex >= 0 && closeIndex > openIndex)
            {
                int thoughtStart = openIndex + openTag.Length;
                string taggedReasoning = content.Substring(thoughtStart, closeIndex - thoughtStart).Trim();
                if (!string.IsNullOrWhiteSpace(taggedReasoning))
                {
                    reasoning = string.IsNullOrWhiteSpace(reasoning)
                        ? taggedReasoning
                        : reasoning.Trim() + Environment.NewLine + Environment.NewLine + taggedReasoning;
                }

                content = (content.Substring(0, openIndex) + content.Substring(closeIndex + closeTag.Length)).Trim();
            }

            return new ChatUiCompletion
            {
                Content = content,
                Reasoning = reasoning?.Trim() ?? ""
            };
        }

